export const QUOTES = [
  // ============================================================
  // SELF-DEVELOPMENT / MOTIVATION (400 quotes)
  // ============================================================

  // Think and Grow Rich — Napoleon Hill (1-30)
  { text: "Whatever the mind can conceive and believe, it can achieve.", vi: "Bat cu dieu gi tri oc co the hinh dung va tin tuong, no deu co the dat duoc.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "The starting point of all achievement is desire.", vi: "Khoi dau cua moi thanh tuu chinh la khat vong.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Strength and growth come only through continuous effort and struggle.", vi: "Suc manh va su truong thanh chi den tu no luc va phan dau khong ngung.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Every adversity, every failure, every heartache carries with it the seed of an equal or greater benefit.", vi: "Moi nghich canh, moi that bai, moi noi dau deu mang trong no hat giong cua mot loi ich tuong duong hoac lon hon.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Set your mind on a definite goal and observe how quickly the world stands aside to let you pass.", vi: "Hay dat tam tri vao mot muc tieu ro rang va quan sat the gioi nhanh chong nhuong duong cho ban.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "A quitter never wins and a winner never quits.", vi: "Nguoi bo cuoc khong bao gio chien thang, nguoi chien thang khong bao gio bo cuoc.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "You are the master of your destiny. You can influence, direct and control your own environment.", vi: "Ban la chu nhan so phan minh. Ban co the tac dong, dinh huong va kiem soat moi truong xung quanh.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Desire is the starting point of all achievement, not a hope, not a wish, but a keen pulsating desire which transcends everything.", vi: "Khat vong la khoi nguon cua moi thanh tuu, khong phai hy vong, khong phai uoc muon, ma la mot khat khao chay bong vuot len tren tat ca.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "When defeat comes, accept it as a signal that your plans are not sound, rebuild those plans, and set sail once more toward your coveted goal.", vi: "Khi that bai den, hay chap nhan no nhu tin hieu rang ke hoach cua ban chua vung, xay dung lai va tiep tuc huong toi muc tieu.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Patience, persistence and perspiration make an unbeatable combination for success.", vi: "Kien nhan, kien tri va mo hoi tao nen su ket hop bat bai cho thanh cong.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "If you do not conquer self, you will be conquered by self.", vi: "Neu ban khong chinh phuc ban than, ban se bi chinh ban than chinh phuc.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "The man who does more than he is paid for will soon be paid for more than he does.", vi: "Nguoi lam nhieu hon so voi nhung gi duoc tra cong se som duoc tra cong nhieu hon so voi nhung gi anh ta lam.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Great achievement is usually born of great sacrifice, and is never the result of selfishness.", vi: "Thanh tuu lon thuong sinh ra tu su hy sinh lon, va khong bao gio la ket qua cua su ich ky.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Think twice before you speak, because your words and influence will plant the seed of either success or failure in the mind of another.", vi: "Hay suy nghi ky truoc khi noi, vi loi noi va anh huong cua ban se gieo hat giong thanh cong hoac that bai trong tam tri nguoi khac.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Action is the real measure of intelligence.", vi: "Hanh dong moi la thuoc do thuc su cua tri thong minh.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "The world has the habit of making room for the man whose actions show that he knows where he is going.", vi: "The gioi co thoi quen nhuong cho cho nguoi ma hanh dong cho thay ho biet minh dang di dau.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Your big opportunity may be right where you are now.", vi: "Co hoi lon cua ban co the ngay tai noi ban dang dung.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "No one is ready for a thing until he believes he can acquire it.", vi: "Khong ai san sang cho dieu gi cho den khi ho tin rang minh co the dat duoc no.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Every person who wins in any undertaking must be willing to burn his ships and cut all sources of retreat.", vi: "Moi nguoi chien thang trong bat ky cong viec nao deu phai san sang dot tau va cat moi duong lui.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Cherish your visions and your dreams as they are the children of your soul, the blueprints of your ultimate achievements.", vi: "Hay tran trong tam nhin va uoc mo cua ban vi chung la nhung dua con cua tam hon, la ban thiet ke cho thanh tuu cuoi cung.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "One of the most common causes of failure is the habit of quitting when one is overtaken by temporary defeat.", vi: "Mot trong nhung nguyen nhan that bai pho bien nhat la thoi quen bo cuoc khi gap that bai tam thoi.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "A goal is a dream with a deadline.", vi: "Muc tieu la giac mo co thoi han.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "The majority of men meet with failure because of their lack of persistence in creating new plans to take the place of those which fail.", vi: "Da so nguoi that bai vi thieu kien tri trong viec tao ke hoach moi thay the nhung ke hoach da that bai.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Before success comes in any man's life, he is sure to meet with much temporary defeat, and, perhaps, some failure.", vi: "Truoc khi thanh cong den trong cuoc doi, chac chan ban se gap nhieu that bai tam thoi.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "An educated man is not necessarily one who has an abundance of general or specialized knowledge. An educated man is one who has so developed the faculties of his mind that he may acquire anything he wants.", vi: "Nguoi co hoc khong nhat thiet la nguoi co nhieu kien thuc. Nguoi co hoc la nguoi da phat trien nang luc tri tue de co the dat duoc bat cu dieu gi ho muon.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Ideas are the beginning points of all fortunes.", vi: "Y tuong la diem khoi dau cua moi tai san.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "Do not wait; the time will never be just right.", vi: "Dung cho doi; thoi diem hoan hao se khong bao gio den.", author: "Napoleon Hill", source: "Think and Grow Rich" },
  { text: "More gold has been mined from the thoughts of men than has ever been taken from the earth.", vi: "Nhieu vang da duoc khai thac tu suy nghi con nguoi hon la tu long dat.", author: "Napoleon Hill", source: "Think and Grow Rich" },

  // The 7 Habits of Highly Effective People — Stephen Covey (29-55)
  { text: "Begin with the end in mind.", vi: "Hay bat dau voi dich den trong tam tri.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "The key is not to prioritize what's on your schedule, but to schedule your priorities.", vi: "Dieu quan trong khong phai la uu tien nhung gi trong lich trinh, ma la len lich cho nhung uu tien cua ban.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Most people do not listen with the intent to understand; they listen with the intent to reply.", vi: "Hau het moi nguoi khong lang nghe de hieu, ho lang nghe de dap tra.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Seek first to understand, then to be understood.", vi: "Hay tim hieu truoc, roi moi tim cach duoc hieu.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Sow a thought, reap an action; sow an action, reap a habit; sow a habit, reap a character; sow a character, reap a destiny.", vi: "Gieo suy nghi, gat hanh dong; gieo hanh dong, gat thoi quen; gieo thoi quen, gat tinh cach; gieo tinh cach, gat so phan.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "We see the world, not as it is, but as we are — or, as we are conditioned to see it.", vi: "Chung ta nhin the gioi khong nhu no von la, ma nhu chinh chung ta — hoac nhu cach ta duoc dinh hinh de nhin.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "To change ourselves effectively, we first had to change our perceptions.", vi: "De thay doi ban than hieu qua, truoc tien chung ta phai thay doi nhan thuc.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "I am not a product of my circumstances. I am a product of my decisions.", vi: "Toi khong phai san pham cua hoan canh. Toi la san pham cua nhung quyet dinh cua minh.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Habit is the intersection of knowledge, skill, and desire.", vi: "Thoi quen la giao diem cua kien thuc, ky nang va khat vong.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Live out of your imagination, not your history.", vi: "Hay song bang tri tuong tuong, khong phai bang qua khu.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Be proactive. Between stimulus and response, there is a space. In that space is our power to choose our response.", vi: "Hay chu dong. Giua kich thich va phan ung co mot khoang trong. Trong khoang trong do la quyen lua chon phan ung cua chung ta.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Start with the end in mind. If you carefully consider what you wanted to be said of you in the funeral experience, you will find your definition of success.", vi: "Bat dau voi dich den trong tam tri. Neu ban can nhac ky dieu ban muon nguoi ta noi ve minh trong le tang, ban se tim thay dinh nghia thanh cong cua minh.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Put first things first. The main thing is to keep the main thing the main thing.", vi: "Uu tien viec quan trong truoc. Dieu chinh la giu cho dieu chinh luon la dieu chinh.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Think win-win. It's not your way or my way; it's a better way, a higher way.", vi: "Hay nghi doi ben cung thang. Khong phai cach cua ban hay cach cua toi, ma la cach tot hon, cach cao hon.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Sharpen the saw. We must never become too busy sawing to take time to sharpen the saw.", vi: "Mai sac luoi cua. Dung bao gio ban ron cua den noi khong co thoi gian mai luoi cua.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "The way we see the problem is the problem.", vi: "Cach chung ta nhin van de chinh la van de.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Trust is the glue of life. It's the most essential ingredient in effective communication. It's the foundational principle that holds all relationships.", vi: "Niem tin la chat keo cua cuoc song. No la thanh phan thiet yeu nhat trong giao tiep hieu qua va la nen tang giu vung moi moi quan he.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Effective leadership is putting first things first. Effective management is discipline, carrying it out.", vi: "Lanh dao hieu qua la dat viec quan trong len truoc. Quan ly hieu qua la ky luat, la thuc thi.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "If I really want to improve my situation, I can work on the one thing over which I have control — myself.", vi: "Neu toi thuc su muon cai thien tinh huong, toi co the lam viec tren dieu duy nhat toi kiem soat duoc — chinh minh.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "It's not what happens to us, but our response to what happens to us that hurts us.", vi: "Khong phai dieu xay ra voi chung ta, ma la cach chung ta phan ung moi lam ton thuong chung ta.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Every human has four endowments: self-awareness, conscience, independent will, and creative imagination.", vi: "Moi nguoi deu co bon nang luc: tu nhan thuc, luong tam, y chi doc lap va tri tuong tuong sang tao.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Strength lies in differences, not in similarities.", vi: "Suc manh nam o su khac biet, khong phai su tuong dong.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "In the middle of difficulty lies opportunity.", vi: "Giua nhung kho khan an chua co hoi.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "The more people rationalize cheating, the more it becomes a culture of dishonesty. And that can become a vicious, downward cycle.", vi: "Cang bien minh cho su gian doi, no cang tro thanh van hoa thieu trung thuc. Va dieu do co the tro thanh vong xoay di xuong.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "We are not human beings on a spiritual journey. We are spiritual beings on a human journey.", vi: "Chung ta khong phai con nguoi tren hanh trinh tam linh. Chung ta la linh hon tren hanh trinh lam nguoi.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "People can't live with change if there's not a changeless core inside them.", vi: "Con nguoi khong the song voi su thay doi neu khong co mot loi bat bien ben trong.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },
  { text: "Accountability breeds response-ability.", vi: "Tinh than chiu trach nhiem sinh ra kha nang ung pho.", author: "Stephen Covey", source: "The 7 Habits of Highly Effective People" },

  // Atomic Habits — James Clear (56-90)
  { text: "You do not rise to the level of your goals. You fall to the level of your systems.", vi: "Ban khong vuon len tam muc tieu. Ban roi xuong tam he thong cua minh.", author: "James Clear", source: "Atomic Habits" },
  { text: "Every action you take is a vote for the type of person you wish to become.", vi: "Moi hanh dong ban lam la mot phieu bau cho kieu nguoi ban muon tro thanh.", author: "James Clear", source: "Atomic Habits" },
  { text: "Habits are the compound interest of self-improvement.", vi: "Thoi quen la lai kep cua su tu hoan thien.", author: "James Clear", source: "Atomic Habits" },
  { text: "The most effective way to change your habits is to focus not on what you want to achieve, but on who you wish to become.", vi: "Cach hieu qua nhat de thay doi thoi quen la tap trung vao nguoi ban muon tro thanh, khong phai dieu ban muon dat duoc.", author: "James Clear", source: "Atomic Habits" },
  { text: "Be the designer of your world and not merely the consumer of it.", vi: "Hay la nguoi thiet ke the gioi cua ban, khong chi la nguoi tieu thu no.", author: "James Clear", source: "Atomic Habits" },
  { text: "Getting 1 percent better every day counts for a lot in the long run.", vi: "Tot hon 1 phan tram moi ngay se tao nen su khac biet lon ve lau dai.", author: "James Clear", source: "Atomic Habits" },
  { text: "Time magnifies the margin between success and failure. It will multiply whatever you feed it.", vi: "Thoi gian phong dai khoang cach giua thanh cong va that bai. No se nhan len bat cu dieu gi ban nuoi duong.", author: "James Clear", source: "Atomic Habits" },
  { text: "All big things come from small beginnings. The seed of every habit is a single, tiny decision.", vi: "Moi dieu lon lao deu bat dau tu nhung dieu nho be. Hat giong cua moi thoi quen la mot quyet dinh nho.", author: "James Clear", source: "Atomic Habits" },
  { text: "The task of breaking a bad habit is like uprooting a powerful oak within us. And the task of building a good habit is like cultivating a delicate flower one day at a time.", vi: "Bo mot thoi quen xau giong nhu nho goc cay soi trong ta. Xay dung thoi quen tot giong nhu cham soc mot bong hoa mong manh moi ngay.", author: "James Clear", source: "Atomic Habits" },
  { text: "You should be far more concerned with your current trajectory than with your current results.", vi: "Ban nen quan tam den quy dao hien tai hon la ket qua hien tai.", author: "James Clear", source: "Atomic Habits" },
  { text: "When you fall in love with the process rather than the product, you don't have to wait to give yourself permission to be happy.", vi: "Khi ban yeu qua trinh thay vi ket qua, ban khong can cho phep minh duoc hanh phuc.", author: "James Clear", source: "Atomic Habits" },
  { text: "Goals are good for setting a direction, but systems are best for making progress.", vi: "Muc tieu tot de dinh huong, nhung he thong moi la cach tot nhat de tien bo.", author: "James Clear", source: "Atomic Habits" },
  { text: "Success is the product of daily habits — not once-in-a-lifetime transformations.", vi: "Thanh cong la san pham cua thoi quen hang ngay — khong phai nhung thay doi nghin nam mot lan.", author: "James Clear", source: "Atomic Habits" },
  { text: "The purpose of setting goals is to win the game. The purpose of building systems is to continue playing the game.", vi: "Muc dich cua dat muc tieu la thang cuoc choi. Muc dich cua xay dung he thong la tiep tuc choi.", author: "James Clear", source: "Atomic Habits" },
  { text: "Professionals stick to the schedule; amateurs let life get in the way.", vi: "Nguoi chuyen nghiep bam sat lich trinh; nguoi nghiep du de cuoc song can tro.", author: "James Clear", source: "Atomic Habits" },
  { text: "You don't have to be the victim of your environment. You can also be the architect of it.", vi: "Ban khong phai la nan nhan cua moi truong. Ban cung co the la kien truc su cua no.", author: "James Clear", source: "Atomic Habits" },
  { text: "Decisive moments set the options available to your future self.", vi: "Nhung khoanh khac quyet dinh thiet lap cac lua chon cho ban trong tuong lai.", author: "James Clear", source: "Atomic Habits" },
  { text: "True behavior change is identity change. You might start a habit because of motivation, but the only reason you'll stick with one is that it becomes part of your identity.", vi: "Thay doi hanh vi that su la thay doi ban sac. Ban co the bat dau thoi quen vi dong luc, nhung ly do duy nhat ban duy tri la vi no tro thanh mot phan con nguoi ban.", author: "James Clear", source: "Atomic Habits" },
  { text: "Every craving is linked to a desire to change your internal state.", vi: "Moi con them muon deu lien ket voi mong muon thay doi trang thai ben trong.", author: "James Clear", source: "Atomic Habits" },
  { text: "Missing once is an accident. Missing twice is the start of a new habit.", vi: "Bo lo mot lan la tai nan. Bo lo hai lan la bat dau mot thoi quen moi.", author: "James Clear", source: "Atomic Habits" },
  { text: "The first mistake is never the one that ruins you. It is the spiral of repeated mistakes that follows.", vi: "Sai lam dau tien khong bao gio pha huy ban. Chinh vong xoay cua nhung sai lam lap lai moi la thu pha huy.", author: "James Clear", source: "Atomic Habits" },
  { text: "When nothing seems to help, I go and look at a stonecutter hammering away at his rock, perhaps a hundred times without as much as a crack showing in it. Yet at the hundred and first blow it will split in two.", vi: "Khi khong co gi co ve hieu qua, hay nhin nguoi tho da dang duc, co le mot tram lan ma khong thay vet nut nao. Nhung lan thu mot tram le mot, tang da se vo doi.", author: "James Clear", source: "Atomic Habits" },
  { text: "With outcome-based habits, the focus is on what you want to achieve. With identity-based habits, the focus is on who you wish to become.", vi: "Voi thoi quen dua tren ket qua, trong tam la dieu ban muon dat. Voi thoi quen dua tren ban sac, trong tam la nguoi ban muon tro thanh.", author: "James Clear", source: "Atomic Habits" },
  { text: "Motion makes you feel like you're getting things done. But really, you're just preparing to get something done.", vi: "Van dong khien ban cam thay dang lam duoc viec. Nhung thuc ra ban chi dang chuan bi de lam viec.", author: "James Clear", source: "Atomic Habits" },
  { text: "One of the best ways to build a new habit is to identify a current habit you already do each day and then stack your new behavior on top.", vi: "Mot cach tot nhat de xay thoi quen moi la xac dinh thoi quen hien tai ban lam moi ngay roi xep hanh vi moi len tren.", author: "James Clear", source: "Atomic Habits" },
  { text: "Reduce the friction associated with good behaviors. When friction is low, habits are easy.", vi: "Giam ma sat lien quan den hanh vi tot. Khi ma sat thap, thoi quen se de dang.", author: "James Clear", source: "Atomic Habits" },
  { text: "The secret to getting results that last is to never stop making improvements.", vi: "Bi quyet de co ket qua lau dai la khong bao gio ngung cai thien.", author: "James Clear", source: "Atomic Habits" },
  { text: "If you want better results, then forget about setting goals. Focus on your system instead.", vi: "Neu ban muon ket qua tot hon, hay quen viec dat muc tieu. Thay vao do hay tap trung vao he thong.", author: "James Clear", source: "Atomic Habits" },
  { text: "We imitate the habits of three groups in particular: the close, the many, and the powerful.", vi: "Chung ta bat chuoc thoi quen cua ba nhom: nguoi than can, so dong va nguoi quyen luc.", author: "James Clear", source: "Atomic Habits" },
  { text: "The greatest threat to success is not failure but boredom.", vi: "Moi de doa lon nhat cho thanh cong khong phai that bai ma la su nham chan.", author: "James Clear", source: "Atomic Habits" },
  { text: "Standardize before you optimize. You can't improve a habit that doesn't exist.", vi: "Chuan hoa truoc khi toi uu. Ban khong the cai thien thoi quen chua ton tai.", author: "James Clear", source: "Atomic Habits" },
  { text: "People who make a specific plan for when and where they will perform a new habit are more likely to follow through.", vi: "Nguoi lap ke hoach cu the ve thoi gian va dia diem thuc hien thoi quen moi se de thuc hien hon.", author: "James Clear", source: "Atomic Habits" },
  { text: "It is only by making the fundamentals of life easier that you can create the mental space needed for free thinking and creativity.", vi: "Chi khi lam cho nhung dieu co ban trong cuoc song de dang hon, ban moi tao ra khong gian tinh than cho tu duy tu do va sang tao.", author: "James Clear", source: "Atomic Habits" },
  { text: "The more pride you have in a particular aspect of your identity, the more motivated you will be to maintain the habits associated with it.", vi: "Ban cang tu hao ve mot khia canh ban sac, ban cang co dong luc duy tri thoi quen lien quan.", author: "James Clear", source: "Atomic Habits" },
  { text: "Habits do not restrict freedom. They create it.", vi: "Thoi quen khong gioi han tu do. Chung tao ra tu do.", author: "James Clear", source: "Atomic Habits" },

  // The Power of Now — Eckhart Tolle (91-115)
  { text: "Realize deeply that the present moment is all you have. Make the NOW the primary focus of your life.", vi: "Hay nhan ra sau sac rang hien tai la tat ca nhung gi ban co. Hay lay HIEN TAI lam trong tam cuoc song.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Life is now. There was never a time when your life was not now, nor will there ever be.", vi: "Cuoc song la bay gio. Chua bao gio co luc cuoc doi ban khong phai la bay gio, va cung se khong bao gio.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Wherever you are, be there totally.", vi: "Du ban o dau, hay co mat toan ven.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "The past has no power over the present moment.", vi: "Qua khu khong co quyen luc gi tren khoanh khac hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "What a liberation to realize that the voice in my head is not who I am.", vi: "That la giai phong khi nhan ra giong noi trong dau toi khong phai la toi.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Time isn't precious at all, because it is an illusion. What you perceive as precious is not time but the one point that is out of time: the Now.", vi: "Thoi gian khong quy gia chut nao, vi no la ao giac. Dieu ban cho la quy gia khong phai thoi gian ma la diem duy nhat nam ngoai thoi gian: Hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "The primary cause of unhappiness is never the situation but your thoughts about it.", vi: "Nguyen nhan chinh cua bat hanh khong bao gio la tinh huong ma la suy nghi cua ban ve no.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "All negativity is caused by an accumulation of psychological time and denial of the present.", vi: "Moi tieu cuc deu do tich tu thoi gian tam ly va phu nhan hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "As soon as you honor the present moment, all unhappiness and struggle dissolve, and life begins to flow with joy and ease.", vi: "Ngay khi ban ton trong khoanh khac hien tai, moi bat hanh va dau tranh tan bien, cuoc song bat dau chay tran niem vui va nhe nhang.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "If you get the inside right, the outside will fall into place.", vi: "Neu ban on dinh ben trong, ben ngoai se tu vao dung cho.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "The mind is a superb instrument if used rightly. Used wrongly, however, it becomes very destructive.", vi: "Tri oc la cong cu tuyet voi neu dung dung. Nhung dung sai, no tro nen rat huy diet.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "You can always cope with the present moment, but you cannot cope with something that is only a mind projection — you cannot cope with the future.", vi: "Ban luon co the doi pho voi hien tai, nhung khong the doi pho voi thu chi la phong chieu cua tri oc — ban khong the doi pho voi tuong lai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Nothing ever happened in the past; it happened in the Now. Nothing will ever happen in the future; it will happen in the Now.", vi: "Khong co gi tung xay ra trong qua khu; no xay ra trong Hien tai. Khong co gi se xay ra trong tuong lai; no se xay ra trong Hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Don't let a mad world tell you that success is anything other than a successful present moment.", vi: "Dung de the gioi dien ro noi voi ban rang thanh cong la bat cu dieu gi khac ngoai mot khoanh khac hien tai thanh cong.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Any action is often better than no action, especially if you have been stuck in an unhappy situation for a long time.", vi: "Bat ky hanh dong nao cung thuong tot hon khong hanh dong, dac biet neu ban da mac ket trong tinh huong bat hanh lau roi.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Always say yes to the present moment. Surrender to what is. Say yes to life — and see how life suddenly starts working for you rather than against you.", vi: "Luon noi co voi hien tai. Buong bo va chap nhan nhung gi dang la. Noi co voi cuoc song — va xem cuoc song bat ngo lam viec cho ban thay vi chong lai ban.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Is there a difference between happiness and inner peace? Yes. Happiness depends on conditions being perceived as positive; inner peace does not.", vi: "Co su khac biet giua hanh phuc va binh yen noi tam khong? Co. Hanh phuc phu thuoc vao dieu kien duoc xem la tich cuc; binh yen noi tam thi khong.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Accept — then act. Whatever the present moment contains, accept it as if you had chosen it.", vi: "Chap nhan — roi hanh dong. Du hien tai chua dieu gi, hay chap nhan no nhu the ban da chon no.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Unease, anxiety, tension, stress, worry — all forms of fear — are caused by too much future, and not enough presence.", vi: "Bat an, lo lang, cang thang, stress — moi dang so hai — deu do qua nhieu tuong lai va khong du hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Guilt, regret, resentment, grievances, sadness, bitterness, and all forms of nonforgiveness are caused by too much past, and not enough presence.", vi: "Toi loi, hoi tiec, oan gian, buon ba va moi dang khong tha thu deu do qua nhieu qua khu va khong du hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "The moment you realize you are not present, you are present.", vi: "Khoanh khac ban nhan ra minh khong o hien tai, ban da o hien tai.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "To the ego, the present moment hardly exists. Only past and future are considered important.", vi: "Voi ban nga, hien tai hau nhu khong ton tai. Chi qua khu va tuong lai moi duoc xem la quan trong.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "You find peace not by rearranging the circumstances of your life, but by realizing who you are at the deepest level.", vi: "Ban tim thay binh yen khong phai bang cach sap xep lai hoan canh, ma bang cach nhan ra minh la ai o tang sau nhat.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "Pleasure is always derived from something outside you, whereas joy arises from within.", vi: "Khoai lac luon den tu ben ngoai, trong khi niem vui nay sinh tu ben trong.", author: "Eckhart Tolle", source: "The Power of Now" },
  { text: "The power for creating a better future is contained in the present moment: You create a good future by creating a good present.", vi: "Suc manh de tao tuong lai tot hon nam trong hien tai: Ban tao tuong lai tot bang cach tao hien tai tot.", author: "Eckhart Tolle", source: "The Power of Now" },

  // Man's Search for Meaning — Viktor Frankl (116-140)
  { text: "He who has a why to live for can bear almost any how.", vi: "Nguoi co ly do de song co the chiu dung hau het moi cach song.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "When we are no longer able to change a situation, we are challenged to change ourselves.", vi: "Khi khong the thay doi tinh huong, chung ta duoc thach thuc de thay doi chinh minh.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Everything can be taken from a man but one thing: the last of the human freedoms — to choose one's attitude in any given set of circumstances, to choose one's own way.", vi: "Moi thu co the bi lay di tu con nguoi tru mot dieu: tu do cuoi cung — quyen chon thai do trong moi hoan canh, quyen chon con duong cua minh.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Between stimulus and response there is a space. In that space is our power to choose our response. In our response lies our growth and our freedom.", vi: "Giua kich thich va phan ung co mot khoang trong. Trong khoang trong do la quyen lua chon phan ung. Trong phan ung cua ta nam su truong thanh va tu do.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Those who have a 'why' to live, can bear with almost any 'how'.", vi: "Nguoi co 'tai sao' de song co the chiu dung bat ky 'cach nao'.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "In some ways suffering ceases to be suffering at the moment it finds a meaning, such as the meaning of a sacrifice.", vi: "Theo mot cach nao do, dau kho khong con la dau kho khi no tim thay y nghia, nhu y nghia cua su hy sinh.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Don't aim at success. The more you aim at it and make it a target, the more you are going to miss it.", vi: "Dung nham vao thanh cong. Ban cang nham vao no va bien no thanh muc tieu, ban cang de truot.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "What is to give light must endure burning.", vi: "Dieu gi mang lai anh sang phai chiu dung su thieu dot.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "An abnormal reaction to an abnormal situation is normal behavior.", vi: "Phan ung bat thuong truoc tinh huong bat thuong la hanh vi binh thuong.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Life is never made unbearable by circumstances, but only by lack of meaning and purpose.", vi: "Cuoc song khong bao gio tro nen khong the chiu noi vi hoan canh, ma chi vi thieu y nghia va muc dich.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "For success, like happiness, cannot be pursued; it must ensue, and it only does so as the unintended side effect of one's personal dedication to a cause greater than oneself.", vi: "Thanh cong, nhu hanh phuc, khong the theo duoi; no phai tu den, va chi den nhu hieu ung phu cua su cong hien cho muc dich lon hon ban than.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "The salvation of man is through love and in love.", vi: "Su cuu roi cua con nguoi la thong qua tinh yeu va trong tinh yeu.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Challenging the meaning of life is the truest expression of the state of being human.", vi: "Thach thuc y nghia cuoc song la bieu hien chan thuc nhat cua trang thai lam nguoi.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "No man should judge unless he asks himself in absolute honesty whether in a similar situation he might not have done the same.", vi: "Khong ai nen phan xet tru khi tu hoi minh trong tinh huong tuong tu lieu co lam giong vay khong.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Man does not simply exist but always decides what his existence will be, what he will become the next moment.", vi: "Con nguoi khong chi ton tai ma luon quyet dinh su ton tai cua minh se la gi, minh se tro thanh gi vao khoanh khac tiep theo.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Ultimately, man should not ask what the meaning of his life is, but rather must recognize that it is he who is asked.", vi: "Cuoi cung, con nguoi khong nen hoi y nghia cuoc doi la gi, ma phai nhan ra chinh minh la nguoi bi hoi.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Live as if you were living already for the second time and as if you had acted the first time as wrongly as you are about to act now.", vi: "Hay song nhu the ban dang song lan thu hai va nhu the lan dau ban da hanh dong sai lam nhu ban sap lam bay gio.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "A man who becomes conscious of the responsibility he bears toward a human being who affectionately waits for him, or to an unfinished work, will never be able to throw away his life.", vi: "Nguoi y thuc duoc trach nhiem voi nguoi dang yeu thuong cho doi minh, hoac voi cong viec dang do, se khong bao gio bo di cuoc doi.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "The one thing you can't take away from me is the way I choose to respond to what you do to me.", vi: "Dieu duy nhat ban khong the lay di tu toi la cach toi chon phan ung truoc nhung gi ban lam voi toi.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Forces beyond your control can take away everything you possess except one thing, your freedom to choose how you will respond to the situation.", vi: "Nhung luc luong ngoai tam kiem soat co the lay di tat ca tru mot dieu: tu do chon cach ban phan ung.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Even the helpless victim of a hopeless situation, facing a fate he cannot change, may rise above himself, may grow beyond himself, and by so doing change himself.", vi: "Ngay ca nan nhan bat luc trong tinh huong tuyet vong, doi mat so phan khong the thay doi, van co the vuon len tren chinh minh va thay doi ban than.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "It did not really matter what we expected from life, but rather what life expected from us.", vi: "Dieu quan trong khong phai la ta ky vong gi tu cuoc song, ma la cuoc song ky vong gi tu ta.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "The meaning of life is to give life meaning.", vi: "Y nghia cua cuoc song la mang lai y nghia cho cuoc song.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Each man is questioned by life; and he can only answer to life by answering for his own life; to life he can only respond by being responsible.", vi: "Moi nguoi deu bi cuoc doi chat van; va chi co the tra loi cuoc doi bang cach chiu trach nhiem cho cuoc doi minh.", author: "Viktor Frankl", source: "Man's Search for Meaning" },
  { text: "Ever more people today have the means to live, but no meaning to live for.", vi: "Ngay cang nhieu nguoi co phuong tien de song nhung khong co y nghia de song.", author: "Viktor Frankl", source: "Man's Search for Meaning" },

  // Mindset — Carol Dweck (141-165)
  { text: "Becoming is better than being.", vi: "Dang tro thanh tot hon la da la.", author: "Carol Dweck", source: "Mindset" },
  { text: "The view you adopt for yourself profoundly affects the way you lead your life.", vi: "Goc nhin ban chon cho minh anh huong sau sac den cach ban song.", author: "Carol Dweck", source: "Mindset" },
  { text: "In the fixed mindset, everything is about the outcome. If you fail — or if you're not the best — it's all been wasted. The growth mindset allows people to value what they're doing regardless of the outcome.", vi: "Trong tu duy co dinh, moi thu chi ve ket qua. Neu that bai hay khong gioi nhat, tat ca da phi. Tu duy phat trien cho phep tran trong qua trinh bat ke ket qua.", author: "Carol Dweck", source: "Mindset" },
  { text: "Why waste time proving over and over how great you are, when you could be getting better?", vi: "Tai sao lang phi thoi gian chung minh ban gioi, trong khi ban co the dang tro nen gioi hon?", author: "Carol Dweck", source: "Mindset" },
  { text: "No matter what your ability is, effort is what ignites that ability and turns it into accomplishment.", vi: "Du nang luc cua ban la gi, no luc moi la thu chap lua nang luc va bien no thanh thanh tuu.", author: "Carol Dweck", source: "Mindset" },
  { text: "Test scores and measures of achievement tell you where a student is, but they don't tell you where a student could end up.", vi: "Diem so cho biet hoc sinh dang o dau, nhung khong cho biet ho co the di den dau.", author: "Carol Dweck", source: "Mindset" },
  { text: "The passion for stretching yourself and sticking to it, even when it's not going well, is the hallmark of the growth mindset.", vi: "Dam me vuon xa va kien tri, ngay ca khi moi viec khong suon se, la dau hieu cua tu duy phat trien.", author: "Carol Dweck", source: "Mindset" },
  { text: "Effort is one of those things that gives meaning to life. Effort means you care about something, that something is important to you and you are willing to work for it.", vi: "No luc la thu mang lai y nghia cho cuoc song. No luc co nghia ban quan tam dieu gi do va san sang lam viec vi no.", author: "Carol Dweck", source: "Mindset" },
  { text: "Just because some people can do something with little or no training, it doesn't mean that others can't do it with training.", vi: "Chi vi mot so nguoi lam duoc voi it hay khong can luyen tap, khong co nghia nguoi khac khong the lam duoc khi luyen tap.", author: "Carol Dweck", source: "Mindset" },
  { text: "People in a growth mindset don't just seek challenge, they thrive on it. The bigger the challenge, the more they stretch.", vi: "Nguoi co tu duy phat trien khong chi tim kiem thach thuc, ho phat trien nho no. Thach thuc cang lon, ho cang vuon xa.", author: "Carol Dweck", source: "Mindset" },
  { text: "You have a choice. Mindsets are just beliefs. They're powerful beliefs, but they're just something in your mind, and you can change your mind.", vi: "Ban co quyen lua chon. Tu duy chi la niem tin. Chung la niem tin manh me, nhung chi la thu trong dau ban, va ban co the thay doi.", author: "Carol Dweck", source: "Mindset" },
  { text: "True self-confidence is the courage to be open — to welcome change and new ideas regardless of their source.", vi: "Tu tin that su la su can dam de mo long — don nhan thay doi va y tuong moi bat ke nguon goc.", author: "Carol Dweck", source: "Mindset" },
  { text: "If parents want to give their children a gift, the best thing they can do is to teach their children to love challenges.", vi: "Neu cha me muon tang con mon qua, dieu tot nhat la day con yeu thich thach thuc.", author: "Carol Dweck", source: "Mindset" },
  { text: "Picture your brain forming new connections as you meet the challenge and learn. Keep on going.", vi: "Hay hinh dung nao bo tao ket noi moi khi ban doi mat thach thuc va hoc hoi. Hay tiep tuc.", author: "Carol Dweck", source: "Mindset" },
  { text: "Did I win? Did I lose? Those are the wrong questions. The correct question is: Did I make my best effort?", vi: "Toi thang hay thua? Do la cau hoi sai. Cau hoi dung la: Toi da no luc het suc chua?", author: "Carol Dweck", source: "Mindset" },
  { text: "Character grows out of mindset. It grows out of the willingness to tackle challenges, to not give up.", vi: "Tinh cach truong thanh tu tu duy. No lon len tu su san sang doi mat thach thuc va khong bo cuoc.", author: "Carol Dweck", source: "Mindset" },
  { text: "People with the growth mindset know that it takes time for potential to flower.", vi: "Nguoi co tu duy phat trien biet rang tiem nang can thoi gian de no hoa.", author: "Carol Dweck", source: "Mindset" },
  { text: "A person's true potential is unknown and unknowable; it's impossible to foresee what can be accomplished with years of passion, toil, and training.", vi: "Tiem nang that su cua con nguoi la an so; khong the du doan duoc dieu gi co the dat duoc voi nhieu nam dam me, lao dong va ren luyen.", author: "Carol Dweck", source: "Mindset" },
  { text: "In the growth mindset, failure can be a painful experience. But it doesn't define you. It's a problem to be faced, dealt with, and learned from.", vi: "Trong tu duy phat trien, that bai co the dau don. Nhung no khong dinh nghia ban. No la van de can doi mat, xu ly va hoc hoi.", author: "Carol Dweck", source: "Mindset" },
  { text: "The growth mindset is based on the belief that your basic qualities are things you can cultivate through your efforts, your strategies, and help from others.", vi: "Tu duy phat trien dua tren niem tin rang pham chat co ban co the duoc boi duong qua no luc, chien luoc va su giup do tu nguoi khac.", author: "Carol Dweck", source: "Mindset" },
  { text: "Praising children's intelligence harms their motivation and it harms their performance.", vi: "Khen tri thong minh cua tre lam hai dong luc va thanh tich cua chung.", author: "Carol Dweck", source: "Mindset" },
  { text: "We like to think of our champions and idols as superheroes who were born different from us. We don't like to think of them as relatively ordinary people who made themselves extraordinary.", vi: "Chung ta thich nghi nha vo dich la sieu nhan sinh ra khac biet. Chung ta khong thich nghi ho la nguoi binh thuong tu lam minh phi thuong.", author: "Carol Dweck", source: "Mindset" },
  { text: "Think about your hero. Do you think of this person as someone with extraordinary abilities who achieved with little effort? Now go find out the truth.", vi: "Hay nghi ve than tuong cua ban. Ban co nghi ho la nguoi tai nang phi thuong dat duoc thanh cong de dang? Hay di tim su that.", author: "Carol Dweck", source: "Mindset" },
  { text: "What did you learn today? What mistake did you make that taught you something? What did you try hard at today?", vi: "Hom nay ban hoc duoc gi? Ban mac sai lam gi day ban dieu gi? Hom nay ban da co gang het suc o dau?", author: "Carol Dweck", source: "Mindset" },
  { text: "Mindsets are an important part of your personality, but you can change them.", vi: "Tu duy la phan quan trong cua tinh cach, nhung ban co the thay doi chung.", author: "Carol Dweck", source: "Mindset" },

  // Grit — Angela Duckworth (166-190)
  { text: "Grit is passion and perseverance for very long-term goals.", vi: "Kien cuong la dam me va ben chi cho nhung muc tieu dai han.", author: "Angela Duckworth", source: "Grit" },
  { text: "Enthusiasm is common. Endurance is rare.", vi: "Nhiet huyet thi pho bien. Ben bi moi la hiem.", author: "Angela Duckworth", source: "Grit" },
  { text: "Our potential is one thing. What we do with it is quite another.", vi: "Tiem nang la mot chuyen. Dieu chung ta lam voi no la chuyen khac.", author: "Angela Duckworth", source: "Grit" },
  { text: "There are no shortcuts to excellence. Developing real expertise, figuring out really hard problems, it all takes time.", vi: "Khong co duong tat den su xuat sac. Phat trien chuyen mon that su, giai quyet van de kho, tat ca deu can thoi gian.", author: "Angela Duckworth", source: "Grit" },
  { text: "As much as talent counts, effort counts twice.", vi: "Tai nang quan trong bao nhieu, no luc quan trong gap doi.", author: "Angela Duckworth", source: "Grit" },
  { text: "Grit is about working on something you care about so much that you're willing to stay loyal to it.", vi: "Kien cuong la lam viec tren dieu ban quan tam den muc san sang trung thanh voi no.", author: "Angela Duckworth", source: "Grit" },
  { text: "Without effort, your talent is nothing more than your unmet potential. Without effort, your skill is nothing more than what you could have done but didn't.", vi: "Khong co no luc, tai nang chi la tiem nang chua duoc khai pha. Khong co no luc, ky nang chi la dieu ban co the lam nhung da khong lam.", author: "Angela Duckworth", source: "Grit" },
  { text: "One form of perseverance is the daily discipline of trying to do things better than we did yesterday.", vi: "Mot hinh thuc kien tri la ky luat hang ngay co lam tot hon hom qua.", author: "Angela Duckworth", source: "Grit" },
  { text: "Nobody wants to show you the hours and hours of becoming. They'd rather show you the highlight of what they've become.", vi: "Khong ai muon cho ban thay hang gio phan dau. Ho chi muon cho ban diem sang cua thanh tuu.", author: "Angela Duckworth", source: "Grit" },
  { text: "Passion for your work is a little bit of discovery, followed by a lot of development, and then a lifetime of deepening.", vi: "Dam me voi cong viec bat dau tu mot chut kham pha, tiep theo la nhieu phat trien, va ca doi di sau.", author: "Angela Duckworth", source: "Grit" },
  { text: "Grit is not just having resilience in the face of failure, but also having deep commitments that you remain loyal to over many years.", vi: "Kien cuong khong chi la ben bi truoc that bai, ma con la nhung cam ket sau sac ma ban trung thanh suot nhieu nam.", author: "Angela Duckworth", source: "Grit" },
  { text: "What ripens passion is the conviction that your work matters.", vi: "Dieu lam chin muoi dam me la niem tin rang cong viec cua ban co y nghia.", author: "Angela Duckworth", source: "Grit" },
  { text: "At its core, the idea of grit is quite simple. Grit is about not giving up.", vi: "Ve ban chat, y tuong ve kien cuong rat don gian. Kien cuong la khong bo cuoc.", author: "Angela Duckworth", source: "Grit" },
  { text: "Talent times effort equals skill. Skill times effort equals achievement.", vi: "Tai nang nhan no luc bang ky nang. Ky nang nhan no luc bang thanh tuu.", author: "Angela Duckworth", source: "Grit" },
  { text: "Is this what I want to be doing with my time? That question needs a confident answer of yes, year after year.", vi: "Day co phai la dieu toi muon lam voi thoi gian cua minh? Cau hoi do can mot cau tra loi tu tin la co, nam nay qua nam khac.", author: "Angela Duckworth", source: "Grit" },
  { text: "The main thing is to keep the main thing the main thing. And for that you need grit.", vi: "Dieu chinh la giu cho dieu chinh luon la dieu chinh. Va de lam dieu do ban can kien cuong.", author: "Angela Duckworth", source: "Grit" },
  { text: "Interest without purpose is nearly impossible to sustain for a lifetime.", vi: "Hung thu khong co muc dich gan nhu khong the duy tri ca doi.", author: "Angela Duckworth", source: "Grit" },
  { text: "Falling down is not a failure. Failure comes when you stay where you have fallen.", vi: "Nga xuong khong phai that bai. That bai la khi ban nam yen tai cho.", author: "Angela Duckworth", source: "Grit" },
  { text: "Most dazzling human achievements are, in fact, the aggregate of countless individual elements, each of which is, in a sense, ordinary.", vi: "Nhung thanh tuu ruc ro nhat thuc ra la tong hop cua vo so yeu to rieng le, moi yeu to deu binh thuong.", author: "Angela Duckworth", source: "Grit" },
  { text: "You can grow your grit from the inside out by developing your interests, building a habit of daily challenge-exceeding-skill practice, connecting your work to a purpose beyond yourself, and learning to hope when all seems lost.", vi: "Ban co the phat trien kien cuong tu ben trong bang cach phat trien so thich, xay dung thoi quen luyen tap vuot qua gioi han, ket noi cong viec voi muc dich lon hon ban than, va hoc cach hy vong khi tat ca tuong nhu da mat.", author: "Angela Duckworth", source: "Grit" },
  { text: "What I mean by passion is not just that you have something you care about. What I mean is that you care about that same ultimate goal in an abiding, loyal, steady way.", vi: "Dam me khong chi la ban quan tam dieu gi do. Ma la ban quan tam den cung mot muc tieu cuoi cung mot cach ben bi, trung thanh va vung vang.", author: "Angela Duckworth", source: "Grit" },
  { text: "To be gritty is to keep putting one foot in front of the other. To be gritty is to hold fast to an interesting and purposeful goal.", vi: "Kien cuong la tiep tuc buoc tung buoc mot. Kien cuong la bam chat vao muc tieu thu vi va co y nghia.", author: "Angela Duckworth", source: "Grit" },
  { text: "Greatness is many, many individual feats, and each of them is doable.", vi: "Su vi dai la rat nhieu ky cong rieng le, va moi cai deu co the lam duoc.", author: "Angela Duckworth", source: "Grit" },
  { text: "The source of our strength is the person we know ourselves to be.", vi: "Nguon suc manh cua chung ta la con nguoi ma ta biet minh la.", author: "Angela Duckworth", source: "Grit" },
  { text: "Consistency of effort over the long run is everything.", vi: "Su nhat quan trong no luc ve lau dai la tat ca.", author: "Angela Duckworth", source: "Grit" },

  // The Subtle Art of Not Giving a F*ck — Mark Manson (191-215)
  { text: "Who you are is defined by what you're willing to struggle for.", vi: "Ban la ai duoc dinh nghia boi dieu ban san sang chien dau.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "The desire for more positive experience is itself a negative experience. And, paradoxically, the acceptance of one's negative experience is itself a positive experience.", vi: "Mong muon co trai nghiem tich cuc ban than no la trai nghiem tieu cuc. Va nghich ly thay, chap nhan trai nghiem tieu cuc lai la trai nghiem tich cuc.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "You and everyone you know are going to be dead soon. And in the short amount of time between here and there, you have a limited amount of f*cks to give.", vi: "Ban va moi nguoi ban biet deu se chet som. Va trong khoang thoi gian ngan ngui do, ban chi co gioi han nhung dieu de quan tam.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Not giving a f*ck does not mean being indifferent; it means being comfortable with being different.", vi: "Khong quan tam khong co nghia la tho o; ma la thoai mai voi viec khac biet.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Maturity is what happens when one learns to only give a f*ck about what's truly f*ckworthy.", vi: "Truong thanh la khi ban hoc cach chi quan tam den nhung dieu thuc su dang quan tam.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "The problem isn't the problem. The problem is the incredible amount of overthinking you're doing with the problem.", vi: "Van de khong phai la van de. Van de la ban suy nghi qua nhieu ve no.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Don't just sit there. Do something. The answers will follow.", vi: "Dung chi ngoi do. Hay lam gi di. Cau tra loi se theo sau.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Action isn't just the effect of motivation; it's also the cause of it.", vi: "Hanh dong khong chi la ket qua cua dong luc; no cung la nguyen nhan tao ra dong luc.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "The more something threatens your identity, the more you will avoid it.", vi: "Dieu gi cang de doa ban sac cua ban, ban cang tranh ne no.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "If you're stuck on a problem, don't sit there and think about it; just start working on it. Even if you don't know what you're doing, the simple act of working on it will eventually cause the right ideas to show up in your head.", vi: "Neu ban mac ket voi van de, dung ngoi suy nghi; hay bat dau lam. Du khong biet minh dang lam gi, hanh dong don gian do se khien y tuong dung dan xuat hien.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Pain is an inextricable thread in the fabric of life, and to tear it out is not only impossible, but destructive.", vi: "Noi dau la soi chi khong the tach roi trong tam vai cuoc song, va xo no ra khong chi bat kha thi ma con huy hoai.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "This is the most simple and basic component of life: our struggles determine our successes.", vi: "Day la thanh phan don gian va co ban nhat cua cuoc song: nhung cuoc dau tranh quyet dinh thanh cong cua ta.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "To be happy we need something to solve. Happiness is therefore a form of action.", vi: "De hanh phuc chung ta can dieu gi do de giai quyet. Hanh phuc vi the la mot hinh thuc hanh dong.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "If you think about a young child trying to learn to walk, that child will fall down and hurt itself hundreds of times. But at no point does that child ever stop and think, 'I guess walking just isn't for me.'", vi: "Hay nghi ve dua tre tap di, no se nga va dau hang tram lan. Nhung khong luc nao no dung lai va nghi 'Chac la di bo khong hop voi minh.'", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "The rare people who do become truly exceptional at something do so not because they believe they're exceptional. On the contrary, they become amazing because they're obsessed with improvement.", vi: "Nhung nguoi hiem hoi tro nen xuat sac khong phai vi ho tin minh xuat sac. Nguoc lai, ho tro nen tuyet voi vi am anh voi su cai thien.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Travel is a fantastic self-development tool, because it extricates you from the values of your culture and shows you that another society can live with entirely different values and still function.", vi: "Du lich la cong cu phat trien ban than tuyet voi, vi no keo ban ra khoi gia tri van hoa va cho thay xa hoi khac co the song voi gia tri hoan toan khac ma van van hanh.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "We suffer for the simple reason that suffering is biologically useful. It is nature's preferred agent for inspiring change.", vi: "Chung ta dau kho vi ly do don gian rang dau kho co ich ve mat sinh hoc. No la tac nhan ma tu nhien ua thich de truyen cam hung thay doi.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Certainty is the enemy of growth.", vi: "Su chac chan la ke thu cua su truong thanh.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Life is essentially an endless series of problems. The solution to one problem is merely the creation of another.", vi: "Cuoc song ve ban chat la chuoi van de bat tan. Giai phap cho van de nay chi la tao ra van de khac.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "The more we choose to accept responsibility in our lives, the more power we will exercise over our lives.", vi: "Cang chap nhan trach nhiem trong cuoc song, chung ta cang co nhieu quyen luc tren cuoc doi minh.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Fault is past tense. Responsibility is present tense.", vi: "Loi lam la thi qua khu. Trach nhiem la thi hien tai.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "It's worth remembering that at one point everything in your life was new and exciting and you felt alive.", vi: "Dang nho rang co luc moi thu trong doi ban deu moi me, thu vi va ban cam thay song dong.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "There is a simple realization from which all personal improvement and growth emerges. This is the realization that we, individually, are responsible for everything in our lives.", vi: "Co mot nhan thuc don gian ma tu do moi su cai thien va truong thanh bat nguon. Do la nhan ra rang chinh chung ta chiu trach nhiem cho moi thu trong cuoc doi.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Decision-making based on emotional intuition, without the aid of reason to keep it in line, pretty much always sucks.", vi: "Ra quyet dinh dua tren truc giac cam xuc, khong co ly tri kiem soat, hau nhu luon te.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },
  { text: "Happiness comes from solving problems. Not from avoiding them or pretending they don't exist.", vi: "Hanh phuc den tu viec giai quyet van de. Khong phai tu tranh ne hay gia vo chung khong ton tai.", author: "Mark Manson", source: "The Subtle Art of Not Giving a F*ck" },

  // Can't Hurt Me — David Goggins (216-240)
  { text: "The only person who was going to turn my life around was me.", vi: "Nguoi duy nhat co the thay doi cuoc doi toi chinh la toi.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "We don't rise to the level of our expectations, we fall to the level of our training.", vi: "Chung ta khong vuon len tam ky vong, chung ta roi xuong tam luyen tap.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "You are in danger of living a life so comfortable and soft that you will die without ever realizing your true potential.", vi: "Ban dang co nguy co song cuoc doi qua thoai mai va mem yeu den muc chet ma khong bao gio nhan ra tiem nang that su.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "It's a lot more than mind over matter. It takes relentless self-discipline to schedule suffering into your day, every day.", vi: "Khong chi la y chi vuot qua vat chat. Can ky luat ban than khong ngung nghi de len lich cho kho dau moi ngay.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "When you think you're done, you're only at 40% of your total potential.", vi: "Khi ban nghi minh da het suc, ban moi chi o 40% tiem nang.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "No one is going to come help you. No one's coming to save you.", vi: "Khong ai den giup ban dau. Khong ai den cuu ban ca.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Mental toughness is a lifestyle.", vi: "Tinh than cung ran la loi song.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "The most important conversation is the one you have with yourself.", vi: "Cuoc doi thoai quan trong nhat la cuoc doi thoai voi chinh minh.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Suffering is a test. That's all it is. Suffering is the true test of life.", vi: "Dau kho la bai kiem tra. Chi co vay thoi. Dau kho la bai kiem tra that su cua cuoc doi.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "In the military we have a saying: if you ain't cheating, you ain't trying. But the reverse is also true. If you're cheating yourself, you're the one who'll pay.", vi: "Trong quan doi co cau: neu ban khong gian lan, ban chua co gang. Nhung dieu nguoc lai cung dung. Neu ban tu lua minh, ban la nguoi phai tra gia.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Denial is the ultimate comfort zone.", vi: "Phu nhan la vung an toan toi thuong.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "We all have the ability to come from nothing to something. But we gotta keep pushing through the darkness.", vi: "Tat ca chung ta deu co kha nang di tu so khong den thanh cong. Nhung phai tiep tuc vuot qua bong toi.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "You gotta start your journey. It may suck, but eventually you will come out the other side on top.", vi: "Ban phai bat dau hanh trinh. Co the se rat kho, nhung cuoi cung ban se vuot qua va len dinh.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Embrace the suck.", vi: "Hay om lay kho khan.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "It won't always go your way, so you can't get trapped in this idea that just because you've imagined a possibility for yourself that you somehow deserve it.", vi: "Moi thu khong phai luc nao cung thuan loi, nen dung mac ket trong y nghi rang chi vi ban tuong tuong ra kha nang thi ban xung dang co no.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Be uncommon amongst uncommon people.", vi: "Hay phi thuong giua nhung nguoi phi thuong.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "You have to build calluses on your brain just like how you build calluses on your hands.", vi: "Ban phai tao chai san cho nao bo giong nhu tao chai san cho ban tay.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Motivation is crap. Motivation comes and goes. When you're driven, whatever is in front of you will get destroyed.", vi: "Dong luc la vo nghia. Dong luc den roi di. Khi ban bi thuc day, bat cu thu gi truoc mat deu bi pha vo.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "I don't stop when I'm tired. I stop when I'm done.", vi: "Toi khong dung khi met. Toi dung khi xong.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Our culture has become hooked on the quick-fix, the life hack, efficiency. Everyone is looking for that pill, that new app, that special technique.", vi: "Van hoa chung ta da nghien giai phap nhanh, meo song, hieu qua. Ai cung tim vien thuoc than, ung dung moi, ky thuat dac biet.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "The only way to move beyond mediocrity is to push past your limits.", vi: "Cach duy nhat vuot qua tam thuong la vuot qua gioi han cua ban.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "The cookie jar is a concept where you put all your past achievements and hard moments you've overcome. When you hit a wall, you reach in the cookie jar for strength.", vi: "Lo banh la khai niem ban bo tat ca thanh tuu va khoanh khac kho khan da vuot qua vao do. Khi gap tuong, ban voi vao lo banh tim suc manh.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Tell yourself the truth! That you've gotten soft. That you've let your standards slip.", vi: "Hay noi su that voi chinh minh! Rang ban da tro nen yeu duoi. Rang ban da de tieu chuan tut xuong.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "You want to be uncommon amongst uncommon people. Period.", vi: "Ban muon la nguoi phi thuong giua nhung nguoi phi thuong. Cham het.", author: "David Goggins", source: "Can't Hurt Me" },
  { text: "Greatness is not something that if you meet it once it's forever. You have to meet it over and over again.", vi: "Su vi dai khong phai gap mot lan la mai mai. Ban phai gap no het lan nay den lan khac.", author: "David Goggins", source: "Can't Hurt Me" },

  // 12 Rules for Life — Jordan Peterson (241-265)
  { text: "Compare yourself to who you were yesterday, not to who someone else is today.", vi: "Hay so sanh ban than voi chinh minh ngay hom qua, khong phai voi nguoi khac hom nay.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Set your house in perfect order before you criticize the world.", vi: "Hay sap xep nha cua that ngay ngan truoc khi chi trich the gioi.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "To stand up straight with your shoulders back is to accept the terrible responsibility of life, with eyes wide open.", vi: "Dung thang vai ngay la chap nhan trach nhiem nang ne cua cuoc doi, voi doi mat mo to.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "The purpose of life is finding the largest burden that you can bear and bearing it.", vi: "Muc dich cuoc doi la tim ganh nang lon nhat ban co the mang va ganh vac no.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "You should take care of, help, and be good to yourself the same way you would take care of, help, and be good to someone you loved and valued.", vi: "Hay cham soc, giup do va doi xu tot voi ban than nhu cach ban doi xu voi nguoi ban yeu thuong va tran trong.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "If you can't even clean up your own room, who the hell are you to give advice to the world?", vi: "Neu ban khong don noi phong minh, ban la ai ma khuyen bao the gioi?", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Pursue what is meaningful, not what is expedient.", vi: "Hay theo duoi dieu co y nghia, khong phai dieu tien loi.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "You must determine where you are going in your life, because you cannot get there unless you move in that direction.", vi: "Ban phai xac dinh minh dang di dau, vi ban khong the den do neu khong di theo huong do.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "When you have something to say, silence is a lie.", vi: "Khi ban co dieu can noi, im lang la noi doi.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "It took untold generations to get you where you are. A little gratitude might be in order.", vi: "Phai bao nhieu the he moi dua ban den day. Mot chut biet on cung nen co.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "You're going to pay a price for every bloody thing you do and everything you don't do. You don't get to choose to not pay a price.", vi: "Ban se phai tra gia cho moi dieu ban lam va khong lam. Ban khong co quyen chon khong tra gia.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "If you fulfill your obligations every day you don't need to worry about the future.", vi: "Neu ban hoan thanh nghia vu moi ngay, ban khong can lo lang ve tuong lai.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Perhaps you are overvaluing what you don't have and undervaluing what you do.", vi: "Co le ban dang danh gia qua cao dieu khong co va qua thap dieu dang co.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "People organize their brains with conversation. If they don't have anyone to tell their story to, they lose their minds.", vi: "Con nguoi sap xep nao bo bang tro chuyen. Neu khong co ai de ke chuyen, ho se mat tri.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Don't underestimate the power of vision and direction. These are irresistible forces, able to transform what might appear to be unconquerable obstacles into traversable pathways.", vi: "Dung danh gia thap suc manh cua tam nhin va huong di. Day la nhung luc luong khong the cuong lai, co the bien tro ngai tuong nhu bat kha vao con duong co the di qua.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Make friends with people who want the best for you.", vi: "Hay ket ban voi nhung nguoi muon dieu tot nhat cho ban.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Do not let your children do anything that makes you dislike them.", vi: "Dung de con ban lam dieu gi khien ban khong ua chung.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Tell the truth — or, at least, don't lie.", vi: "Hay noi su that — hoac it nhat, dung noi doi.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Assume that the person you are listening to might know something you don't.", vi: "Hay gia dinh rang nguoi ban dang lang nghe co the biet dieu ban khong biet.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Be precise in your speech.", vi: "Hay chinh xac trong loi noi.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Do not bother children when they are skateboarding.", vi: "Dung quay ray tre con khi chung dang truot van.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Pet a cat when you encounter one on the street.", vi: "Hay vuot ve mot con meo khi ban gap no tren duong.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "What you aim at determines what you see.", vi: "Dieu ban nham toi quyet dinh dieu ban nhin thay.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Treat yourself as someone you are responsible for helping.", vi: "Hay doi xu voi ban than nhu nguoi ma ban co trach nhiem giup do.", author: "Jordan Peterson", source: "12 Rules for Life" },
  { text: "Intolerance of others' views — no matter how ignorant or incoherent they may be — is not simply wrong; in a world where there is no right or wrong, it is worse: it is a failure of imagination.", vi: "Khong dung nap quan diem nguoi khac — du no thieu hieu biet hay thieu logic — khong chi sai; trong the gioi khong co dung sai, no te hon: no la su that bai cua tri tuong tuong.", author: "Jordan Peterson", source: "12 Rules for Life" },

  // Awaken the Giant Within — Tony Robbins (266-285)
  { text: "It is in your moments of decision that your destiny is shaped.", vi: "Chinh trong nhung khoanh khac quyet dinh ma so phan ban duoc dinh hinh.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "If you do what you've always done, you'll get what you've always gotten.", vi: "Neu ban lam dieu luon lam, ban se nhan dieu luon nhan.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Setting goals is the first step in turning the invisible into the visible.", vi: "Dat muc tieu la buoc dau tien bien dieu vo hinh thanh huu hinh.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "It's not what we do once in a while that shapes our lives, but what we do consistently.", vi: "Khong phai dieu ta thi thoang lam dinh hinh cuoc doi, ma la dieu ta lam deu dan.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "The path to success is to take massive, determined action.", vi: "Con duong toi thanh cong la hanh dong quyet liet va manh me.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "The only thing that's keeping you from getting what you want is the story you keep telling yourself.", vi: "Dieu duy nhat ngan ban co duoc dieu muon la cau chuyen ban tu ke cho minh.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "It is not what happens to us that determines our lives — it is what we make of what happens.", vi: "Khong phai dieu xay ra quyet dinh cuoc doi chung ta — ma la cach chung ta xu ly dieu xay ra.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "A real decision is measured by the fact that you've taken a new action. If there's no action, you haven't truly decided.", vi: "Quyet dinh that su duoc do bang viec ban da hanh dong moi. Neu khong co hanh dong, ban chua thuc su quyet dinh.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Your life changes the moment you make a new, congruent, and committed decision.", vi: "Cuoc doi ban thay doi ngay khoanh khac ban dua ra quyet dinh moi, nhat quan va kien dinh.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Using the power of decision gives you the capacity to get past any excuse to change any and every part of your life in an instant.", vi: "Su dung suc manh quyet dinh cho ban kha nang vuot qua moi ly do de thay doi bat ky phan nao cuoc doi trong tich tac.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "People are not lazy. They simply have impotent goals — that is, goals that do not inspire them.", vi: "Con nguoi khong luoi. Ho chi co nhung muc tieu yeu ot — nhung muc tieu khong truyen cam hung.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Where focus goes, energy flows.", vi: "Tap trung vao dau, nang luong chay ve do.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "The secret of success is learning how to use pain and pleasure instead of having pain and pleasure use you.", vi: "Bi quyet thanh cong la hoc cach su dung noi dau va niem vui thay vi de chung su dung ban.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "We can change our lives. We can do, have, and be exactly what we wish.", vi: "Chung ta co the thay doi cuoc doi. Co the lam, co, va tro thanh dung dieu ta muon.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "The quality of your life is the quality of your relationships.", vi: "Chat luong cuoc song la chat luong cac moi quan he.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "I challenge you to make your life a masterpiece. I challenge you to join the ranks of those people who live what they teach, who walk their talk.", vi: "Toi thach ban bien cuoc doi thanh kiet tac. Toi thach ban gia nhap hang ngu nhung nguoi song dung nhu nhung gi ho day.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Stay committed to your decisions, but stay flexible in your approach.", vi: "Hay kien dinh voi quyet dinh, nhung linh hoat trong cach tiep can.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "For changes to be of any true value, they've got to be lasting and consistent.", vi: "De thay doi co gia tri that su, chung phai ben vung va nhat quan.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "We will act consistently with our view of who we truly are, whether that view is accurate or not.", vi: "Chung ta se hanh dong nhat quan voi cach nhin ve chinh minh, du cach nhin do co chinh xac hay khong.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Beliefs have the power to create and the power to destroy.", vi: "Niem tin co suc manh tao dung va suc manh huy diet.", author: "Tony Robbins", source: "Awaken the Giant Within" },

  // The Magic of Thinking Big — David Schwartz (286-305)
  { text: "Believe it can be done. When you believe something can be done, your mind will find the ways to do it.", vi: "Hay tin rang no co the lam duoc. Khi ban tin, tri oc se tim ra cach.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Think big and you'll live big. You'll live big in happiness. You'll live big in accomplishment.", vi: "Nghi lon va ban se song lon. Song lon trong hanh phuc. Song lon trong thanh tuu.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Action cures fear, while inaction creates terror.", vi: "Hanh dong chua lanh noi so, trong khi khong hanh dong tao ra kinh hoang.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Do what you fear and fear disappears.", vi: "Hay lam dieu ban so va noi so se bien mat.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Look at things not as they are, but as they can be. Visualization adds value to everything.", vi: "Hay nhin su vat khong nhu chung dang la, ma nhu chung co the tro thanh. Hinh dung tang gia tri cho moi thu.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "The thinking that guides your intelligence is much more important than how much intelligence you have.", vi: "Tu duy dan dat tri tue quan trong hon nhieu so voi luong tri tue ban co.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Those who believe they can move mountains, do. Those who believe they can't, cannot.", vi: "Nguoi tin co the doi nui thi lam duoc. Nguoi tin khong the thi khong the.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "To fight fear, act. To increase fear — wait, put off, postpone.", vi: "De chong lai so hai, hay hanh dong. De tang so hai — cho doi, tri hoan.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "How you think when you lose determines how long it will be until you win.", vi: "Cach ban suy nghi khi thua quyet dinh bao lau nua ban se thang.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Success is determined not so much by the size of one's brain as it is by the size of one's thinking.", vi: "Thanh cong khong do kich thuoc nao bo ma do kich thuoc tu duy.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Remind yourself regularly that you are better than you think you are. Successful people are not superhuman.", vi: "Hay thuong xuyen nhac minh rang ban gioi hon ban nghi. Nguoi thanh cong khong phai sieu nhan.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Capacity is a state of mind. How much we can do depends on how much we think we can do.", vi: "Nang luc la trang thai cua tri oc. Chung ta lam duoc bao nhieu phu thuoc vao viec ta nghi minh lam duoc bao nhieu.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Every big accomplishment is a series of little accomplishments.", vi: "Moi thanh tuu lon la chuoi nhung thanh tuu nho.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Think little goals and expect little achievements. Think big goals and win big success.", vi: "Nghi muc tieu nho va ky vong thanh tuu nho. Nghi muc tieu lon va gianh thanh cong lon.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Nothing, absolutely nothing, in this life gives you more satisfaction than knowing you're on the road to success and achievement.", vi: "Khong gi, tuyet doi khong gi, trong cuoc doi nay mang lai nhieu hai long hon viec biet ban dang tren duong den thanh cong.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "When you believe, your mind finds ways to do.", vi: "Khi ban tin, tri oc se tim ra cach.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Go first class. That is one of the wisest things you can do for yourself.", vi: "Hay chon hang nhat. Do la mot trong nhung dieu khon ngoan nhat ban co the lam cho minh.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Surrender to what is. Let go of what was. Have faith in what will be.", vi: "Chap nhan nhung gi dang la. Buong bo nhung gi da qua. Tin vao nhung gi se den.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "People who tell you it cannot be done almost always are unsuccessful people, strictly average or mediocre at best.", vi: "Nguoi noi ban khong the lam duoc hau nhu luon la nguoi that bai, trung binh hoac tam thuong.", author: "David Schwartz", source: "The Magic of Thinking Big" },
  { text: "Your mind is a thought factory. And the thoughts you produce will determine how you feel and act.", vi: "Tri oc ban la nha may suy nghi. Va nhung suy nghi ban tao ra se quyet dinh cam xuc va hanh dong.", author: "David Schwartz", source: "The Magic of Thinking Big" },

  // You Are a Badass — Jen Sincero (306-325)
  { text: "You are responsible for what you say and do. You are not responsible for whether or not people freak out about it.", vi: "Ban chiu trach nhiem ve loi noi va hanh dong cua minh. Ban khong chiu trach nhiem ve viec nguoi khac co phat dien hay khong.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "You need to go from wanting to change your life to deciding to change your life.", vi: "Ban can chuyen tu muon thay doi cuoc doi sang quyet dinh thay doi cuoc doi.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "What other people think about you has nothing to do with you and everything to do with them.", vi: "Nguoi khac nghi gi ve ban khong lien quan den ban ma hoan toan lien quan den ho.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "If you're serious about changing your life, you'll find a way. If you're not, you'll find an excuse.", vi: "Neu ban nghiem tuc thay doi cuoc doi, ban se tim ra cach. Neu khong, ban se tim ly do.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "You are loved. Massively. Ferociously. Unconditionally. The Universe is totally freaking out about how awesome you are.", vi: "Ban duoc yeu thuong. Manh me. Mung ro. Vo dieu kien. Vu tru dang phat dien vi ban tuyet voi den the.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "Most answers reveal themselves through doing, not thinking.", vi: "Hau het cau tra loi tu lo ra qua hanh dong, khong phai suy nghi.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "The only failure is quitting. Everything else is just gathering information.", vi: "That bai duy nhat la bo cuoc. Moi thu khac chi la thu thap thong tin.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "Our fantasies are our realities in an ugly duckling stage.", vi: "Nhung tuong tuong cua chung ta la thuc te dang trong giai doan vit con xau xi.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "It's not your job to like, love, or respect me. It's mine.", vi: "Viec thich, yeu hay ton trong toi khong phai viec cua ban. La viec cua toi.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "When you change who you are being, you are changing your entire universe.", vi: "Khi ban thay doi con nguoi minh dang la, ban dang thay doi ca vu tru cua minh.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "So often we pretend we've made a decision, when what we've really done is signed up to try until it gets too uncomfortable.", vi: "Chung ta thuong gia vo da quyet dinh, trong khi thuc su chi dang dang ky thu cho den khi qua kho chiu.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "The moment you decide to forgive and let your negative feelings melt away, you are on the road to freedom.", vi: "Khoanh khac ban quyet dinh tha thu va de cam xuc tieu cuc tan di, ban dang tren duong den tu do.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "You are perfect. To think anything less is as pointless as a river thinking that it's got too many curves or that it moves too slowly.", vi: "Ban la hoan hao. Nghi bat cu dieu gi kem hon la vo nghia nhu con song nghi minh qua nhieu khuc cua hay chay qua cham.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "If you want to live a life you've never lived, you have to do things you've never done.", vi: "Neu muon song cuoc doi chua tung song, ban phai lam nhung dieu chua tung lam.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "Faith is having the audacity to believe in something you can't see.", vi: "Niem tin la su lieu linh tin vao dieu ban khong the nhin thay.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "You have to change your thinking first, and then the evidence comes. Our big mistake is that we do it the other way around.", vi: "Ban phai thay doi suy nghi truoc, roi bang chung se den. Sai lam lon cua chung ta la lam nguoc lai.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "We need to be the kind of people who can fall down, get back up, and go all in regardless.", vi: "Chung ta can la kieu nguoi co the nga, dung day va lao vao bat chap.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "Comparing yourself to others is the fastest way to take all the fun out of life.", vi: "So sanh ban than voi nguoi khac la cach nhanh nhat de mat het niem vui trong cuoc song.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "We only have so many trips around the sun. Don't waste any of them living someone else's dream.", vi: "Chung ta chi co bao nhieu vong quanh mat troi. Dung lang phi bat ky vong nao de song giac mo cua nguoi khac.", author: "Jen Sincero", source: "You Are a Badass" },
  { text: "Taking a leap of faith is better than building a fortress of doubt.", vi: "Nhay mot buoc tin tuong tot hon xay phao dai nghi ngo.", author: "Jen Sincero", source: "You Are a Badass" },

  // The Four Agreements — Don Miguel Ruiz (326-350)
  { text: "Be impeccable with your word.", vi: "Hay hoan hao voi loi noi cua ban.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Don't take anything personally.", vi: "Dung ca nhan hoa bat cu dieu gi.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Don't make assumptions.", vi: "Dung gia dinh.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Always do your best.", vi: "Luon lam het suc minh.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Speak with integrity. Say only what you mean. Avoid using the word to speak against yourself or to gossip about others.", vi: "Noi voi su chinh truc. Chi noi dieu ban thuc su muon noi. Tranh dung loi noi chong lai minh hay noi xau nguoi khac.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Nothing others do is because of you. What others say and do is a projection of their own reality, their own dream.", vi: "Khong dieu gi nguoi khac lam la vi ban. Nhung gi nguoi khac noi va lam la su phan chieu thuc tai va giac mo cua chinh ho.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Find the courage to ask questions and to express what you really want. Communicate with others as clearly as you can to avoid misunderstandings.", vi: "Hay can dam dat cau hoi va bay to dieu ban thuc su muon. Giao tiep ro rang nhat co the de tranh hieu lam.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Your best is going to change from moment to moment; it will be different when you are healthy as opposed to sick.", vi: "Het suc cua ban se thay doi tung khoanh khac; no se khac khi ban khoe so voi khi ban om.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "If someone is not treating you with love and respect, it is a gift if they walk away from you.", vi: "Neu ai do khong doi xu voi ban bang tinh yeu va su ton trong, ho ra di la mot mon qua.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "The word is the most powerful tool you have as a human; it is the tool of magic.", vi: "Loi noi la cong cu manh me nhat cua con nguoi; no la cong cu cua phep mau.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "We only see what we want to see; we only hear what we want to hear. Our belief system is just like a mirror that only shows us what we believe.", vi: "Chung ta chi nhin thay dieu muon thay, chi nghe dieu muon nghe. He thong niem tin giong nhu tam guong chi phan chieu dieu ta tin.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "If others tell us something, we make assumptions, and if they don't tell us something, we make assumptions to fulfill our need to know.", vi: "Neu nguoi khac noi gi do, ta gia dinh. Neu ho khong noi, ta van gia dinh de thoa man nhu cau biet.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Real love is accepting other people the way they are without trying to change them.", vi: "Tinh yeu that su la chap nhan nguoi khac nhu ho von la ma khong co thay doi ho.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Wherever you go you will find people lying to you, and as your awareness grows, you will notice that you also lie to yourself.", vi: "Di dau ban cung gap nguoi noi doi ban, va khi nhan thuc lon len, ban se thay minh cung tu noi doi.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Death is not the biggest fear we have; our biggest fear is taking the risk to be alive.", vi: "Cai chet khong phai noi so lon nhat; noi so lon nhat la lieu linh de duoc song that su.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "You don't need to justify your love, you don't need to explain your love, you just need to practice your love.", vi: "Ban khong can bien minh cho tinh yeu, khong can giai thich tinh yeu, chi can thuc hanh tinh yeu.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "In your whole life nobody has ever abused you more than you have abused yourself.", vi: "Ca doi ban khong ai nguu doi ban nhieu hon chinh ban nguu doi ban than.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "The way to keep yourself from making assumptions is to ask questions.", vi: "Cach de khong gia dinh la dat cau hoi.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Every human is an artist. The dream of your life is to make beautiful art.", vi: "Moi nguoi deu la nghe si. Giac mo cua cuoc doi ban la tao ra nghe thuat dep.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "You were born with the right to be happy. You were born with the right to love, to enjoy, and to share your love.", vi: "Ban sinh ra voi quyen duoc hanh phuc. Ban sinh ra voi quyen yeu thuong, tan huong va chia se tinh yeu.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "If you live in a past dream, you don't enjoy what is happening right now because you will always wish it to be different than it is.", vi: "Neu ban song trong giac mo qua khu, ban khong tan huong hien tai vi luc nao cung uoc no khac di.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Forgiveness is the only way to heal.", vi: "Tha thu la cach duy nhat de chua lanh.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "If you can see yourself as an artist, and you can see that your life is your own creation, then why not create the most beautiful story for yourself?", vi: "Neu ban thay minh la nghe si, va cuoc doi la tac pham cua minh, sao khong tao ra cau chuyen dep nhat cho ban?", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "When you are immune to the opinions and actions of others, you won't be the victim of needless suffering.", vi: "Khi ban mien nhiem voi y kien va hanh dong cua nguoi khac, ban se khong la nan nhan cua dau kho vo ich.", author: "Don Miguel Ruiz", source: "The Four Agreements" },
  { text: "Use the word to share your love. Use white magic, beginning with yourself.", vi: "Hay dung loi noi de chia se tinh yeu. Hay dung phep mau trang, bat dau tu chinh minh.", author: "Don Miguel Ruiz", source: "The Four Agreements" },

  // Deep Work — Cal Newport (351-375)
  { text: "If you don't produce, you won't thrive — no matter how skilled or talented you are.", vi: "Neu ban khong tao ra san pham, ban se khong phat trien — du ban gioi hay tai nang den dau.", author: "Cal Newport", source: "Deep Work" },
  { text: "Clarity about what matters provides clarity about what does not.", vi: "Ro rang ve dieu quan trong mang lai su ro rang ve dieu khong quan trong.", author: "Cal Newport", source: "Deep Work" },
  { text: "Two core abilities for thriving in the new economy: the ability to quickly master hard things, and the ability to produce at an elite level.", vi: "Hai nang luc cot loi de phat trien trong nen kinh te moi: kha nang nhanh chong thong thao dieu kho va kha nang san xuat o dang cap cao.", author: "Cal Newport", source: "Deep Work" },
  { text: "The key to developing a deep work habit is to move beyond good intentions and add routines and rituals designed to minimize the amount of your limited willpower necessary to transition into and maintain a state of unbroken concentration.", vi: "Chia khoa phat trien thoi quen lam viec sau la vuot qua y dinh tot va them thu tuc giup giam thieu y chi can thiet de duy tri trang thai tap trung khong gian doan.", author: "Cal Newport", source: "Deep Work" },
  { text: "Who you are, what you think, feel, and do, what you love — is the sum of what you focus on.", vi: "Ban la ai, ban nghi gi, cam gi, lam gi, yeu gi — la tong hop cua nhung gi ban tap trung vao.", author: "Cal Newport", source: "Deep Work" },
  { text: "A deep life is a good life, any way you look at it.", vi: "Cuoc song sau sac la cuoc song tot dep, nhin tu bat ky goc do nao.", author: "Cal Newport", source: "Deep Work" },
  { text: "If every moment of potential boredom in your life is relieved with a glance at your smartphone, then your brain has likely been rewired to a point where it's not ready for deep work.", vi: "Neu moi khoanh khac nham chan deu duoc giai toa bang cai nhin vao dien thoai, nao bo ban co le da bi tai lap den muc khong san sang cho cong viec sau.", author: "Cal Newport", source: "Deep Work" },
  { text: "To simply wait and be bored has become a novel experience in modern life, but from the perspective of concentration training, it's incredibly valuable.", vi: "Don gian cho doi va buon chan da tro thanh trai nghiem moi la trong cuoc song hien dai, nhung tu goc do ren luyen tap trung, no vo cung gia tri.", author: "Cal Newport", source: "Deep Work" },
  { text: "Human beings, it seems, are at their best when immersed deeply in something challenging.", vi: "Con nguoi, co ve, o trang thai tot nhat khi dam minh sau vao dieu gi do thach thuc.", author: "Cal Newport", source: "Deep Work" },
  { text: "The ability to perform deep work is becoming increasingly rare at exactly the same time it is becoming increasingly valuable in our economy.", vi: "Kha nang lam viec sau dang ngay cang hiem dung vao luc no ngay cang co gia tri trong nen kinh te.", author: "Cal Newport", source: "Deep Work" },
  { text: "Don't take breaks from distraction. Instead take breaks from focus.", vi: "Dung nghi giua luc mat tap trung. Thay vao do hay nghi giua luc tap trung.", author: "Cal Newport", source: "Deep Work" },
  { text: "Less mental clutter means more mental resources available for deep thinking.", vi: "It lon xon tinh than hon nghia la nhieu nguon luc tinh than hon cho tu duy sau.", author: "Cal Newport", source: "Deep Work" },
  { text: "Efforts to deepen your focus will struggle if you don't simultaneously wean your mind from a dependence on distraction.", vi: "No luc tap trung sau se that bai neu ban khong dong thoi cai nghien phan tan cho tri oc.", author: "Cal Newport", source: "Deep Work" },
  { text: "The batching of hard but important intellectual work into long, uninterrupted stretches is the key to high productivity.", vi: "Gom cong viec tri tue kho nhung quan trong thanh nhung khoang dai khong gian doan la chia khoa cua nang suat cao.", author: "Cal Newport", source: "Deep Work" },
  { text: "What we choose to focus on and what we choose to ignore plays in defining the quality of our life.", vi: "Dieu chung ta chon tap trung vao va dieu chung ta chon bo qua gop phan dinh nghia chat luong cuoc song.", author: "Cal Newport", source: "Deep Work" },
  { text: "To learn hard things quickly, you must focus intensely without distraction.", vi: "De hoc nhanh nhung dieu kho, ban phai tap trung cao do khong phan tan.", author: "Cal Newport", source: "Deep Work" },
  { text: "High-quality work produced equals time spent multiplied by intensity of focus.", vi: "Cong viec chat luong cao bang thoi gian bo ra nhan cuong do tap trung.", author: "Cal Newport", source: "Deep Work" },
  { text: "Be so good they can't ignore you.", vi: "Hay gioi den muc ho khong the pho lo ban.", author: "Cal Newport", source: "Deep Work" },
  { text: "Three to four hours a day, five days a week, of uninterrupted and carefully directed concentration, it turns out, can produce a lot of valuable output.", vi: "Ba den bon gio moi ngay, nam ngay mot tuan, tap trung khong gian doan va co dinh huong, hoa ra co the tao ra rat nhieu san pham gia tri.", author: "Cal Newport", source: "Deep Work" },
  { text: "Your will is not a manifestation of your character that you can deploy without limit; it's instead like a muscle that tires.", vi: "Y chi khong phai bieu hien tinh cach ban co the dung khong gioi han; no giong co bap se met moi.", author: "Cal Newport", source: "Deep Work" },
  { text: "If you want to eliminate the addictive pull of entertainment sites on your time and attention, give your brain a quality alternative.", vi: "Neu muon loai bo suc hut giai tri len thoi gian va su chu y, hay cho nao bo mot lua chon chat luong.", author: "Cal Newport", source: "Deep Work" },
  { text: "Idleness is not just a vacation, an indulgence or a vice; it is as indispensable to the brain as vitamin D is to the body.", vi: "Nhan roi khong chi la nghi phep hay thu vui; no can thiet cho nao bo nhu vitamin D can cho co the.", author: "Cal Newport", source: "Deep Work" },
  { text: "The deep life, of course, is not for everybody. It requires hard work and drastic changes to your habits.", vi: "Cuoc song sau sac, tat nhien, khong danh cho tat ca. No doi hoi lam viec cham chi va thay doi lon trong thoi quen.", author: "Cal Newport", source: "Deep Work" },
  { text: "You have a finite amount of willpower that becomes depleted as you use it. Your will, in other words, is not a manifestation of your character that you can deploy without limit.", vi: "Ban co luong y chi huu han va no can kiet khi su dung. Noi cach khac, y chi khong phai thu ban co the dung khong gioi han.", author: "Cal Newport", source: "Deep Work" },
  { text: "Concentration so intense that there is no attention left over to think about anything irrelevant, or to worry about problems.", vi: "Tap trung manh me den muc khong con su chu y nao de nghi ve dieu khong lien quan hay lo lang ve van de.", author: "Cal Newport", source: "Deep Work" },

  // Additional motivation quotes (376-400)
  { text: "The only way to do great work is to love what you do.", vi: "Cach duy nhat de lam viec tuyet voi la yeu nhung gi ban lam.", author: "Steve Jobs", source: "Speech" },
  { text: "Your time is limited, so don't waste it living someone else's life.", vi: "Thoi gian cua ban co han, nen dung lang phi no de song cuoc doi nguoi khac.", author: "Steve Jobs", source: "Speech" },
  { text: "Stay hungry, stay foolish.", vi: "Hay luon khat khao, hay luon dai kho.", author: "Steve Jobs", source: "Speech" },
  { text: "Have the courage to follow your heart and intuition. They somehow already know what you truly want to become.", vi: "Hay can dam theo trai tim va truc giac. Chung bang cach nao do da biet ban thuc su muon tro thanh gi.", author: "Steve Jobs", source: "Speech" },
  { text: "Innovation distinguishes between a leader and a follower.", vi: "Doi moi phan biet nguoi dan dau va nguoi theo sau.", author: "Steve Jobs", source: "Interview" },
  { text: "The people who are crazy enough to think they can change the world are the ones who do.", vi: "Nhung nguoi dien ro du de tin ho co the thay doi the gioi chinh la nhung nguoi lam duoc dieu do.", author: "Steve Jobs", source: "Speech" },
  { text: "Sometimes life hits you in the head with a brick. Don't lose faith.", vi: "Doi khi cuoc doi danh vao dau ban mot cuc gach. Dung mat niem tin.", author: "Steve Jobs", source: "Speech" },
  { text: "Remembering that you are going to die is the best way I know to avoid the trap of thinking you have something to lose.", vi: "Nho rang ban se chet la cach tot nhat toi biet de tranh cai bay nghi rang ban co gi do de mat.", author: "Steve Jobs", source: "Speech" },
  { text: "I'm convinced that about half of what separates the successful entrepreneurs from the non-successful ones is pure perseverance.", vi: "Toi tin rang khoang mot nua dieu tach biet doanh nhan thanh cong va khong thanh cong la su kien tri thuan tuy.", author: "Steve Jobs", source: "Interview" },
  { text: "Quality is more important than quantity. One home run is much better than two doubles.", vi: "Chat luong quan trong hon so luong. Mot cu danh hoan hao tot hon hai cu danh tam thuong.", author: "Steve Jobs", source: "Interview" },
  { text: "If today were the last day of my life, would I want to do what I am about to do today?", vi: "Neu hom nay la ngay cuoi cung cua doi toi, toi co muon lam dieu toi sap lam hom nay khong?", author: "Steve Jobs", source: "Speech" },
  { text: "Details matter, it's worth waiting to get it right.", vi: "Chi tiet quan trong, dang de cho de lam dung.", author: "Steve Jobs", source: "Interview" },
  { text: "You can't connect the dots looking forward; you can only connect them looking backwards.", vi: "Ban khong the noi cac diem khi nhin ve phia truoc; ban chi co the noi chung khi nhin lai phia sau.", author: "Steve Jobs", source: "Speech" },
  { text: "Design is not just what it looks like and feels like. Design is how it works.", vi: "Thiet ke khong chi la hinh thuc va cam giac. Thiet ke la cach no van hanh.", author: "Steve Jobs", source: "Interview" },
  { text: "Being the richest man in the cemetery doesn't matter to me. Going to bed at night saying we've done something wonderful, that's what matters to me.", vi: "La nguoi giau nhat nghia trang khong quan trong voi toi. Di ngu ma noi chung ta da lam dieu tuyet voi, do moi quan trong.", author: "Steve Jobs", source: "Interview" },
  { text: "Simple can be harder than complex. You have to work hard to get your thinking clean to make it simple.", vi: "Don gian co the kho hon phuc tap. Ban phai lam viec cham chi de lam sach tu duy va lam no don gian.", author: "Steve Jobs", source: "Interview" },
  { text: "Life can be much broader once you discover one simple fact: Everything around you that you call life was made up by people that were no smarter than you.", vi: "Cuoc song co the rong lon hon nhieu khi ban kham pha mot su that don gian: Moi thu xung quanh ban goi la cuoc song deu do nhung nguoi khong thong minh hon ban tao ra.", author: "Steve Jobs", source: "Interview" },
  { text: "I think if you do something and it turns out pretty good, then you should go do something else wonderful, not dwell on it for too long.", vi: "Toi nghi neu ban lam dieu gi do va no kha tot, hay di lam dieu tuyet voi khac, dung nam vuong qua lau.", author: "Steve Jobs", source: "Interview" },
  { text: "My favorite things in life don't cost any money. It's really clear that the most precious resource we all have is time.", vi: "Nhung dieu toi yeu thich trong doi khong ton tien. Rat ro rang nguon tai nguyen quy gia nhat chung ta co la thoi gian.", author: "Steve Jobs", source: "Interview" },
  { text: "Don't let the noise of others' opinions drown out your own inner voice.", vi: "Dung de tieng on y kien nguoi khac at di tieng noi noi tam cua ban.", author: "Steve Jobs", source: "Speech" },
  { text: "We're here to put a dent in the universe. Otherwise why else even be here?", vi: "Chung ta o day de tao dau an trong vu tru. Neu khong thi tai sao phai o day?", author: "Steve Jobs", source: "Interview" },
  { text: "It doesn't make sense to hire smart people and tell them what to do; we hire smart people so they can tell us what to do.", vi: "Khong co ly gi tuyen nguoi gioi roi bao ho phai lam gi; chung ta tuyen nguoi gioi de ho noi cho chung ta phai lam gi.", author: "Steve Jobs", source: "Interview" },
  { text: "Great things in business are never done by one person. They're done by a team of people.", vi: "Nhung dieu vi dai trong kinh doanh khong bao gio do mot nguoi lam. Chung do ca doi lam.", author: "Steve Jobs", source: "Interview" },
  { text: "Sometimes when you innovate, you make mistakes. It is best to admit them quickly, and get on with improving your other innovations.", vi: "Doi khi khi doi moi, ban mac sai. Tot nhat la thua nhan nhanh va tiep tuc cai thien nhung doi moi khac.", author: "Steve Jobs", source: "Interview" },
  { text: "I want to put a ding in the universe.", vi: "Toi muon tao mot vet lom trong vu tru.", author: "Steve Jobs", source: "Interview" },

  // ============================================================
  // LEADERSHIP / BUSINESS (200 quotes)
  // ============================================================

  // Good to Great — Jim Collins (401-425)
  { text: "Good is the enemy of great.", vi: "Tot la ke thu cua vi dai.", author: "Jim Collins", source: "Good to Great" },
  { text: "Greatness is not a function of circumstance. Greatness, it turns out, is largely a matter of conscious choice, and discipline.", vi: "Su vi dai khong phu thuoc hoan canh. Su vi dai phan lon la van de lua chon co y thuc va ky luat.", author: "Jim Collins", source: "Good to Great" },
  { text: "Level 5 leaders channel their ego needs away from themselves and into the larger goal of building a great company.", vi: "Lanh dao cap 5 chuyen nhu cau ban nga ra khoi ban than vao muc tieu lon hon la xay dung cong ty vi dai.", author: "Jim Collins", source: "Good to Great" },
  { text: "A company should limit its growth based on its ability to attract enough of the right people.", vi: "Cong ty nen gioi han tang truong dua tren kha nang thu hut du nguoi phu hop.", author: "Jim Collins", source: "Good to Great" },
  { text: "Get the right people on the bus, the wrong people off the bus, and the right people in the right seats.", vi: "Dua dung nguoi len xe, dua nguoi sai xuong xe, va dat dung nguoi vao dung cho.", author: "Jim Collins", source: "Good to Great" },
  { text: "The good-to-great leaders never wanted to become larger-than-life heroes. They never aspired to be put on a pedestal.", vi: "Cac lanh dao tu tot den vi dai chua bao gio muon tro thanh anh hung huyen thoai. Ho chua bao gio khao khat duoc ton vinh.", author: "Jim Collins", source: "Good to Great" },
  { text: "Confront the brutal facts of your current reality, whatever they might be.", vi: "Doi mat voi su that phu phang cua thuc tai, du chung la gi.", author: "Jim Collins", source: "Good to Great" },
  { text: "The Hedgehog Concept: What you are deeply passionate about, what drives your economic engine, and what you can be the best in the world at.", vi: "Khai niem Con Nhim: Dieu ban dam me sau sac, dieu thuc day dong co kinh te, va dieu ban co the gioi nhat the gioi.", author: "Jim Collins", source: "Good to Great" },
  { text: "Great vision without great people is irrelevant.", vi: "Tam nhin vi dai khong co nguoi vi dai la vo nghia.", author: "Jim Collins", source: "Good to Great" },
  { text: "The purpose of bureaucracy is to compensate for incompetence and lack of discipline.", vi: "Muc dich cua bo may quan lieu la bu dap cho su bat tai va thieu ky luat.", author: "Jim Collins", source: "Good to Great" },
  { text: "Technology accelerators, not technology creators. Technology alone never drives greatness.", vi: "Cong nghe la chat xuc tac, khong phai nguoi tao ra. Cong nghe don le khong bao gio tao nen su vi dai.", author: "Jim Collins", source: "Good to Great" },
  { text: "Those who build great companies understand that the ultimate throttle on growth for any great company is not markets, or technology, or competition, or products. It is one thing above all others: the ability to get and keep enough of the right people.", vi: "Nguoi xay dung cong ty vi dai hieu rang gioi han tang truong cuoi cung khong phai thi truong, cong nghe, canh tranh hay san pham. Ma la kha nang tim va giu du nguoi phu hop.", author: "Jim Collins", source: "Good to Great" },
  { text: "Yes, leadership is about vision. But leadership is equally about creating a climate where the truth is heard and the brutal facts confronted.", vi: "Dung, lanh dao la ve tam nhin. Nhung lanh dao cung la tao moi truong noi su that duoc lang nghe va su that phu phang duoc doi mat.", author: "Jim Collins", source: "Good to Great" },
  { text: "The flywheel effect: each turn builds upon work done earlier, compounding your investment of effort.", vi: "Hieu ung banh da: moi vong quay xay tren cong viec truoc do, nhan gap no luc dau tu.", author: "Jim Collins", source: "Good to Great" },
  { text: "When you have disciplined people, you don't need hierarchy. When you have disciplined thought, you don't need bureaucracy.", vi: "Khi co nguoi ky luat, ban khong can cap bac. Khi co tu duy ky luat, ban khong can bo may quan lieu.", author: "Jim Collins", source: "Good to Great" },
  { text: "The moment you feel the need to tightly manage someone, you've made a hiring mistake.", vi: "Khoanh khac ban thay can quan ly chat ai do, ban da tuyen nham.", author: "Jim Collins", source: "Good to Great" },
  { text: "Retain faith that you will prevail in the end, regardless of the difficulties, and at the same time, confront the most brutal facts of your current reality.", vi: "Giu niem tin rang ban se chien thang cuoi cung, bat chap kho khan, dong thoi doi mat voi su that phu phang nhat cua thuc tai.", author: "Jim Collins", source: "Good to Great" },
  { text: "It is impossible to have a great life unless it is a meaningful life. And it is very difficult to have a meaningful life without meaningful work.", vi: "Khong the co cuoc doi vi dai neu khong co y nghia. Va rat kho co cuoc doi y nghia ma khong co cong viec y nghia.", author: "Jim Collins", source: "Good to Great" },
  { text: "The essential strategic difference between the good-to-great and comparison companies lay in two fundamental distinctions. First, they got the right people on the bus. Second, they had Level 5 leadership.", vi: "Khac biet chien luoc cot loi giua cong ty tu tot den vi dai nam o hai dieu. Thu nhat, ho dua dung nguoi len xe. Thu hai, ho co lanh dao cap 5.", author: "Jim Collins", source: "Good to Great" },
  { text: "Expending energy trying to motivate people is largely a waste of time. If you have the right people on the bus, they will be self-motivated.", vi: "Tieu hao nang luong co tao dong luc cho nguoi khac phan lon la lang phi. Neu ban co dung nguoi, ho se tu tao dong luc.", author: "Jim Collins", source: "Good to Great" },
  { text: "True discipline requires the independence of mind to reject pressures to conform in ways incompatible with values, performance standards, and long-term aspirations.", vi: "Ky luat that su can tu duy doc lap de tu choi ap luc tuan thu theo cach khong tuong thich voi gia tri, tieu chuan va khat vong dai han.", author: "Jim Collins", source: "Good to Great" },
  { text: "The comparison companies were more like hedgehogs that never found a concept, or, worse, like foxes that never settled down to one concept.", vi: "Cac cong ty doi chung giong nhu nhim khong bao gio tim ra khai niem, hoac te hon, nhu cao chua bao gio on dinh voi mot khai niem.", author: "Jim Collins", source: "Good to Great" },
  { text: "The good-to-great companies made a habit of putting their best people on their best opportunities, not their biggest problems.", vi: "Cong ty tu tot den vi dai co thoi quen dat nguoi gioi nhat vao co hoi tot nhat, khong phai van de lon nhat.", author: "Jim Collins", source: "Good to Great" },
  { text: "People are not your most important asset. The right people are.", vi: "Con nguoi khong phai tai san quan trong nhat. Dung nguoi moi la.", author: "Jim Collins", source: "Good to Great" },
  { text: "The key question is not what you're passionate about, but what you can be passionate about and what drives your economic engine.", vi: "Cau hoi then chot khong phai ban dam me gi, ma la ban co the dam me gi va dieu gi thuc day dong co kinh te.", author: "Jim Collins", source: "Good to Great" },

  // Start with Why — Simon Sinek (426-450)
  { text: "People don't buy what you do; they buy why you do it.", vi: "Nguoi ta khong mua thu ban lam; ho mua ly do ban lam dieu do.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Working hard for something we don't care about is called stress; working hard for something we love is called passion.", vi: "Lam viec cham chi cho dieu khong quan tam goi la stress; lam viec cham chi cho dieu yeu thich goi la dam me.", author: "Simon Sinek", source: "Start with Why" },
  { text: "There are only two ways to influence human behavior: you can manipulate it or you can inspire it.", vi: "Chi co hai cach anh huong hanh vi con nguoi: thao tung hoac truyen cam hung.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Leadership is not about being in charge. It's about taking care of those in your charge.", vi: "Lanh dao khong phai la nam quyen. Ma la cham soc nhung nguoi ban phu trach.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Great companies don't hire skilled people and motivate them, they hire already motivated people and inspire them.", vi: "Cong ty vi dai khong tuyen nguoi gioi roi tao dong luc, ho tuyen nguoi da co dong luc va truyen cam hung.", author: "Simon Sinek", source: "Start with Why" },
  { text: "The goal is not to do business with everybody who needs what you have. The goal is to do business with people who believe what you believe.", vi: "Muc tieu khong phai lam an voi moi nguoi can san pham cua ban. Muc tieu la lam an voi nguoi tin dieu ban tin.", author: "Simon Sinek", source: "Start with Why" },
  { text: "If you hire people just because they can do a job, they'll work for your money. But if you hire people who believe what you believe, they'll work for you with blood and sweat and tears.", vi: "Neu tuyen nguoi chi vi ho lam duoc viec, ho se lam vi tien. Nhung neu tuyen nguoi tin dieu ban tin, ho se lam viec bang mau va nuoc mat.", author: "Simon Sinek", source: "Start with Why" },
  { text: "People don't buy what you do, they buy why you do it. And what you do simply proves what you believe.", vi: "Nguoi ta khong mua thu ban lam, ho mua ly do ban lam. Va dieu ban lam chi chung minh dieu ban tin.", author: "Simon Sinek", source: "Start with Why" },
  { text: "The role of a leader is not to come up with all the great ideas. The role of a leader is to create an environment in which great ideas can happen.", vi: "Vai tro cua lanh dao khong phai nghi ra moi y tuong hay. Ma la tao moi truong de y tuong hay co the xuat hien.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Customers will never love a company until the employees love it first.", vi: "Khach hang se khong bao gio yeu cong ty cho den khi nhan vien yeu no truoc.", author: "Simon Sinek", source: "Start with Why" },
  { text: "When we tell people to do their jobs, we get workers. When we trust people to get the job done, we get leaders.", vi: "Khi chung ta bao nguoi ta lam viec, chung ta co nhan cong. Khi tin tuong ho hoan thanh cong viec, chung ta co lanh dao.", author: "Simon Sinek", source: "Start with Why" },
  { text: "If your actions inspire others to dream more, learn more, do more and become more, you are a leader.", vi: "Neu hanh dong cua ban truyen cam hung cho nguoi khac mo nhieu hon, hoc nhieu hon, lam nhieu hon va tro nen tot hon, ban la lanh dao.", author: "Simon Sinek", source: "Start with Why" },
  { text: "A team is not a group of people who work together. A team is a group of people who trust each other.", vi: "Doi nhom khong phai nhom nguoi lam viec cung nhau. Doi nhom la nhom nguoi tin tuong nhau.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Value is not determined by those who set the price. Value is determined by those who choose to pay it.", vi: "Gia tri khong do nguoi dat gia quyet dinh. Gia tri do nguoi chon tra quyet dinh.", author: "Simon Sinek", source: "Start with Why" },
  { text: "You don't hire for skills, you hire for attitude. You can always teach skills.", vi: "Dung tuyen vi ky nang, hay tuyen vi thai do. Ky nang luon co the day.", author: "Simon Sinek", source: "Start with Why" },
  { text: "The ability to recruit, the ability to galvanize, all require that those you are trying to lead feel that making your vision a reality is in their own self-interest.", vi: "Kha nang tuyen dung, kha nang tap hop, tat ca deu can nhung nguoi ban dan dat cam thay bien tam nhin cua ban thanh hien thuc la loi ich cua chinh ho.", author: "Simon Sinek", source: "Start with Why" },
  { text: "The best organizations make their people feel safe. And the result is trust and cooperation.", vi: "To chuc tot nhat lam cho nguoi cua ho cam thay an toan. Ket qua la niem tin va su hop tac.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Directions are instructions given to explain how. Direction is a vision offered to explain why.", vi: "Chi dan la huong dan giai thich cach lam. Huong di la tam nhin giai thich ly do.", author: "Simon Sinek", source: "Start with Why" },
  { text: "Average companies give their people something to work on. The most innovative organizations give their people something to work toward.", vi: "Cong ty trung binh cho nguoi dieu de lam. To chuc sang tao nhat cho nguoi dieu de huong toi.", author: "Simon Sinek", source: "Start with Why" },
  { text: "All organizations start with WHY, but only the great ones keep their WHY clear year after year.", vi: "Moi to chuc deu bat dau voi TAI SAO, nhung chi nhung to chuc vi dai giu TAI SAO ro rang nam nay qua nam khac.", author: "Simon Sinek", source: "Start with Why" },

  // The Lean Startup — Eric Ries (451-470)
  { text: "The only way to win is to learn faster than anyone else.", vi: "Cach duy nhat de thang la hoc nhanh hon moi nguoi.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "If we do not know who the customer is, we do not know what quality is.", vi: "Neu khong biet khach hang la ai, chung ta khong biet chat luong la gi.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Build-Measure-Learn: the fundamental activity of a startup is to turn ideas into products, measure how customers respond, and then learn whether to pivot or persevere.", vi: "Xay-Do-Hoc: hoat dong co ban cua startup la bien y tuong thanh san pham, do phan ung khach hang, roi hoc xem nen xoay truc hay kien tri.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Success is not delivering a feature; success is learning how to solve the customer's problem.", vi: "Thanh cong khong phai giao tinh nang; thanh cong la hoc cach giai quyet van de cua khach hang.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "We must learn what customers really want, not what they say they want or what we think they should want.", vi: "Chung ta phai hoc dieu khach hang that su muon, khong phai dieu ho noi ho muon hay dieu ta nghi ho nen muon.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "A startup is a human institution designed to create a new product or service under conditions of extreme uncertainty.", vi: "Startup la to chuc con nguoi duoc thiet ke de tao san pham hoac dich vu moi trong dieu kien bat dinh cuc do.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "The lesson of the MVP is that any additional work beyond what was required to start learning is waste.", vi: "Bai hoc cua MVP la bat ky cong viec nao vuot qua muc can thiet de bat dau hoc deu la lang phi.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Planning and forecasting are only accurate when based on a long, stable operating history and a relatively static environment.", vi: "Lap ke hoach va du bao chi chinh xac khi dua tren lich su van hanh dai, on dinh va moi truong tuong doi tinh.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Startups exist not to make stuff, make money, or serve customers. They exist to learn how to build a sustainable business.", vi: "Startup ton tai khong phai de tao san pham, kiem tien hay phuc vu khach hang. Ma de hoc cach xay dung doanh nghiep ben vung.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "The big question of our time is not 'Can it be built?' but 'Should it be built?'", vi: "Cau hoi lon cua thoi dai khong phai 'Co the xay duoc khong?' ma 'Co nen xay khong?'", author: "Eric Ries", source: "The Lean Startup" },
  { text: "The goal of every startup experiment is to discover how to build a sustainable business around that vision.", vi: "Muc tieu cua moi thi nghiem startup la kham pha cach xay dung doanh nghiep ben vung quanh tam nhin do.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Vanity metrics allow you to form false conclusions and live in your own private reality.", vi: "Chi so ao cho phep ban rut ket luan sai va song trong thuc tai rieng cua minh.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Learning is the essential unit of progress for startups.", vi: "Hoc hoi la don vi tien bo thiet yeu cua startup.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "The ability to learn faster from customers is the essential competitive advantage that startups must possess.", vi: "Kha nang hoc nhanh hon tu khach hang la loi the canh tranh thiet yeu cua startup.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Sustainable growth is characterized by one simple rule: New customers come from the actions of past customers.", vi: "Tang truong ben vung dac trung boi mot quy tac don gian: Khach hang moi den tu hanh dong cua khach hang cu.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "The pivot: a structured course correction designed to test a new fundamental hypothesis about the product, strategy, and engine of growth.", vi: "Xoay truc: dieu chinh co cau truc de kiem tra gia thuyet co ban moi ve san pham, chien luoc va dong co tang truong.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Most of the time customers don't know what they want in advance.", vi: "Phan lon thoi gian khach hang khong biet truoc ho muon gi.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Innovation accounting: how to measure progress, how to set up milestones, and how to prioritize work in a startup context.", vi: "Ke toan doi moi: cach do tien do, thiet lap moc va uu tien cong viec trong boi canh startup.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Every startup is a grand experiment that attempts to answer a question.", vi: "Moi startup la thi nghiem lon co gang tra loi mot cau hoi.", author: "Eric Ries", source: "The Lean Startup" },
  { text: "Anything those customers experience from their interaction with a company should be considered part of that company's product.", vi: "Bat cu dieu gi khach hang trai nghiem tu tuong tac voi cong ty deu nen duoc xem la phan cua san pham.", author: "Eric Ries", source: "The Lean Startup" },

  // Zero to One — Peter Thiel (471-490)
  { text: "What important truth do very few people agree with you on?", vi: "Su that quan trong nao ma rat it nguoi dong y voi ban?", author: "Peter Thiel", source: "Zero to One" },
  { text: "The next Bill Gates will not build an operating system. The next Larry Page will not build a search engine. If you are copying these guys, you aren't learning from them.", vi: "Bill Gates tiep theo se khong xay he dieu hanh. Larry Page tiep theo se khong xay cong cu tim kiem. Neu ban sao chep ho, ban khong hoc tu ho.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Doing what we already know how to do takes the world from 1 to n, adding more of something familiar. Every new creation goes from 0 to 1.", vi: "Lam dieu da biet dua the gioi tu 1 den n, them nhieu thu quen thuoc. Moi sang tao moi di tu 0 den 1.", author: "Peter Thiel", source: "Zero to One" },
  { text: "The most contrarian thing of all is not to oppose the crowd but to think for yourself.", vi: "Dieu nguoc dong nhat khong phai phan doi dam dong ma la tu suy nghi cho minh.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Brilliant thinking is rare, but courage is in even shorter supply than genius.", vi: "Tu duy xuat sac thi hiem, nhung can dam con hiem hon ca thien tai.", author: "Peter Thiel", source: "Zero to One" },
  { text: "If your goal is to never make a mistake in your life, you shouldn't look for secrets. The prospect of being lonely but right — dedicating your life to something that no one else believes in — is already hard.", vi: "Neu muc tieu la khong bao gio sai, ban khong nen tim bi mat. Trien vong co don nhung dung — cong hien doi cho dieu khong ai tin — da du kho.", author: "Peter Thiel", source: "Zero to One" },
  { text: "A great business is defined by its ability to generate cash flows in the future.", vi: "Doanh nghiep vi dai duoc dinh nghia boi kha nang tao dong tien trong tuong lai.", author: "Peter Thiel", source: "Zero to One" },
  { text: "The best entrepreneurs know this: every great business is built around a secret that's hidden from the outside.", vi: "Doanh nhan gioi nhat biet dieu nay: moi doanh nghiep vi dai deu xay quanh bi mat an giau voi ben ngoai.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Competition is for losers. If you want to create and capture lasting value, look to build a monopoly.", vi: "Canh tranh danh cho ke thua. Neu muon tao va nam giu gia tri lau dai, hay xay dung the doc quyen.", author: "Peter Thiel", source: "Zero to One" },
  { text: "All happy companies are different: each one earns a monopoly by solving a unique problem.", vi: "Moi cong ty hanh phuc deu khac nhau: moi cong ty gianh doc quyen bang cach giai quyet van de doc nhat.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Every moment in business happens only once. The next Mark Zuckerberg won't create a social network. The next Larry Page won't make a search engine.", vi: "Moi khoanh khac trong kinh doanh chi xay ra mot lan. Mark Zuckerberg tiep theo se khong tao mang xa hoi. Larry Page tiep theo se khong tao cong cu tim kiem.", author: "Peter Thiel", source: "Zero to One" },
  { text: "The paradox of teaching entrepreneurship is that such a formula necessarily cannot exist; because every innovation is new and unique, no authority can prescribe in concrete terms how to be innovative.", vi: "Nghich ly cua day khoi nghiep la cong thuc nhu vay khong the ton tai; vi moi doi moi deu moi va doc nhat, khong ai co the chi ro cach doi moi.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Customers won't care about any particular technology unless it solves a particular problem in a superior way.", vi: "Khach hang khong quan tam cong nghe nao tru khi no giai quyet van de cu the mot cach vuot troi.", author: "Peter Thiel", source: "Zero to One" },
  { text: "A startup is the largest endeavor over which you can have definite mastery. You can have agency not just over your own life, but over a small and important part of the world.", vi: "Startup la no luc lon nhat ma ban co the lam chu hoan toan. Ban co quyen tac dong khong chi len cuoc doi minh, ma len mot phan nho nhung quan trong cua the gioi.", author: "Peter Thiel", source: "Zero to One" },
  { text: "As a good rule of thumb, proprietary technology must be at least 10 times better than its closest substitute in some important dimension to lead to a real monopolistic advantage.", vi: "Theo nguyen tac chung, cong nghe doc quyen phai tot hon it nhat 10 lan so voi san pham thay the gan nhat o khia canh quan trong nao do.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Positively defined, a startup is the largest group of people you can convince of a plan to build a different future.", vi: "Dinh nghia tich cuc, startup la nhom nguoi lon nhat ban co the thuyet phuc ve ke hoach xay dung tuong lai khac biet.", author: "Peter Thiel", source: "Zero to One" },
  { text: "Indefinite attitudes to the future explain what's most dysfunctional in our world today.", vi: "Thai do mo ho voi tuong lai giai thich dieu bat on nhat trong the gioi hom nay.", author: "Peter Thiel", source: "Zero to One" },
  { text: "You are not a lottery ticket. You are not a victim of forces beyond your control.", vi: "Ban khong phai ve so. Ban khong phai nan nhan cua nhung luc luong ngoai tam kiem soat.", author: "Peter Thiel", source: "Zero to One" },
  { text: "The business version of our contrarian question is: what valuable company is nobody building?", vi: "Phien ban kinh doanh cua cau hoi nguoc dong la: cong ty gia tri nao khong ai dang xay?", author: "Peter Thiel", source: "Zero to One" },
  { text: "Even the most prominent technology startup founders have boring backgrounds by the standards of tabloid media.", vi: "Ngay ca nhung nha sang lap startup cong nghe noi tieng nhat cung co lai lich nham chan theo tieu chuan bao la.", author: "Peter Thiel", source: "Zero to One" },

  // Principles — Ray Dalio (491-515)
  { text: "Pain plus reflection equals progress.", vi: "Dau kho cong suy ngam bang tien bo.", author: "Ray Dalio", source: "Principles" },
  { text: "He who lives by the crystal ball will eat shattered glass.", vi: "Nguoi song bang qua cau pha le se phai an thuy tinh vo.", author: "Ray Dalio", source: "Principles" },
  { text: "If you're not failing, you're not pushing your limits, and if you're not pushing your limits, you're not maximizing your potential.", vi: "Neu ban khong that bai, ban chua day gioi han, va neu khong day gioi han, ban chua toi da hoa tiem nang.", author: "Ray Dalio", source: "Principles" },
  { text: "Don't let fears of what others think of you stand in your way.", vi: "Dung de noi so nguoi khac nghi gi ve ban can duong ban.", author: "Ray Dalio", source: "Principles" },
  { text: "Think for yourself to decide what you want, what is true, and what you should do to achieve the first in light of the second.", vi: "Tu suy nghi de quyet dinh ban muon gi, dieu gi la that, va nen lam gi de dat dieu muon dua tren su that.", author: "Ray Dalio", source: "Principles" },
  { text: "Radical open-mindedness and radical transparency are invaluable for rapid learning and effective change.", vi: "Co mo triet de va minh bach triet de la vo gia cho viec hoc nhanh va thay doi hieu qua.", author: "Ray Dalio", source: "Principles" },
  { text: "Embrace reality and deal with it.", vi: "Hay don nhan thuc tai va doi mat voi no.", author: "Ray Dalio", source: "Principles" },
  { text: "The biggest mistake most people make is to not see themselves and others objectively.", vi: "Sai lam lon nhat cua da so la khong nhin minh va nguoi khac mot cach khach quan.", author: "Ray Dalio", source: "Principles" },
  { text: "Truth — or, more precisely, an accurate understanding of reality — is the essential foundation for any good outcome.", vi: "Su that — hay chinh xac hon, hieu biet dung ve thuc tai — la nen tang thiet yeu cho moi ket qua tot.", author: "Ray Dalio", source: "Principles" },
  { text: "Don't worry about looking good — worry about achieving your goals.", vi: "Dung lo ve viec trong dep — hay lo ve viec dat muc tieu.", author: "Ray Dalio", source: "Principles" },
  { text: "Having the basics — a good bed to sleep in, good relationships, good food, and good sex — is most important, and those things don't get much better when you have a lot of money or much worse when you have less.", vi: "Co nhung dieu co ban — giuong tot, quan he tot, thuc an tot — la quan trong nhat, va nhung dieu do khong tot hon nhieu khi co nhieu tien hay te hon khi it tien.", author: "Ray Dalio", source: "Principles" },
  { text: "I learned that if you work hard and creatively, you can have just about anything you want, but not everything you want.", vi: "Toi hoc duoc rang neu lam viec cham chi va sang tao, ban co the co hau het dieu muon, nhung khong phai tat ca.", author: "Ray Dalio", source: "Principles" },
  { text: "Meaningful work and meaningful relationships aren't just nice things we chose for ourselves — they are genetically programmed into us.", vi: "Cong viec y nghia va moi quan he y nghia khong chi la dieu ta chon — chung duoc lap trinh trong gen.", author: "Ray Dalio", source: "Principles" },
  { text: "Recognize that making mistakes is okay, but failing to learn from them is not.", vi: "Hay nhan ra rang sai lam la duoc, nhung khong hoc tu sai lam thi khong.", author: "Ray Dalio", source: "Principles" },
  { text: "People who worry about looking good typically hide what they don't know and hide their weaknesses, so they never learn how to properly deal with them.", vi: "Nguoi lo ve ve ngoai thuong giau nhung gi khong biet va diem yeu, nen khong bao gio hoc cach doi pho dung.", author: "Ray Dalio", source: "Principles" },
  { text: "Look at the patterns of your mistakes and identify at which step in the 5-Step Process you typically fail. Ask others for their input too.", vi: "Hay nhin vao khuon mau sai lam va xac dinh buoc nao trong Quy trinh 5 Buoc ban thuong that bai. Hay hoi y kien nguoi khac.", author: "Ray Dalio", source: "Principles" },
  { text: "To be effective you must not let your need to be right be more important than your need to find out what's true.", vi: "De hieu qua, ban khong duoc de nhu cau dung quan trong hon nhu cau tim ra su that.", author: "Ray Dalio", source: "Principles" },
  { text: "The more you think you know, the more closed-minded you'll be.", vi: "Ban cang nghi minh biet nhieu, ban cang dong y.", author: "Ray Dalio", source: "Principles" },
  { text: "Life is like a game where you seek to overcome the obstacles that stand in the way of achieving your goals.", vi: "Cuoc song giong tro choi noi ban tim cach vuot qua tro ngai tren duong dat muc tieu.", author: "Ray Dalio", source: "Principles" },
  { text: "Time is like a river that carries us forward into encounters with reality that require us to make decisions. We can't stop our movement down this river, and we can't avoid the encounters.", vi: "Thoi gian nhu dong song dua ta tien vao nhung cuoc gap go voi thuc tai doi hoi ta quyet dinh. Ta khong the dung lai va khong the tranh nhung cuoc gap go do.", author: "Ray Dalio", source: "Principles" },
  { text: "Every time you confront something painful, you are at a potentially important juncture in your life — you have the opportunity to choose healthy and painful truth or unhealthy but comfortable delusion.", vi: "Moi khi doi mat dieu dau don, ban dang o nghi toa quan trong — co hoi chon su that lanh manh nhung dau don hoac ao tuong thoai mai nhung khong lanh manh.", author: "Ray Dalio", source: "Principles" },
  { text: "Remember that the quality of your decisions will determine the quality of your life.", vi: "Hay nho rang chat luong quyet dinh se quyet dinh chat luong cuoc song.", author: "Ray Dalio", source: "Principles" },
  { text: "Knowing what is true is good. Being open-minded about what is true is even better.", vi: "Biet dieu gi la that thi tot. Co mo voi su that con tot hon.", author: "Ray Dalio", source: "Principles" },
  { text: "Maturity is the ability to reject good alternatives in order to pursue even better ones.", vi: "Truong thanh la kha nang tu choi lua chon tot de theo duoi lua chon tot hon.", author: "Ray Dalio", source: "Principles" },
  { text: "The most important thing is that you develop your own principles and ideally write them down.", vi: "Dieu quan trong nhat la ban phat trien nguyen tac cua rieng minh va ly tuong nhat la viet chung ra.", author: "Ray Dalio", source: "Principles" },

  // The Hard Thing About Hard Things — Ben Horowitz (516-535)
  { text: "Hard things are hard because there are no easy answers or recipes. They are hard because your emotions are at odds with your logic.", vi: "Dieu kho thi kho vi khong co cau tra loi hay cong thuc de dang. Chung kho vi cam xuc mau thuan voi logic.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Take care of the people, the products, and the profits — in that order.", vi: "Cham lo con nguoi, san pham va loi nhuan — theo thu tu do.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "The most difficult skill I learned as a CEO was the ability to manage my own psychology.", vi: "Ky nang kho nhat toi hoc duoc khi lam CEO la kha nang quan ly tam ly cua chinh minh.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "There is no recipe for really complicated, dynamic situations. There's no recipe for building a high-tech company.", vi: "Khong co cong thuc cho tinh huong phuc tap va dong. Khong co cong thuc xay dung cong ty cong nghe cao.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "In life, everybody faces choices between doing what's popular, easy, and wrong versus doing what's lonely, difficult, and right.", vi: "Trong cuoc song, ai cung doi mat lua chon giua lam dieu pho bien, de va sai so voi lam dieu co don, kho va dung.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "That's the hard thing about hard things — there is no formula for dealing with them.", vi: "Do la dieu kho ve nhung dieu kho — khong co cong thuc nao de doi pho.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "If you are going to eat shit, don't nibble.", vi: "Neu phai nuot dang, dung nham nhap.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Nobody cares. Just run your company.", vi: "Khong ai quan tam. Hay dieu hanh cong ty cua ban.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "The most important thing I learned as an entrepreneur was that every time I made the hard right decision instead of the easy wrong decision, the hard decision turned out to be way better.", vi: "Dieu quan trong nhat toi hoc duoc la moi lan chon quyet dinh kho nhung dung thay vi de nhung sai, quyet dinh kho luon tot hon nhieu.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Spend zero time on what you could have done, and devote all of your time on what you might do.", vi: "Khong danh thoi gian cho dieu le ra da lam, hay danh toan bo thoi gian cho dieu co the lam.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "A CEO must be able to see the company through the eyes of the employees, the partners, the investors, and the customers.", vi: "CEO phai co the nhin cong ty qua con mat cua nhan vien, doi tac, nha dau tu va khach hang.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "By far the most difficult skill I learned as CEO was the ability to manage my own psychology. Organizational design, process design, metrics, hiring and firing were all relatively straightforward.", vi: "Ky nang kho nhat toi hoc khi lam CEO la quan ly tam ly ban than. Thiet ke to chuc, quy trinh, chi so, tuyen dung va sa thai deu tuong doi don gian.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Being a good company doesn't matter when things go well, but it can be the difference between life and death when things go wrong.", vi: "La cong ty tot khong quan trong khi moi thu suon se, nhung co the la su khac biet giua song va chet khi moi thu tro nen te.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Every really good, really experienced CEO I know shares one important characteristic: they tend to opt for the hard answer to organizational issues.", vi: "Moi CEO gioi va nhieu kinh nghiem toi biet deu co chung dac diem: ho thuong chon cau tra loi kho cho van de to chuc.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "The only thing that prepares you to run a company is running a company.", vi: "Dieu duy nhat chuan bi cho ban dieu hanh cong ty la dieu hanh cong ty.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Sometimes an organization doesn't need a solution; it just needs clarity.", vi: "Doi khi to chuc khong can giai phap; chi can su ro rang.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "A healthy company culture encourages people to share bad news. A company that discusses its problems freely and openly can quickly solve them.", vi: "Van hoa cong ty lanh manh khuyen khich chia se tin xau. Cong ty thao luan van de tu do va coi mo co the giai quyet nhanh.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "You won't be able to share every burden, but share every burden you can.", vi: "Ban khong the chia se moi ganh nang, nhung hay chia se moi ganh nang co the.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Hire for strength rather than lack of weakness.", vi: "Tuyen vi diem manh, khong phai vi thieu diem yeu.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },
  { text: "Looking at the world through such different prisms helped me separate facts from perceptions.", vi: "Nhin the gioi qua nhieu lang kinh khac nhau giup toi tach su that khoi nhan thuc.", author: "Ben Horowitz", source: "The Hard Thing About Hard Things" },

  // Famous leaders: Elon Musk (536-555)
  { text: "When something is important enough, you do it even if the odds are not in your favor.", vi: "Khi dieu gi do du quan trong, ban lam du ty le khong ung ho ban.", author: "Elon Musk", source: "Interview" },
  { text: "I think it's very important to have a feedback loop, where you're constantly thinking about what you've done and how you could be doing it better.", vi: "Toi nghi rat quan trong la co vong phan hoi, noi ban luon suy nghi ve nhung gi da lam va cach lam tot hon.", author: "Elon Musk", source: "Interview" },
  { text: "Failure is an option here. If things are not failing, you are not innovating enough.", vi: "That bai la mot lua chon o day. Neu khong co gi that bai, ban chua doi moi du.", author: "Elon Musk", source: "Interview" },
  { text: "Persistence is very important. You should not give up unless you are forced to give up.", vi: "Kien tri rat quan trong. Ban khong nen bo cuoc tru khi bi buoc phai bo cuoc.", author: "Elon Musk", source: "Interview" },
  { text: "It's OK to have your eggs in one basket as long as you control what happens to that basket.", vi: "Bo trung vao mot gio cung duoc mien la ban kiem soat dieu xay ra voi cai gio do.", author: "Elon Musk", source: "Interview" },
  { text: "I could either watch it happen or be a part of it.", vi: "Toi co the dung nhin hoac tham gia vao.", author: "Elon Musk", source: "Interview" },
  { text: "Some people don't like change, but you need to embrace change if the alternative is disaster.", vi: "Mot so nguoi khong thich thay doi, nhung ban can don nhan thay doi neu phuong an thay the la tham hoa.", author: "Elon Musk", source: "Interview" },
  { text: "The first step is to establish that something is possible; then probability will occur.", vi: "Buoc dau tien la xac dinh dieu gi do la kha thi; sau do xac suat se xay ra.", author: "Elon Musk", source: "Interview" },
  { text: "If you get up in the morning and think the future is going to be better, it is a bright day. Otherwise, it's not.", vi: "Neu sang day va nghi tuong lai se tot hon, do la ngay tuoi sang. Nguoc lai thi khong.", author: "Elon Musk", source: "Interview" },
  { text: "Don't confuse schooling with education. I didn't go to Harvard but the people that work for me did.", vi: "Dung nham lan di hoc voi giao duc. Toi khong hoc Harvard nhung nguoi lam viec cho toi thi co.", author: "Elon Musk", source: "Interview" },
  { text: "Life is too short for long-term grudges.", vi: "Cuoc doi qua ngan de giu oan gian lau.", author: "Elon Musk", source: "Interview" },
  { text: "I'd rather be optimistic and wrong than pessimistic and right.", vi: "Toi tha lac quan va sai con hon bi quan va dung.", author: "Elon Musk", source: "Interview" },
  { text: "Starting a company is like eating glass and staring into the abyss of death.", vi: "Khoi nghiep giong nhu an thuy tinh va nhin vao vuc tham cua cai chet.", author: "Elon Musk", source: "Interview" },
  { text: "If something's important enough, you should try. Even if the probable outcome is failure.", vi: "Neu dieu gi do du quan trong, ban nen thu. Du ket qua co the la that bai.", author: "Elon Musk", source: "Interview" },
  { text: "Really pay attention to negative feedback and solicit it, particularly from friends. Hardly anyone does that, and it's incredibly helpful.", vi: "Hay that su chu y den phan hoi tieu cuc va chu dong hoi, dac biet tu ban be. Hau nhu khong ai lam dieu do, va no vo cung huu ich.", author: "Elon Musk", source: "Interview" },
  { text: "Brand is just a perception, and perception will match reality over time.", vi: "Thuong hieu chi la nhan thuc, va nhan thuc se khop voi thuc te theo thoi gian.", author: "Elon Musk", source: "Interview" },
  { text: "People work better when they know what the goal is and why.", vi: "Nguoi ta lam viec tot hon khi biet muc tieu la gi va tai sao.", author: "Elon Musk", source: "Interview" },
  { text: "I always have optimism, but I'm realistic. It was not with the expectation of great success that I started Tesla or SpaceX. It's just that I thought they were important enough to do anyway.", vi: "Toi luon lac quan nhung thuc te. Toi khong bat dau Tesla hay SpaceX voi ky vong thanh cong lon. Chi la toi nghi chung du quan trong de lam.", author: "Elon Musk", source: "Interview" },
  { text: "Work like hell. I mean you just have to put in 80-to-100-hour weeks every week. This improves the odds of success.", vi: "Lam viec nhu dien. Toi muon noi ban phai bo ra 80 den 100 gio moi tuan. Dieu nay tang co hoi thanh cong.", author: "Elon Musk", source: "Interview" },
  { text: "You want to be extra rigorous about making the best possible thing you can. Find everything that's wrong with it and fix it.", vi: "Ban muon cuc ky nghiem ngat trong viec tao ra thu tot nhat co the. Tim moi thu sai va sua no.", author: "Elon Musk", source: "Interview" },

  // Warren Buffett (556-575)
  { text: "The most important investment you can make is in yourself.", vi: "Khoan dau tu quan trong nhat ban co the lam la dau tu vao chinh minh.", author: "Warren Buffett", source: "Interview" },
  { text: "It takes 20 years to build a reputation and five minutes to ruin it.", vi: "Mat 20 nam de xay dung danh tieng va 5 phut de pha huy no.", author: "Warren Buffett", source: "Interview" },
  { text: "Price is what you pay. Value is what you get.", vi: "Gia la thu ban tra. Gia tri la thu ban nhan.", author: "Warren Buffett", source: "Interview" },
  { text: "Someone's sitting in the shade today because someone planted a tree a long time ago.", vi: "Ai do dang ngoi duoi bong mat hom nay vi ai do da trong cay tu lau.", author: "Warren Buffett", source: "Interview" },
  { text: "Rule No. 1: Never lose money. Rule No. 2: Never forget rule No. 1.", vi: "Quy tac so 1: Dung bao gio mat tien. Quy tac so 2: Dung bao gio quen quy tac so 1.", author: "Warren Buffett", source: "Interview" },
  { text: "Risk comes from not knowing what you're doing.", vi: "Rui ro den tu viec khong biet minh dang lam gi.", author: "Warren Buffett", source: "Interview" },
  { text: "The difference between successful people and really successful people is that really successful people say no to almost everything.", vi: "Khac biet giua nguoi thanh cong va nguoi that su thanh cong la nguoi that su thanh cong noi khong voi hau het moi thu.", author: "Warren Buffett", source: "Interview" },
  { text: "Only when the tide goes out do you discover who's been swimming naked.", vi: "Chi khi thuy trieu rut moi biet ai dang boi khong mac gi.", author: "Warren Buffett", source: "Interview" },
  { text: "Honesty is a very expensive gift. Don't expect it from cheap people.", vi: "Trung thuc la mon qua rat dat. Dung mong doi tu nhung nguoi re tien.", author: "Warren Buffett", source: "Interview" },
  { text: "In the business world, the rearview mirror is always clearer than the windshield.", vi: "Trong the gioi kinh doanh, guong chieu hau luon ro hon kinh chan gio.", author: "Warren Buffett", source: "Interview" },
  { text: "Chains of habit are too light to be felt until they are too heavy to be broken.", vi: "Xich thoi quen qua nhe de cam nhan cho den khi qua nang de pha vo.", author: "Warren Buffett", source: "Interview" },
  { text: "The best thing I did was to choose the right heroes.", vi: "Dieu tot nhat toi lam la chon dung than tuong.", author: "Warren Buffett", source: "Interview" },
  { text: "I insist on a lot of time being spent, almost every day, to just sit and think.", vi: "Toi doi hoi danh nhieu thoi gian, gan nhu moi ngay, chi de ngoi va suy nghi.", author: "Warren Buffett", source: "Interview" },
  { text: "You only have to do a very few things right in your life so long as you don't do too many things wrong.", vi: "Ban chi can lam dung vai dieu trong doi mien la khong lam sai qua nhieu dieu.", author: "Warren Buffett", source: "Interview" },
  { text: "The more you learn, the more you earn.", vi: "Ban cang hoc nhieu, ban cang kiem nhieu.", author: "Warren Buffett", source: "Interview" },
  { text: "If you aren't willing to own a stock for ten years, don't even think about owning it for ten minutes.", vi: "Neu ban khong san sang giu co phieu muoi nam, dung nghi den viec giu no muoi phut.", author: "Warren Buffett", source: "Interview" },
  { text: "It's better to hang out with people better than you. Pick out associates whose behavior is better than yours and you'll drift in that direction.", vi: "Tot hon la choi voi nguoi gioi hon ban. Chon ban dong hanh co hanh vi tot hon va ban se di theo huong do.", author: "Warren Buffett", source: "Interview" },
  { text: "Tell me who your heroes are and I'll tell you who you'll turn out to be.", vi: "Noi cho toi than tuong cua ban la ai va toi se noi ban se tro thanh ai.", author: "Warren Buffett", source: "Interview" },
  { text: "You've gotta keep control of your time, and you can't unless you say no. You can't let people set your agenda in life.", vi: "Ban phai kiem soat thoi gian, va khong the lam vay tru khi noi khong. Ban khong the de nguoi khac dat lich trinh cuoc doi ban.", author: "Warren Buffett", source: "Interview" },
  { text: "Read 500 pages every day. That's how knowledge works. It builds up, like compound interest.", vi: "Doc 500 trang moi ngay. Kien thuc hoat dong nhu vay. No tich luy, giong nhu lai kep.", author: "Warren Buffett", source: "Interview" },

  // Jeff Bezos (576-600)
  { text: "Your brand is what other people say about you when you're not in the room.", vi: "Thuong hieu cua ban la dieu nguoi khac noi ve ban khi ban khong co mat.", author: "Jeff Bezos", source: "Interview" },
  { text: "If you're not stubborn, you'll give up on experiments too soon. And if you're not flexible, you'll pound your head against the wall.", vi: "Neu khong buong binh, ban se bo thi nghiem qua som. Neu khong linh hoat, ban se dap dau vao tuong.", author: "Jeff Bezos", source: "Interview" },
  { text: "I knew that if I failed I wouldn't regret that, but I knew the one thing I might regret is not trying.", vi: "Toi biet neu that bai toi se khong hoi tiec, nhung dieu toi co the hoi tiec la khong thu.", author: "Jeff Bezos", source: "Interview" },
  { text: "Life's too short to hang out with people who aren't resourceful.", vi: "Cuoc doi qua ngan de choi voi nguoi khong lanh loi.", author: "Jeff Bezos", source: "Interview" },
  { text: "In the end, we are our choices. Build yourself a great story.", vi: "Cuoi cung, chung ta la nhung lua chon cua minh. Hay xay cho minh mot cau chuyen tuyet voi.", author: "Jeff Bezos", source: "Speech" },
  { text: "One of the only ways to get out of a tight box is to invent your way out.", vi: "Mot trong nhung cach duy nhat thoat khoi the kho la sang tao loi thoat.", author: "Jeff Bezos", source: "Interview" },
  { text: "Be stubborn on vision, but flexible on details.", vi: "Hay buong binh voi tam nhin, nhung linh hoat voi chi tiet.", author: "Jeff Bezos", source: "Interview" },
  { text: "We see our customers as invited guests to a party, and we are the hosts. It's our job every day to make every important aspect of the customer experience a little bit better.", vi: "Chung toi xem khach hang nhu khach moi toi bua tiec va chung toi la chu nha. Cong viec moi ngay la lam moi khia canh quan trong cua trai nghiem khach hang tot hon mot chut.", author: "Jeff Bezos", source: "Interview" },
  { text: "If you double the number of experiments you do per year, you're going to double your inventiveness.", vi: "Neu ban gap doi so thi nghiem moi nam, ban se gap doi su sang tao.", author: "Jeff Bezos", source: "Interview" },
  { text: "Invention requires a long-term willingness to be misunderstood.", vi: "Sang tao doi hoi su san sang bi hieu lam trong thoi gian dai.", author: "Jeff Bezos", source: "Interview" },
  { text: "What's dangerous is not to evolve.", vi: "Dieu nguy hiem la khong tien hoa.", author: "Jeff Bezos", source: "Interview" },
  { text: "If you never want to be criticized, for goodness' sake don't do anything new.", vi: "Neu ban khong muon bi chi trich, lam on dung lam gi moi.", author: "Jeff Bezos", source: "Interview" },
  { text: "It's not an experiment if you know it's going to work.", vi: "Khong phai thi nghiem neu ban biet no se thanh cong.", author: "Jeff Bezos", source: "Interview" },
  { text: "The thing about inventing is you have to be both stubborn and flexible.", vi: "Dieu ve sang tao la ban phai vua buong binh vua linh hoat.", author: "Jeff Bezos", source: "Interview" },
  { text: "Work hard, have fun, make history.", vi: "Lam viec cham chi, vui choi va tao nen lich su.", author: "Jeff Bezos", source: "Interview" },
  { text: "A company shouldn't get addicted to being shiny. What really matters is that companies have a culture of going down blind alleys.", vi: "Cong ty khong nen nghien bong bay. Dieu quan trong la co van hoa dam di vao ngo cut.", author: "Jeff Bezos", source: "Interview" },
  { text: "I believe you have to be willing to be misunderstood if you're going to innovate.", vi: "Toi tin ban phai san sang bi hieu lam neu muon doi moi.", author: "Jeff Bezos", source: "Interview" },
  { text: "We've had three big ideas at Amazon that we've stuck with for 18 years, and they're the reason we're successful: Put the customer first. Invent. And be patient.", vi: "Chung toi co ba y tuong lon tai Amazon da theo duoi 18 nam va la ly do thanh cong: Dat khach hang len truoc. Sang tao. Va kien nhan.", author: "Jeff Bezos", source: "Interview" },
  { text: "All of my best decisions in business and in life have been made with heart, intuition, guts — not analysis.", vi: "Tat ca quyet dinh tot nhat cua toi trong kinh doanh va cuoc song deu duoc dua ra bang trai tim, truc giac, ban nang — khong phai phan tich.", author: "Jeff Bezos", source: "Interview" },
  { text: "Position yourself with something that captures your curiosity, something that you're missionary about.", vi: "Hay dat minh voi dieu nao do khoi day tri to mo, dieu ma ban het long vi no.", author: "Jeff Bezos", source: "Interview" },

  // ============================================================
  // COMMUNICATION (150 quotes)
  // ============================================================

  // How to Win Friends and Influence People — Dale Carnegie (601-650)
  { text: "You can make more friends in two months by becoming interested in other people than you can in two years by trying to get other people interested in you.", vi: "Ban co the ket ban nhieu hon trong hai thang bang cach quan tam nguoi khac hon hai nam co lam nguoi khac quan tam ban.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Any fool can criticize, complain, and condemn — and most fools do. But it takes character and self-control to be understanding and forgiving.", vi: "Ke ngu nao cung co the chi trich, phan nan va len an — va da so ke ngu lam vay. Nhung can ban linh va tu chu de thau hieu va tha thu.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Talk to someone about themselves and they'll listen for hours.", vi: "Noi voi ai do ve chinh ho va ho se lang nghe hang gio.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Names are the sweetest and most important sound in any language.", vi: "Ten nguoi la am thanh ngot ngao va quan trong nhat trong bat ky ngon ngu nao.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Don't be afraid of enemies who attack you. Be afraid of the friends who flatter you.", vi: "Dung so ke thu tan cong ban. Hay so nhung nguoi ban ninh hot ban.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "You can't win an argument. If you lose it, you lose it; and if you win it, you lose it.", vi: "Ban khong the thang cuoc tranh luan. Neu thua, ban thua; va neu thang, ban cung thua.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "If you want to gather honey, don't kick over the beehive.", vi: "Neu muon lay mat ong, dung da to ong.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "When dealing with people, remember you are not dealing with creatures of logic, but with creatures bristling with prejudice and motivated by pride and vanity.", vi: "Khi doi xu voi nguoi khac, hay nho ban khong doi xu voi sinh vat cua logic, ma voi sinh vat day thanh kien va bi thuc day boi tu hao va hu danh.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "People rarely succeed unless they have fun in what they are doing.", vi: "Nguoi ta hiem khi thanh cong tru khi ho vui voi dieu ho lam.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "The only way to get the best of an argument is to avoid it.", vi: "Cach duy nhat de thang cuoc tranh luan la tranh no.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "A person's name is to him or her the sweetest and most important sound in any language.", vi: "Ten cua mot nguoi la am thanh ngot ngao va quan trong nhat voi ho trong bat ky ngon ngu nao.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "If you want to be enthusiastic, act enthusiastic.", vi: "Neu muon nhiet tinh, hay hanh dong nhiet tinh.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Arouse in the other person an eager want. He who can do this has the whole world with him. He who cannot walks a lonely way.", vi: "Khoi day trong nguoi khac mong muon manh liet. Nguoi lam duoc co ca the gioi. Nguoi khong lam duoc se di duong co don.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Become genuinely interested in other people.", vi: "Hay that su quan tam den nguoi khac.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Smile. It costs nothing, but creates much.", vi: "Hay cuoi. Khong ton gi nhung tao ra nhieu.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Be a good listener. Encourage others to talk about themselves.", vi: "Hay la nguoi lang nghe tot. Khuyen khich nguoi khac noi ve chinh ho.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Make the other person feel important — and do it sincerely.", vi: "Lam nguoi khac cam thay quan trong — va hay lam dieu do chan thanh.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Show respect for the other person's opinions. Never say, 'You're wrong.'", vi: "Ton trong y kien nguoi khac. Dung bao gio noi 'Ban sai.'", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "If you are wrong, admit it quickly and emphatically.", vi: "Neu ban sai, hay thua nhan nhanh chong va manh me.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Begin in a friendly way.", vi: "Hay bat dau mot cach than thien.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Let the other person do a great deal of the talking.", vi: "Hay de nguoi khac noi nhieu.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Let the other person feel that the idea is his or hers.", vi: "Hay de nguoi khac cam thay y tuong la cua ho.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Try honestly to see things from the other person's point of view.", vi: "Hay thanh that co nhin su viec tu goc nhin cua nguoi khac.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Be sympathetic with the other person's ideas and desires.", vi: "Hay thong cam voi y tuong va mong muon cua nguoi khac.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Appeal to the nobler motives.", vi: "Hay keu goi dong co cao thuong.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Throw down a challenge.", vi: "Hay dua ra thach thuc.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Begin with praise and honest appreciation.", vi: "Hay bat dau bang loi khen va su tran trong chan thanh.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Call attention to people's mistakes indirectly.", vi: "Hay chi ra loi cua nguoi khac mot cach gian tiep.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Talk about your own mistakes before criticizing the other person.", vi: "Hay noi ve sai lam cua ban truoc khi chi trich nguoi khac.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Ask questions instead of giving direct orders.", vi: "Hay dat cau hoi thay vi ra lenh truc tiep.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Let the other person save face.", vi: "Hay de nguoi khac giu the dien.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Praise the slightest improvement and praise every improvement. Be hearty in your approbation and lavish in your praise.", vi: "Khen ngoi su tien bo nho nhat va moi tien bo. Hay nhiet tinh trong su tan thuong va hao phong trong loi khen.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Give the other person a fine reputation to live up to.", vi: "Hay trao cho nguoi khac danh tieng tot de ho phan dau song dung voi no.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Use encouragement. Make the fault seem easy to correct.", vi: "Hay dung su khuyen khich. Lam cho loi lam co ve de sua.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Make the other person happy about doing the thing you suggest.", vi: "Hay lam nguoi khac vui ve khi lam dieu ban goi y.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "The unvarnished truth is that almost all the people you meet feel themselves superior to you in some way, and a sure way to their hearts is to let them realize in some subtle way that you recognize their importance, and recognize it sincerely.", vi: "Su that tran trui la hau het nguoi ban gap deu cam thay hon ban o khia canh nao do, va cach chac chan nhat de chinh phuc ho la tinh te nhan ra tam quan trong cua ho, va nhan ra mot cach chan thanh.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Instead of condemning people, let's try to understand them. Let's try to figure out why they do what they do.", vi: "Thay vi len an nguoi khac, hay co hieu ho. Hay co tim ra tai sao ho lam nhung gi ho lam.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "There is only one way under high heaven to get anybody to do anything. And that is by making the other person want to do it.", vi: "Chi co mot cach duy nhat de khien ai do lam bat cu dieu gi. Do la lam cho nguoi do muon lam dieu do.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "We are interested in others when they are interested in us.", vi: "Chung ta quan tam nguoi khac khi ho quan tam chung ta.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Actions speak louder than words, and a smile says, 'I like you. You make me happy. I am glad to see you.'", vi: "Hanh dong noi to hon loi noi, va nu cuoi noi 'Toi thich ban. Ban lam toi vui. Toi mung gap ban.'", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "The rare individual who unselfishly tries to serve others has an enormous advantage.", vi: "Nguoi hiem hoi vo tu phuc vu nguoi khac co loi the to lon.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "You can close more business in two months by becoming interested in other people than you can in two years by trying to get people interested in you.", vi: "Ban co the chot nhieu thuong vu hon trong hai thang bang cach quan tam nguoi khac hon hai nam co lam nguoi khac quan tam ban.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Feeling important is one of the deepest urges in human nature.", vi: "Cam thay quan trong la mot trong nhung thoi thuc sau xa nhat cua ban chat con nguoi.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Criticism is futile because it puts a person on the defensive and usually makes him strive to justify himself.", vi: "Chi trich la vo ich vi no dua nguoi ta vao the phong thu va thuong khien ho co bien minh.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "When we hate our enemies, we are giving them power over us: power over our sleep, our appetites, our blood pressure, our health, and our happiness.", vi: "Khi ghet ke thu, chung ta dang cho ho quyen luc tren chung ta: quyen luc tren giac ngu, khau vi, huyet ap, suc khoe va hanh phuc.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Success in dealing with people depends on a sympathetic grasp of the other person's viewpoint.", vi: "Thanh cong trong doi xu voi nguoi khac phu thuoc vao viec thong cam nam bat goc nhin cua ho.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Most of us go through life blissfully unaware of how our habits affect other people.", vi: "Da so chung ta song ma vui ve khong biet thoi quen cua minh anh huong nguoi khac nhu the nao.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "If you tell me how you get your feeling of importance, I'll tell you what you are.", vi: "Neu ban noi cho toi cach ban co cam giac quan trong, toi se noi cho ban ban la ai.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "Every man I meet is my superior in some way. In that, I learn of him.", vi: "Moi nguoi toi gap deu gioi hon toi o khia canh nao do. Trong dieu do, toi hoc tu ho.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },
  { text: "The expression one wears on one's face is far more important than the clothes one wears on one's back.", vi: "Net mat ban mang tren guong mat quan trong hon nhieu so voi quan ao ban mac tren nguoi.", author: "Dale Carnegie", source: "How to Win Friends and Influence People" },

  // Influence — Robert Cialdini (651-680)
  { text: "People prefer to say yes to those they know and like.", vi: "Nguoi ta thich noi co voi nguoi ho biet va quy men.", author: "Robert Cialdini", source: "Influence" },
  { text: "The way to love anything is to realize that it might be lost.", vi: "Cach de yeu dieu gi la nhan ra rang co the mat no.", author: "Robert Cialdini", source: "Influence" },
  { text: "Since 95 percent of the people are imitators and only 5 percent initiators, people are persuaded more by the actions of others than by any proof we can offer.", vi: "Vi 95 phan tram nguoi la nguoi bat chuoc va chi 5 phan tram la nguoi khoi xuong, nguoi ta bi thuyet phuc boi hanh dong cua nguoi khac hon bat ky bang chung nao.", author: "Robert Cialdini", source: "Influence" },
  { text: "The truly gifted negotiator, then, is one whose initial position is exaggerated enough to allow for a series of reciprocal concessions that will yield a desirable final offer.", vi: "Nha dam phan tai nang la nguoi co vi tri ban dau du phong dai de cho phep chuoi nhuong bo doi ung dan den de nghi cuoi cung mong muon.", author: "Robert Cialdini", source: "Influence" },
  { text: "We all fool ourselves from time to time in order to keep our thoughts and beliefs consistent with what we have already done or decided.", vi: "Chung ta deu tu lua minh doi khi de giu suy nghi va niem tin nhat quan voi nhung gi da lam hoac quyet dinh.", author: "Robert Cialdini", source: "Influence" },
  { text: "The principle of social proof says so: The greater the number of people who find any idea correct, the more the idea will be correct.", vi: "Nguyen ly bang chung xa hoi noi: Cang nhieu nguoi cho y tuong la dung, y tuong do cang duoc cho la dung.", author: "Robert Cialdini", source: "Influence" },
  { text: "A well-known principle of human behavior says that when we ask someone to do us a favor we will be more successful if we provide a reason.", vi: "Nguyen tac hanh vi con nguoi noi rang khi nho ai lam on, chung ta se thanh cong hon neu dua ra ly do.", author: "Robert Cialdini", source: "Influence" },
  { text: "The rule of reciprocation says that we should try to repay, in kind, what another person has provided us.", vi: "Quy tac co di co lai noi rang chung ta nen co dap tra tuong xung nhung gi nguoi khac cho ta.", author: "Robert Cialdini", source: "Influence" },
  { text: "The scarcity principle: opportunities seem more valuable to us when their availability is limited.", vi: "Nguyen ly khan hiem: co hoi co ve gia tri hon khi kha nang co chung bi han che.", author: "Robert Cialdini", source: "Influence" },
  { text: "When we are unsure of ourselves, when the situation is unclear or ambiguous, we are most likely to look to and accept the actions of others as correct.", vi: "Khi khong chac chan, khi tinh huong khong ro rang, chung ta de nhin va chap nhan hanh dong nguoi khac la dung.", author: "Robert Cialdini", source: "Influence" },
  { text: "Our best evidence of what people truly feel and believe comes less from their words than from their deeds.", vi: "Bang chung tot nhat ve cam xuc va niem tin cua nguoi ta den tu hanh dong hon la loi noi.", author: "Robert Cialdini", source: "Influence" },
  { text: "Often we don't realize that our attitude toward something has been influenced by the number of times we have been exposed to it in the past.", vi: "Thuong chung ta khong nhan ra thai do cua minh da bi anh huong boi so lan tiep xuc voi no trong qua khu.", author: "Robert Cialdini", source: "Influence" },
  { text: "Once we have made a choice or taken a stand, we will encounter personal and interpersonal pressures to behave consistently with that commitment.", vi: "Mot khi da lua chon hay lap truong, chung ta se gap ap luc ca nhan va xa hoi de hanh dong nhat quan voi cam ket do.", author: "Robert Cialdini", source: "Influence" },
  { text: "People seem to be more motivated by the thought of losing something than by the thought of gaining something of equal value.", vi: "Nguoi ta co ve duoc thuc day boi y nghi mat dieu gi do hon la y nghi duoc dieu gi do co gia tri tuong duong.", author: "Robert Cialdini", source: "Influence" },
  { text: "There is a natural human tendency to dislike a person who brings us unpleasant information, even when that person did not cause the bad news.", vi: "Con nguoi co xu huong tu nhien khong thich nguoi mang tin xau, du nguoi do khong gay ra tin xau.", author: "Robert Cialdini", source: "Influence" },
  { text: "When it comes to the question of influence, the messenger is often the message.", vi: "Khi noi ve anh huong, nguoi truyen tin thuong chinh la thong diep.", author: "Robert Cialdini", source: "Influence" },
  { text: "Compliance professionals who infuse their requests with one or another of the weapons of influence can expect dramatically increased success.", vi: "Chuyen gia thuyet phuc khi ket hop yeu cau voi vu khi anh huong co the ky vong thanh cong tang dot bien.", author: "Robert Cialdini", source: "Influence" },
  { text: "The obligation to receive reduces our ability to choose whom we wish to be indebted to and puts that power in the hands of others.", vi: "Nghia vu nhan giam kha nang chon nguoi minh muon mang on va dat quyen luc do vao tay nguoi khac.", author: "Robert Cialdini", source: "Influence" },
  { text: "Persons who go through a great deal of trouble or pain to attain something tend to value it more highly than persons who attain the same thing with a minimum of effort.", vi: "Nguoi trai qua nhieu kho khan de dat dieu gi do thuong tran trong no hon nguoi dat duoc voi no luc toi thieu.", author: "Robert Cialdini", source: "Influence" },
  { text: "We will use the actions of others to decide on proper behavior for ourselves, especially when we view those others as similar to ourselves.", vi: "Chung ta se dung hanh dong cua nguoi khac de quyet dinh hanh vi phu hop, dac biet khi thay ho giong minh.", author: "Robert Cialdini", source: "Influence" },

  // Never Split the Difference — Chris Voss (681-720)
  { text: "He who has learned to disagree without being disagreeable has discovered the most valuable secret of negotiation.", vi: "Nguoi hoc cach bat dong ma khong gay kho chiu da kham pha bi mat gia tri nhat cua dam phan.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Negotiation is not an act of battle; it's a process of discovery.", vi: "Dam phan khong phai hanh dong chien dau; no la qua trinh kham pha.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Don't feel their pain, label it.", vi: "Dung cam nhan noi dau cua ho, hay goi ten no.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Tactical empathy is understanding the feelings and mindset of another in the moment and also hearing what is behind those feelings.", vi: "Dong cam chien thuat la hieu cam xuc va tu duy cua nguoi khac trong khoanh khac va cung nghe thay dieu gi dang sau cam xuc do.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "The beauty of empathy is that it doesn't demand that you agree with the other person's ideas.", vi: "Ve dep cua dong cam la no khong doi hoi ban phai dong y voi y tuong cua nguoi khac.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "It's not how well you speak, but how well you listen that determines your success in negotiation.", vi: "Khong phai ban noi gioi the nao, ma la ban lang nghe gioi the nao quyet dinh thanh cong trong dam phan.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "No deal is better than a bad deal.", vi: "Khong co thoa thuan tot hon thoa thuan toi.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "The secret to gaining the upper hand in a negotiation is giving the other side the illusion of control.", vi: "Bi quyet nam the thuong phong trong dam phan la cho doi phuong ao giac ve quyen kiem soat.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Yes is nothing without how.", vi: "Co la vo nghia neu khong co cach nao.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "The last impression is the lasting impression.", vi: "An tuong cuoi cung la an tuong lau dai.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "If you approach a negotiation thinking the other guy thinks like you, you are wrong.", vi: "Neu ban buoc vao dam phan nghi doi phuong suy nghi nhu ban, ban da sai.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Mirrors work magic. Repeat the last three words of what someone has just said.", vi: "Phan chieu tao phep mau. Hay lap lai ba tu cuoi cung nguoi khac vua noi.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "The most dangerous negotiation is the one you don't know you're in.", vi: "Cuoc dam phan nguy hiem nhat la cuoc dam phan ban khong biet minh dang o trong.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "We fear what's different and are drawn to what's similar. We trust people who are similar to us.", vi: "Chung ta so dieu khac biet va bi thu hut boi dieu tuong dong. Chung ta tin nguoi giong minh.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "That's right is better than yes. Strive to hear that's right instead of you're right.", vi: "'Dung vay' tot hon 'co'. Hay co gang nghe 'dung vay' thay vi 'ban dung'.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "People will take more risks to avoid a loss than to realize a gain.", vi: "Nguoi ta chap nhan nhieu rui ro hon de tranh mat mat hon la de dat duoc loi ich.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Black swans are leverage multipliers. They are the hidden pieces of information that, once discovered, can change the course of a negotiation.", vi: "Thien nga den la chat nhan don bay. Chung la nhung manh thong tin an giau ma khi phat hien co the thay doi cuc dien dam phan.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Saying 'No' makes the speaker feel safe, secure, and in control, so trigger it. Ask solution-based questions that start with 'How' or 'What'.", vi: "Noi 'Khong' khien nguoi noi cam thay an toan va kiem soat, nen hay kich hoat no. Dat cau hoi giai phap bat dau bang 'Lam the nao' hoac 'Cai gi'.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Never be so sure of what you want that you wouldn't take something better.", vi: "Dung bao gio qua chac chan ve dieu muon den muc khong chap nhan dieu tot hon.", author: "Chris Voss", source: "Never Split the Difference" },
  { text: "Creative solutions are almost always preceded by some degree of risk, annoyance, confusion, and conflict.", vi: "Giai phap sang tao hau nhu luon duoc bat dau boi mot muc do rui ro, kho chiu, boi roi va xung dot.", author: "Chris Voss", source: "Never Split the Difference" },

  // Crucial Conversations — Patterson/Grenny/McMillan/Switzler (721-750)
  { text: "At the core of every successful conversation lies the free flow of relevant information.", vi: "O cot loi cua moi cuoc tro chuyen thanh cong la dong chay tu do cua thong tin lien quan.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "The single biggest problem in communication is the illusion that it has taken place.", vi: "Van de lon nhat trong giao tiep la ao tuong rang no da xay ra.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "When it matters most, we often do our worst.", vi: "Khi quan trong nhat, chung ta thuong lam te nhat.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "People who are skilled at dialogue do their best to make it safe for everyone to add their meaning to the shared pool.", vi: "Nguoi gioi doi thoai co gang het suc tao su an toan de moi nguoi dong gop y nghia vao kho chung.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "When stakes are high, opinions vary, and emotions run strong, you're in a crucial conversation.", vi: "Khi van de hep troi, y kien khac nhau va cam xuc dang cao, ban dang trong cuoc doi thoai then chot.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "The Pool of Shared Meaning is the birthplace of synergy.", vi: "Kho Y Nghia Chung la noi khai sinh cua suc manh cong huong.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Start with heart: focus on what you really want.", vi: "Bat dau tu trai tim: tap trung vao dieu ban that su muon.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Learn to look: notice when safety is at risk.", vi: "Hoc cach quan sat: nhan ra khi su an toan bi de doa.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Make it safe: restore safety when you notice it's at risk.", vi: "Tao su an toan: khoi phuc an toan khi thay no bi de doa.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Master my stories: stay in dialogue when you're angry, scared, or hurt.", vi: "Lam chu cau chuyen: o lai trong doi thoai khi gian, so hay ton thuong.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "State my path: speak persuasively, not abrasively.", vi: "Trinh bay con duong: noi thuyet phuc, khong gay gat.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Explore others' paths: make it safe for others to share.", vi: "Kham pha con duong cua nguoi khac: tao su an toan de nguoi khac chia se.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Move to action: turn crucial conversations into action and results.", vi: "Chuyen sang hanh dong: bien cuoc doi thoai then chot thanh hanh dong va ket qua.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Mutual purpose is the entry condition of dialogue. Find a shared goal, and you have both a good reason and a healthy climate for talking.", vi: "Muc dich chung la dieu kien dau vao cua doi thoai. Tim muc tieu chung, va ban co ca ly do va bau khong khi lanh manh de noi chuyen.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Mutual respect is the continuance condition of dialogue. As people perceive that others don't respect them, the conversation immediately becomes unsafe.", vi: "Ton trong lan nhau la dieu kien duy tri doi thoai. Khi nguoi ta cam nhan khong duoc ton trong, cuoc tro chuyen lap tuc mat an toan.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "We don't get angry because of what others do to us. We make ourselves angry by telling ourselves a story.", vi: "Chung ta khong gian vi dieu nguoi khac lam. Chung ta tu lam minh gian bang cach tu ke mot cau chuyen.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Nothing kills the ability to hold a crucial conversation faster than fear. Fear of being judged, fear of looking foolish, fear of being rejected.", vi: "Khong gi giet chet kha nang tro chuyen then chot nhanh hon noi so. So bi phan xet, so trong ngu ngoc, so bi tu choi.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Speak when you are angry and you'll make the best speech you'll ever regret.", vi: "Noi khi gian va ban se tao ra bai phat bieu hay nhat ma ban se hoi tiec.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "What would I do right now if I really wanted these results?", vi: "Toi se lam gi ngay bay gio neu thuc su muon nhung ket qua nay?", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },
  { text: "Strong relationships, careers, organizations, and communities all draw from the same source of power — the ability to talk openly about high-stakes, emotional, controversial topics.", vi: "Moi quan he, su nghiep, to chuc va cong dong vung manh deu rut tu cung mot nguon suc manh — kha nang noi chuyen coi mo ve nhung chu de hep troi, cam xuc va gay tranh cai.", author: "Patterson/Grenny/McMillan/Switzler", source: "Crucial Conversations" },

  // ============================================================
  // PHILOSOPHY / WISDOM (150 quotes)
  // ============================================================

  // Meditations — Marcus Aurelius (751-785)
  { text: "You have power over your mind — not outside events. Realize this, and you will find strength.", vi: "Ban co quyen luc tren tri oc — khong phai su kien ben ngoai. Nhan ra dieu nay, ban se tim thay suc manh.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "The happiness of your life depends upon the quality of your thoughts.", vi: "Hanh phuc cuoc doi phu thuoc vao chat luong suy nghi cua ban.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Waste no more time arguing about what a good man should be. Be one.", vi: "Dung lang phi thoi gian tranh luan nguoi tot nen la gi. Hay tro thanh mot nguoi.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Very little is needed to make a happy life; it is all within yourself, in your way of thinking.", vi: "Can rat it de co cuoc song hanh phuc; tat ca nam trong ban, trong cach ban suy nghi.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "The best revenge is to be unlike him who performed the injury.", vi: "Su tra thu tot nhat la khong giong nguoi da lam ton thuong ban.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "If it is not right, do not do it. If it is not true, do not say it.", vi: "Neu khong dung, dung lam. Neu khong that, dung noi.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "When you arise in the morning, think of what a precious privilege it is to be alive — to breathe, to think, to enjoy, to love.", vi: "Khi thuc day buoi sang, hay nghi ve dac an quy gia duoc song — duoc tho, duoc nghi, duoc tan huong, duoc yeu.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Everything we hear is an opinion, not a fact. Everything we see is a perspective, not the truth.", vi: "Moi dieu nghe la y kien, khong phai su that. Moi dieu thay la goc nhin, khong phai su that.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "The soul becomes dyed with the color of its thoughts.", vi: "Tam hon nhuom mau cua suy nghi.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Accept the things to which fate binds you, and love the people with whom fate brings you together, and do so with all your heart.", vi: "Chap nhan nhung dieu so phan rang buoc, va yeu nhung nguoi so phan mang den, va lam dieu do bang ca trai tim.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "It is not death that a man should fear, but he should fear never beginning to live.", vi: "Con nguoi khong nen so chet, ma nen so chua bao gio bat dau song.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Never esteem anything as of advantage to you that will make you break your word or lose your self-respect.", vi: "Dung bao gio danh gia dieu gi la loi the neu no khien ban that hua hoac mat tu trong.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "The object of life is not to be on the side of the majority, but to escape finding oneself in the ranks of the insane.", vi: "Muc dich cuoc song khong phai dung ve phia da so, ma la thoat khoi hang ngu cua ke dien.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Look well into thyself; there is a source of strength which will always spring up if thou wilt always look.", vi: "Hay nhin sau vao ben trong; co nguon suc manh luon tran ra neu ban luon nhin.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "How much more grievous are the consequences of anger than the causes of it.", vi: "Hau qua cua con gian nang ne hon nhieu so voi nguyen nhan gay ra no.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Dwell on the beauty of life. Watch the stars, and see yourself running with them.", vi: "Hay ngam ve dep cuoc doi. Hay nhin nhung vi sao, va thay minh dang chay cung chung.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "The impediment to action advances action. What stands in the way becomes the way.", vi: "Tro ngai cua hanh dong thuc day hanh dong. Dieu can duong tro thanh con duong.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "You always own the option of having no opinion.", vi: "Ban luon co quyen khong co y kien.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "Be tolerant with others and strict with yourself.", vi: "Hay khoan dung voi nguoi khac va nghiem khac voi chinh minh.", author: "Marcus Aurelius", source: "Meditations" },
  { text: "The first rule is to keep an untroubled spirit. The second is to look things in the face and know them for what they are.", vi: "Quy tac dau tien la giu tinh than binh than. Quy tac thu hai la nhin thang vao su vat va nhan biet chung nhu chung thuc su la.", author: "Marcus Aurelius", source: "Meditations" },

  // The Art of War — Sun Tzu (786-805)
  { text: "The supreme art of war is to subdue the enemy without fighting.", vi: "Nghe thuat chien tranh toi cao la khuon phuc ke dich ma khong can chien dau.", author: "Sun Tzu", source: "The Art of War" },
  { text: "In the midst of chaos, there is also opportunity.", vi: "Giua hon loan, cung co co hoi.", author: "Sun Tzu", source: "The Art of War" },
  { text: "If you know the enemy and know yourself, you need not fear the result of a hundred battles.", vi: "Biet nguoi biet ta, tram tran tram thang.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Appear weak when you are strong, and strong when you are weak.", vi: "To ra yeu khi manh, manh khi yeu.", author: "Sun Tzu", source: "The Art of War" },
  { text: "The greatest victory is that which requires no battle.", vi: "Chien thang vi dai nhat la chien thang khong can tran chien.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Victorious warriors win first and then go to war, while defeated warriors go to war first and then seek to win.", vi: "Chien binh thang loi thang truoc roi moi ra tran, con chien binh bai tran ra tran roi moi tim chien thang.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Let your plans be dark and impenetrable as night, and when you move, fall like a thunderbolt.", vi: "Hay de ke hoach toi tam va kin dao nhu dem, va khi hanh dong, hay ha nhu set danh.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Opportunities multiply as they are seized.", vi: "Co hoi nhan len khi duoc nam bat.", author: "Sun Tzu", source: "The Art of War" },
  { text: "There is no instance of a nation benefitting from prolonged warfare.", vi: "Khong co quoc gia nao huong loi tu chien tranh keo dai.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Know yourself and you will win all battles.", vi: "Biet minh va ban se thang moi tran chien.", author: "Sun Tzu", source: "The Art of War" },
  { text: "He will win who knows when to fight and when not to fight.", vi: "Nguoi thang la nguoi biet khi nao nen danh va khi nao khong.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Supreme excellence consists of breaking the enemy's resistance without fighting.", vi: "Xuat sac toi cao la pha vo suc khang cu cua dich ma khong can danh.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Energy may be likened to the bending of a crossbow; decision, to the releasing of a trigger.", vi: "Nang luong giong nhu giuong no; quyet dinh giong nhu nha co.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Move swift as the wind and closely-formed as the wood. Attack like the fire and be still as the mountain.", vi: "Di nhanh nhu gio, hop chat nhu rung. Tan cong nhu lua, bat dong nhu nui.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Treat your men as you would your own beloved sons. And they will follow you into the deepest valley.", vi: "Doi xu voi binh si nhu con than yeu. Va ho se theo ban vao thung lung sau nhat.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Strategy without tactics is the slowest route to victory. Tactics without strategy is the noise before defeat.", vi: "Chien luoc khong co chien thuat la con duong cham nhat toi chien thang. Chien thuat khong co chien luoc la tieng on truoc that bai.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Even the finest sword plunged into salt water will eventually rust.", vi: "Ngay ca thanh kiem tot nhat nham vao nuoc muoi cuoi cung cung ri set.", author: "Sun Tzu", source: "The Art of War" },
  { text: "The whole secret lies in confusing the enemy, so that he cannot fathom our real intent.", vi: "Toan bo bi mat nam o viec lam roi ke dich, de ho khong the do duoc y dinh that su.", author: "Sun Tzu", source: "The Art of War" },
  { text: "To know your enemy, you must become your enemy.", vi: "De biet ke dich, ban phai tro thanh ke dich.", author: "Sun Tzu", source: "The Art of War" },
  { text: "Build your opponent a golden bridge to retreat across.", vi: "Hay xay cho doi thu cay cau vang de rut lui.", author: "Sun Tzu", source: "The Art of War" },

  // Tao Te Ching — Lao Tzu (806-820)
  { text: "A journey of a thousand miles begins with a single step.", vi: "Hanh trinh ngan dam bat dau tu mot buoc chan.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "When I let go of what I am, I become what I might be.", vi: "Khi buong bo con nguoi hien tai, toi tro thanh con nguoi co the la.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Knowing others is intelligence; knowing yourself is true wisdom. Mastering others is strength; mastering yourself is true power.", vi: "Biet nguoi la thong minh; biet minh la tri tue. Lam chu nguoi la suc manh; lam chu minh la quyen luc that su.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Nature does not hurry, yet everything is accomplished.", vi: "Thien nhien khong voi va, nhung moi thu deu hoan thanh.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "The best fighter is never angry.", vi: "Chien binh gioi nhat khong bao gio gian du.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "He who controls others may be powerful, but he who has mastered himself is mightier still.", vi: "Nguoi kiem soat nguoi khac co the manh, nhung nguoi lam chu ban than con manh hon.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Silence is a source of great strength.", vi: "Im lang la nguon suc manh vi dai.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "The wise man is one who knows what he does not know.", vi: "Nguoi khon ngoan la nguoi biet dieu minh khong biet.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Water is the softest thing, yet it can penetrate mountains and earth. This shows clearly the principle of softness overcoming hardness.", vi: "Nuoc la thu mem nhat, nhung co the xuyen qua nui va dat. Dieu nay cho thay ro nguyen ly mem thang cung.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Be content with what you have; rejoice in the way things are. When you realize there is nothing lacking, the whole world belongs to you.", vi: "Hai long voi nhung gi ban co; vui voi su vat nhu chung dang la. Khi nhan ra khong thieu gi, ca the gioi thuoc ve ban.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Do the difficult things while they are easy and do the great things while they are small.", vi: "Lam dieu kho khi chung con de va lam dieu lon khi chung con nho.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Those who know do not speak. Those who speak do not know.", vi: "Nguoi biet khong noi. Nguoi noi khong biet.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "Care about what other people think and you will always be their prisoner.", vi: "Quan tam nguoi khac nghi gi va ban se mai la tu nhan cua ho.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "At the center of your being you have the answer; you know who you are and you know what you want.", vi: "O trung tam con nguoi ban co cau tra loi; ban biet minh la ai va biet minh muon gi.", author: "Lao Tzu", source: "Tao Te Ching" },
  { text: "The flame that burns twice as bright burns half as long.", vi: "Ngon lua chay sang gap doi se tat nhanh gap doi.", author: "Lao Tzu", source: "Tao Te Ching" },

  // Seneca (821-840)
  { text: "It is not that we have a short time to live, but that we waste a great deal of it.", vi: "Khong phai chung ta co it thoi gian song, ma la chung ta lang phi qua nhieu.", author: "Seneca", source: "On the Shortness of Life" },
  { text: "Luck is what happens when preparation meets opportunity.", vi: "May man la khi su chuan bi gap co hoi.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "We suffer more often in imagination than in reality.", vi: "Chung ta dau kho trong tuong tuong nhieu hon trong thuc te.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "True happiness is to enjoy the present, without anxious dependence upon the future.", vi: "Hanh phuc that su la tan huong hien tai, khong lo lang phu thuoc vao tuong lai.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "Difficulties strengthen the mind, as labor does the body.", vi: "Kho khan toi luyen tri oc, nhu lao dong toi luyen co the.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "It is not because things are difficult that we do not dare; it is because we do not dare that things are difficult.", vi: "Khong phai vi su viec kho ma ta khong dam; vi ta khong dam nen su viec moi kho.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "A gem cannot be polished without friction, nor a man perfected without trials.", vi: "Vien ngoc khong the sang bong ma khong co ma sat, con nguoi khong the hoan thien ma khong co thu thach.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "Hang on to your youthful enthusiasms — you'll be able to use them better when you're older.", vi: "Hay giu nhiet huyet tuoi tre — ban se su dung chung tot hon khi gia.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "If a man knows not to which port he sails, no wind is favorable.", vi: "Neu khong biet den cang nao, khong co gio nao la thuan.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "Begin at once to live, and count each separate day as a separate life.", vi: "Hay bat dau song ngay, va coi moi ngay nhu mot cuoc doi rieng.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "He who is brave is free.", vi: "Nguoi dung cam la nguoi tu do.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "Sometimes even to live is an act of courage.", vi: "Doi khi chi viec song cung la hanh dong can dam.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "The whole future lies in uncertainty: live immediately.", vi: "Toan bo tuong lai nam trong bat dinh: hay song ngay.", author: "Seneca", source: "On the Shortness of Life" },
  { text: "No person has the power to have everything they want, but it is in their power not to want what they don't have, and to cheerfully put to good use what they do have.", vi: "Khong ai co quyen co moi thu ho muon, nhung trong kha nang cua ho la khong muon thu khong co, va vui ve tan dung thu dang co.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "The greatest obstacle to living is expectancy, which hangs upon tomorrow and loses today.", vi: "Tro ngai lon nhat cua cuoc song la su ky vong, bam vao ngay mai va mat ngay hom nay.", author: "Seneca", source: "On the Shortness of Life" },
  { text: "Associate with people who are likely to improve you.", vi: "Hay ket giao voi nguoi co the giup ban tot hon.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "We are more often frightened than hurt; and we suffer more from imagination than from reality.", vi: "Chung ta thuong bi so hon la bi ton thuong; va dau kho tu tuong tuong nhieu hon tu thuc te.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "It is the power of the mind to be unconquerable.", vi: "Suc manh cua tri oc la bat kha chinh phuc.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "While we wait for life, life passes.", vi: "Trong khi cho doi cuoc song, cuoc song troi qua.", author: "Seneca", source: "On the Shortness of Life" },
  { text: "Only time can heal what reason cannot.", vi: "Chi thoi gian moi chua lanh dieu ly tri khong the.", author: "Seneca", source: "Letters from a Stoic" },

  // Epictetus (841-855)
  { text: "It's not what happens to you, but how you react to it that matters.", vi: "Khong phai dieu xay ra voi ban, ma la cach ban phan ung moi quan trong.", author: "Epictetus", source: "The Enchiridion" },
  { text: "We cannot choose our external circumstances, but we can always choose how we respond to them.", vi: "Chung ta khong the chon hoan canh, nhung luon co the chon cach phan ung.", author: "Epictetus", source: "The Discourses" },
  { text: "First say to yourself what you would be; and then do what you have to do.", vi: "Truoc tien hay noi voi minh ban muon la gi; roi lam dieu can lam.", author: "Epictetus", source: "The Discourses" },
  { text: "No man is free who is not master of himself.", vi: "Khong ai tu do neu khong lam chu ban than.", author: "Epictetus", source: "The Discourses" },
  { text: "Make the best use of what is in your power, and take the rest as it happens.", vi: "Hay tan dung tot nhat dieu trong kha nang, va chap nhan phan con lai nhu no xay ra.", author: "Epictetus", source: "The Discourses" },
  { text: "There is only one way to happiness and that is to cease worrying about things which are beyond the power of our will.", vi: "Chi co mot con duong den hanh phuc la ngung lo lang ve nhung dieu nam ngoai y chi cua ta.", author: "Epictetus", source: "The Discourses" },
  { text: "Don't explain your philosophy. Embody it.", vi: "Dung giai thich triet ly. Hay song voi no.", author: "Epictetus", source: "The Discourses" },
  { text: "He who laughs at himself never runs out of things to laugh at.", vi: "Nguoi cuoi chinh minh khong bao gio het thu de cuoi.", author: "Epictetus", source: "The Discourses" },
  { text: "Wealth consists not in having great possessions, but in having few wants.", vi: "Giau co khong nam o viec co nhieu tai san, ma o viec co it ham muon.", author: "Epictetus", source: "The Discourses" },
  { text: "If you want to improve, be content to be thought foolish and stupid.", vi: "Neu muon tien bo, hay chap nhan bi xem la ngu ngoc.", author: "Epictetus", source: "The Enchiridion" },
  { text: "Any person capable of angering you becomes your master.", vi: "Bat ky ai co the lam ban tuc gian deu tro thanh chu nhan cua ban.", author: "Epictetus", source: "The Discourses" },
  { text: "It is impossible for a man to learn what he thinks he already knows.", vi: "Con nguoi khong the hoc dieu ho nghi minh da biet.", author: "Epictetus", source: "The Discourses" },
  { text: "Man is not worried by real problems so much as by his imagined anxieties about real problems.", vi: "Con nguoi khong lo lang ve van de thuc su nhieu bang nhung lo lang tuong tuong ve van de thuc su.", author: "Epictetus", source: "The Enchiridion" },
  { text: "Circumstances don't make the man, they only reveal him to himself.", vi: "Hoan canh khong tao nen con nguoi, chung chi boc lo con nguoi truoc chinh minh.", author: "Epictetus", source: "The Discourses" },
  { text: "Keep your attention focused entirely on what is truly your own concern, and be clear that what belongs to others is their business and none of yours.", vi: "Hay tap trung hoan toan vao dieu thuc su la cua ban, va hieu ro dieu thuoc nguoi khac la viec cua ho, khong phai cua ban.", author: "Epictetus", source: "The Enchiridion" },

  // Socrates, Aristotle, Confucius (856-880)
  { text: "The unexamined life is not worth living.", vi: "Cuoc doi khong tu xem xet khong dang song.", author: "Socrates", source: "Apology" },
  { text: "I know that I know nothing.", vi: "Toi biet rang toi khong biet gi.", author: "Socrates", source: "Apology" },
  { text: "Strong minds discuss ideas, average minds discuss events, weak minds discuss people.", vi: "Tri oc manh ban y tuong, tri oc trung binh ban su kien, tri oc yeu ban con nguoi.", author: "Socrates", source: "Attributed" },
  { text: "To find yourself, think for yourself.", vi: "De tim thay chinh minh, hay tu suy nghi.", author: "Socrates", source: "Attributed" },
  { text: "Education is the kindling of a flame, not the filling of a vessel.", vi: "Giao duc la nhom ngon lua, khong phai lap day binh chua.", author: "Socrates", source: "Attributed" },
  { text: "The secret of change is to focus all of your energy not on fighting the old, but on building the new.", vi: "Bi quyet cua thay doi la tap trung toan bo nang luong khong phai chong lai cai cu, ma xay dung cai moi.", author: "Socrates", source: "Attributed" },
  { text: "Wonder is the beginning of wisdom.", vi: "Kinh ngac la khoi dau cua tri tue.", author: "Socrates", source: "Attributed" },
  { text: "Be kind, for everyone you meet is fighting a hard battle.", vi: "Hay tu te, vi moi nguoi ban gap deu dang chien dau voi tran chien kho khan.", author: "Socrates", source: "Attributed" },
  { text: "We are what we repeatedly do. Excellence, then, is not an act, but a habit.", vi: "Chung ta la nhung gi chung ta lam di lam lai. Xuat sac, vi the, khong phai hanh dong, ma la thoi quen.", author: "Aristotle", source: "Nicomachean Ethics" },
  { text: "Knowing yourself is the beginning of all wisdom.", vi: "Biet minh la khoi dau cua moi tri tue.", author: "Aristotle", source: "Attributed" },
  { text: "It is the mark of an educated mind to be able to entertain a thought without accepting it.", vi: "Dau hieu cua tri oc co hoc la co the suy ngam mot y tuong ma khong chap nhan no.", author: "Aristotle", source: "Attributed" },
  { text: "Pleasure in the job puts perfection in the work.", vi: "Niem vui trong cong viec tao su hoan hao trong san pham.", author: "Aristotle", source: "Attributed" },
  { text: "Educating the mind without educating the heart is no education at all.", vi: "Giao duc tri oc ma khong giao duc trai tim thi khong phai giao duc.", author: "Aristotle", source: "Attributed" },
  { text: "Patience is bitter, but its fruit is sweet.", vi: "Kien nhan thi dang, nhung trai cua no thi ngot.", author: "Aristotle", source: "Attributed" },
  { text: "Happiness depends upon ourselves.", vi: "Hanh phuc phu thuoc vao chinh chung ta.", author: "Aristotle", source: "Nicomachean Ethics" },
  { text: "The whole is greater than the sum of its parts.", vi: "Tong the lon hon tong cac phan.", author: "Aristotle", source: "Metaphysics" },
  { text: "It does not matter how slowly you go as long as you do not stop.", vi: "Khong quan trong ban di cham the nao mien la khong dung lai.", author: "Confucius", source: "Analects" },
  { text: "Our greatest glory is not in never falling, but in rising every time we fall.", vi: "Vinh quang lon nhat khong phai la khong bao gio nga, ma la dung day moi khi nga.", author: "Confucius", source: "Analects" },
  { text: "The man who moves a mountain begins by carrying away small stones.", vi: "Nguoi doi nui bat dau bang cach mang di nhung vien da nho.", author: "Confucius", source: "Analects" },
  { text: "Real knowledge is to know the extent of one's ignorance.", vi: "Kien thuc that su la biet gioi han cua su thieu hieu biet cua minh.", author: "Confucius", source: "Analects" },
  { text: "Before you embark on a journey of revenge, dig two graves.", vi: "Truoc khi len duong tra thu, hay dao hai ngoi mo.", author: "Confucius", source: "Analects" },
  { text: "Everything has beauty, but not everyone sees it.", vi: "Moi thu deu co ve dep, nhung khong phai ai cung nhin thay.", author: "Confucius", source: "Analects" },
  { text: "He who learns but does not think is lost. He who thinks but does not learn is in great danger.", vi: "Hoc ma khong suy nghi la mat phuong huong. Suy nghi ma khong hoc la nguy hiem.", author: "Confucius", source: "Analects" },
  { text: "When it is obvious that the goals cannot be reached, don't adjust the goals, adjust the action steps.", vi: "Khi ro rang muc tieu khong the dat, dung dieu chinh muc tieu, hay dieu chinh cac buoc hanh dong.", author: "Confucius", source: "Analects" },
  { text: "The superior man is modest in his speech, but exceeds in his actions.", vi: "Nguoi quan tu khiem ton trong loi noi, nhung vuot troi trong hanh dong.", author: "Confucius", source: "Analects" },

  // Sapiens — Yuval Noah Harari (881-900)
  { text: "You could never convince a monkey to give you a banana by promising him limitless bananas after death. Only Homo sapiens can believe such stories.", vi: "Ban khong bao gio co the thuyet phuc khi cho ban qua chuoi bang cach hua chuoi vo han sau khi chet. Chi Homo sapiens moi tin nhung cau chuyen nhu vay.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "We study history not to know the future but to widen our horizons, to understand that our present situation is neither natural nor inevitable.", vi: "Chung ta hoc lich su khong phai de biet tuong lai ma de mo rong tam nhin, de hieu rang tinh hinh hien tai khong phai tu nhien hay tat yeu.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "How do you cause people to believe in an imagined order such as Christianity, democracy, or capitalism? First, you never admit that the order is imagined.", vi: "Lam sao de nguoi ta tin vao trat tu tuong tuong nhu ton giao, dan chu hay tu ban? Truoc tien, dung bao gio thua nhan trat tu do la tuong tuong.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Culture tends to argue that it forbids only that which is unnatural. But from a biological perspective, nothing is unnatural.", vi: "Van hoa thuong ly luan rang no chi cam nhung gi phi tu nhien. Nhung tu goc nhin sinh hoc, khong gi la phi tu nhien.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "History is something that very few people have been doing while everyone else was plowing fields and carrying water buckets.", vi: "Lich su la dieu rat it nguoi lam trong khi moi nguoi khac dang cay ruong va ganh nuoc.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "One of history's few iron laws is that luxuries tend to become necessities and to spawn new obligations.", vi: "Mot trong nhung quy luat sat da cua lich su la xa xi thuong tro thanh thiet yeu va sinh ra nghia vu moi.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "The real difference between us and chimpanzees is the mythical glue that binds together large numbers of individuals, families, and groups.", vi: "Khac biet that su giua chung ta va tinh tinh la chat keo than thoai ket noi so luong lon ca nhan, gia dinh va nhom.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Sapiens rule the world because we are the only animal that can cooperate flexibly in large numbers.", vi: "Sapiens thong tri the gioi vi la dong vat duy nhat co the hop tac linh hoat voi so luong lon.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "There are no gods in the universe, no nations, no money, no human rights, no laws, and no justice outside the common imagination of human beings.", vi: "Khong co than linh, quoc gia, tien bac, nhan quyen, luat phap hay cong ly nao ngoai tri tuong tuong chung cua loai nguoi.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Money is the most universal and most efficient system of mutual trust ever devised.", vi: "Tien la he thong tin tuong lan nhau pho quat va hieu qua nhat tung duoc phat minh.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Consistency is the playground of dull minds.", vi: "Nhat quan la san choi cua nhung tri oc te nhat.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "People are usually afraid of change because they fear the unknown. But the single greatest constant of history is that everything changes.", vi: "Nguoi ta thuong so thay doi vi so dieu chua biet. Nhung hang so lon nhat duy nhat cua lich su la moi thu deu thay doi.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "The Agricultural Revolution was history's biggest fraud.", vi: "Cach mang Nong nghiep la tro lua lon nhat lich su.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "We did not domesticate wheat. It domesticated us.", vi: "Chung ta khong thuan hoa lua mi. Lua mi thuan hoa chung ta.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Happiness does not really depend on objective conditions of either wealth, health, or even community. Rather, it depends on the correlation between objective conditions and subjective expectations.", vi: "Hanh phuc khong thuc su phu thuoc dieu kien khach quan ve cua cai, suc khoe hay cong dong. Ma phu thuoc vao tuong quan giua dieu kien khach quan va ky vong chu quan.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Each year the US population spends more money on diets than the amount needed to feed all the hungry people in the rest of the world.", vi: "Moi nam nguoi My chi nhieu tien cho an kieng hon so tien can de nuoi song tat ca nguoi doi tren the gioi.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Biology enables, culture forbids.", vi: "Sinh hoc cho phep, van hoa cam doan.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Telling effective stories is not easy. The difficulty lies not in telling the story, but in convincing everyone else to believe it.", vi: "Ke chuyen hieu qua khong de. Kho khan khong nam o viec ke, ma o viec thuyet phuc moi nguoi tin.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "Large numbers of strangers can cooperate successfully by believing in common myths.", vi: "So luong lon nguoi la co the hop tac thanh cong bang cach tin vao nhung huyen thoai chung.", author: "Yuval Noah Harari", source: "Sapiens" },
  { text: "The ability to create an imagined reality out of words enabled large numbers of strangers to cooperate effectively.", vi: "Kha nang tao thuc tai tuong tuong tu ngon tu cho phep so luong lon nguoi la hop tac hieu qua.", author: "Yuval Noah Harari", source: "Sapiens" },

  // ============================================================
  // FINANCIAL / WEALTH (100 quotes)
  // ============================================================

  // Rich Dad Poor Dad — Robert Kiyosaki (901-925)
  { text: "The rich don't work for money. They make money work for them.", vi: "Nguoi giau khong lam viec vi tien. Ho de tien lam viec cho ho.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "In the real world, the smartest people are people who make mistakes and learn. In school, the smartest people don't make mistakes.", vi: "Ngoai doi thuc, nguoi thong minh nhat la nguoi mac sai va hoc hoi. O truong, nguoi thong minh nhat khong mac sai.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "It's not how much money you make, but how much money you keep, how hard it works for you, and how many generations you keep it for.", vi: "Khong phai ban kiem bao nhieu, ma la ban giu bao nhieu, no lam viec cham chi the nao cho ban, va bao nhieu the he ban giu duoc no.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The single most powerful asset we all have is our mind. If it is trained well, it can create enormous wealth.", vi: "Tai san manh me nhat cua moi nguoi la tri oc. Neu duoc ren luyen tot, no co the tao ra khoi tai san khong lo.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Winners are not afraid of losing. But losers are. Failure is part of the process of success.", vi: "Nguoi thang khong so thua. Nhung ke thua thi co. That bai la mot phan cua qua trinh thanh cong.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "If you want to be rich, you need to develop your vision. You must be standing on the edge of time gazing into the future.", vi: "Neu muon giau, ban can phat trien tam nhin. Ban phai dung o ranh gioi thoi gian nhin vao tuong lai.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The love of money is the root of all evil. The lack of money is the root of all evil.", vi: "Yeu tien la goc re cua moi toi ac. Thieu tien cung la goc re cua moi toi ac.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "An asset puts money in my pocket. A liability takes money out of my pocket.", vi: "Tai san bo tien vao tui toi. No phai lay tien ra khoi tui toi.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The poor and the middle class work for money. The rich have money work for them.", vi: "Nguoi ngheo va trung luu lam viec vi tien. Nguoi giau de tien lam viec cho ho.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Intelligence solves problems and produces money. Money without financial intelligence is money soon gone.", vi: "Tri tue giai quyet van de va tao ra tien. Tien khong co tri tue tai chinh la tien som mat.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Workers work hard enough to not be fired, and owners pay just enough so that workers won't quit.", vi: "Nhan cong lam viec du cham de khong bi duoi, va chu tra du de nhan cong khong nghi.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Don't let the fear of losing be greater than the excitement of winning.", vi: "Dung de noi so thua lon hon su hao hung khi thang.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Financial struggle is often the result of people working all their lives for someone else.", vi: "Khon kho tai chinh thuong la ket qua cua viec lam viec ca doi cho nguoi khac.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "If you want to go somewhere, it is best to find someone who has already been there.", vi: "Neu muon di dau, tot nhat hay tim nguoi da tung den do.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The most life-destroying word of all is the word tomorrow.", vi: "Tu huy hoai cuoc doi nhat la tu ngay mai.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The size of your success is measured by the strength of your desire; the size of your dream; and how you handle disappointment along the way.", vi: "Quy mo thanh cong duoc do bang suc manh khat vong, kich co giac mo, va cach ban xu ly that vong tren duong di.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "There is a difference between being poor and being broke. Broke is temporary. Poor is eternal.", vi: "Co su khac biet giua ngheo va het tien. Het tien la tam thoi. Ngheo la vinh vien.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Your future is created by what you do today, not tomorrow.", vi: "Tuong lai cua ban duoc tao boi nhung gi ban lam hom nay, khong phai ngay mai.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "If you realize that you're the problem, then you can change yourself, learn something, and grow wiser.", vi: "Neu nhan ra ban la van de, ban co the thay doi minh, hoc hoi va tro nen khon ngoan hon.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Emotions are what make us human. The word 'emotion' stands for 'energy in motion.' Be truthful about your emotions, and use your mind and emotions in your favor, not against yourself.", vi: "Cam xuc la thu lam chung ta thanh nguoi. Hay thanh that voi cam xuc, va dung tri oc va cam xuc co loi cho ban, khong phai chong lai ban.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "In today's rapidly changing world, the people who are not taking risk are the risk takers.", vi: "Trong the gioi thay doi nhanh hom nay, nguoi khong chap nhan rui ro moi la nguoi chap nhan rui ro.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "A mistake is a signal that it is time to learn something new, something you didn't know before.", vi: "Sai lam la tin hieu da den luc hoc dieu moi, dieu ban chua biet truoc day.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The more a person seeks security, the more that person gives up control over their life.", vi: "Cang tim kiem su an toan, ban cang tu bo quyen kiem soat cuoc doi.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "Financial freedom is available to those who learn about it and work for it.", vi: "Tu do tai chinh danh cho nhung ai hoc ve no va lam viec vi no.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },
  { text: "The richest people in the world look for and build networks; everyone else looks for work.", vi: "Nguoi giau nhat the gioi tim va xay dung mang luoi; moi nguoi khac tim viec lam.", author: "Robert Kiyosaki", source: "Rich Dad Poor Dad" },

  // The Psychology of Money — Morgan Housel (926-955)
  { text: "Doing well with money has a little to do with how smart you are and a lot to do with how you behave.", vi: "Quan ly tien tot co lien quan it den tri thong minh va nhieu den cach ban cu xu.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "The highest form of wealth is the ability to wake up every morning and say, 'I can do whatever I want today.'", vi: "Hinh thuc giau co cao nhat la kha nang thuc day moi sang va noi 'Hom nay toi co the lam bat cu dieu gi toi muon.'", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Spending money to show people how much money you have is the fastest way to have less money.", vi: "Tieu tien de khoe voi nguoi khac ban co bao nhieu tien la cach nhanh nhat de co it tien hon.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Wealth is what you don't see. It's the cars not purchased, the diamonds not bought, the renovations postponed, the clothes forgone.", vi: "Su giau co la dieu ban khong nhin thay. La xe khong mua, kim cuong khong mua, nha khong sua, quan ao khong sam.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "The ability to do what you want, when you want, with who you want, for as long as you want, is priceless. It is the highest dividend money pays.", vi: "Kha nang lam dieu muon, khi muon, voi nguoi muon, lau bao lam muon, la vo gia. Do la co tuc cao nhat tien tra.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Use money to gain control over your time, because not having control of your time is such a powerful and universal drag on happiness.", vi: "Dung tien de gianh quyen kiem soat thoi gian, vi khong kiem soat duoc thoi gian la luc keo manh me va pho bien nhat len hanh phuc.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Room for error lets you endure a range of potential outcomes, and endurance lets you stick around long enough to let the odds of benefiting from a low-probability outcome fall in your favor.", vi: "Du dia cho sai sot cho ban chiu dung nhieu ket qua tiem nang, va su ben bi cho ban o lai du lau de co hoi tu ket qua xac suat thap roi vao phan ban.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "No one is impressed with your possessions as much as you are.", vi: "Khong ai an tuong voi tai san cua ban nhieu nhu ban.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Things that have never happened before happen all the time.", vi: "Nhung dieu chua tung xay ra van xay ra moi luc.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "You can be wrong half the time and still make a fortune, because a small minority of things account for the majority of outcomes.", vi: "Ban co the sai mot nua thoi gian va van lam giau, vi mot thieu so nho quyet dinh da so ket qua.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Savings can be created by spending less. You can spend less if you desire less. And you will desire less if you care less about what others think of you.", vi: "Tiet kiem duoc tao ra bang cach chi it hon. Ban chi it hon neu muon it hon. Va ban muon it hon neu bot quan tam nguoi khac nghi gi ve ban.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Planning is important, but the most important part of every plan is to plan on the plan not going according to plan.", vi: "Lap ke hoach la quan trong, nhung phan quan trong nhat la ke hoach cho viec ke hoach khong theo ke hoach.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Getting money requires taking risks, being optimistic, and putting yourself out there. But keeping money requires the opposite of taking risk.", vi: "Kiem tien doi hoi chap nhan rui ro, lac quan va dua minh ra ngoai. Nhung giu tien doi hoi dieu nguoc lai.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Every job looks easy when you're not the one doing it.", vi: "Cong viec nao cung trong de khi ban khong phai la nguoi lam.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Good investing isn't necessarily about earning the highest returns, because the highest returns tend to be one-off hits that can't be repeated. It's about earning pretty good returns that you can stick with and which can be repeated for the longest period of time.", vi: "Dau tu tot khong nhat thiet la kiem loi nhuan cao nhat, vi loi nhuan cao nhat thuong la may man mot lan. Ma la kiem loi nhuan kha tot ma ban co the duy tri lau nhat.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Compounding doesn't rely on earning big returns. Merely good returns sustained uninterrupted for the longest period of time — especially in times of chaos and havoc — will always win.", vi: "Lai kep khong dua vao loi nhuan lon. Chi can loi nhuan tot duy tri lien tuc trong thoi gian dai nhat — dac biet trong hon loan — se luon thang.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Financial success is not a hard science. It's a soft skill, where how you behave is more important than what you know.", vi: "Thanh cong tai chinh khong phai khoa hoc chinh xac. La ky nang mem, noi cach ban cu xu quan trong hon dieu ban biet.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "History is the study of change, ironically used as a map of the future.", vi: "Lich su la nghien cuu ve thay doi, nhung nghich ly thay lai duoc dung nhu ban do tuong lai.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Reasonable is more realistic and you have a better chance of sticking with it for the long run, which is what matters most when managing money.", vi: "Hop ly thi thuc te hon va ban co co hoi bam tru lau dai hon, dieu quan trong nhat khi quan ly tien.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Independence, to me, doesn't mean you'll stop working. It means you only do the work you like with people you like at the times you want for as long as you want.", vi: "Doc lap, voi toi, khong co nghia ngung lam viec. Ma chi lam viec ban thich voi nguoi ban thich vao luc ban muon lau bao nhieu tuy ban.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "The world is full of obvious things which nobody by any chance ever observes.", vi: "The gioi day nhung dieu hien nhien ma khong ai tinh co quan sat thay.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Be nicer and less flashy. No one is impressed with your possessions as much as you are.", vi: "Hay tu te hon va bot khoa truong. Khong ai an tuong voi tai san cua ban nhieu nhu ban.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Controlling your time is the highest dividend money pays.", vi: "Kiem soat thoi gian la co tuc cao nhat ma tien tra.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Past a certain level of income, what you need is just what sits below your ego.", vi: "Qua mot muc thu nhap nhat dinh, dieu ban can chi la nhung gi nam duoi ban nga.", author: "Morgan Housel", source: "The Psychology of Money" },
  { text: "Progress happens too slowly to notice, but setbacks happen too quickly to ignore.", vi: "Tien bo xay ra qua cham de nhan thay, nhung tro ngai xay ra qua nhanh de pho lo.", author: "Morgan Housel", source: "The Psychology of Money" },

  // The Intelligent Investor — Benjamin Graham (956-975)
  { text: "The intelligent investor is a realist who sells to optimists and buys from pessimists.", vi: "Nha dau tu thong minh la nguoi thuc te ban cho nguoi lac quan va mua tu nguoi bi quan.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "In the short run, the market is a voting machine but in the long run, it is a weighing machine.", vi: "Ngan han, thi truong la may bo phieu nhung dai han, no la cai can.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "The investor's chief problem — and even his worst enemy — is likely to be himself.", vi: "Van de chinh cua nha dau tu — va thang ke thu lon nhat — co le la chinh minh.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Have the courage of your knowledge and experience. If you have formed a conclusion from the facts and if you know your judgment is sound, act on it.", vi: "Hay can dam voi kien thuc va kinh nghiem. Neu ban da rut ra ket luan tu du kien va biet phan doan cua minh dung, hay hanh dong.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "The margin of safety is always dependent on the price paid.", vi: "Bien do an toan luon phu thuoc vao gia da tra.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Successful investing is about managing risk, not avoiding it.", vi: "Dau tu thanh cong la quan ly rui ro, khong phai tranh rui ro.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "The best way to measure your investing success is not by whether you're beating the market but by whether you've put in place a financial plan and a behavioral discipline that are likely to get you where you want to go.", vi: "Cach tot nhat do luong thanh cong dau tu khong phai thang thi truong ma la lieu ban co ke hoach tai chinh va ky luat hanh vi dua ban den noi muon den.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Those who do not remember the past are condemned to repeat it.", vi: "Nhung ai khong nho qua khu se bi ket an lap lai no.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "An investment operation is one which, upon thorough analysis, promises safety of principal and an adequate return.", vi: "Hoat dong dau tu la hoat dong, sau phan tich ky luong, hua hen an toan von goc va loi nhuan hop ly.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "To achieve satisfactory investment results is easier than most people realize; to achieve superior results is harder than it looks.", vi: "Dat ket qua dau tu hai long de hon da so nghi; dat ket qua vuot troi kho hon ve ngoai.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Buy not on optimism, but on arithmetic.", vi: "Mua khong dua tren lac quan, ma dua tren so lieu.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "The individual investor should act consistently as an investor and not as a speculator.", vi: "Nha dau tu ca nhan nen hanh dong nhat quan nhu nha dau tu, khong phai ke dau co.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Invest only if you would be comfortable owning a stock even if you had no way of knowing its daily share price.", vi: "Chi dau tu neu ban thoai mai so huu co phieu du khong biet gia hang ngay.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "People who invest make money for themselves; people who speculate make money for their brokers.", vi: "Nguoi dau tu kiem tien cho minh; nguoi dau co kiem tien cho moi gioi.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Confronted with a challenge to distill the secret of sound investment into three words, we venture the motto: Margin of Safety.", vi: "Doi mat voi thach thuc chung cat bi quyet dau tu thanh ba tu, chung toi mao hiem dua ra khau hieu: Bien Do An Toan.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "You are neither right nor wrong because the crowd disagrees with you. You are right because your data and reasoning are right.", vi: "Ban khong dung hay sai vi dam dong bat dong. Ban dung vi du lieu va ly luan cua ban dung.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "The market is a pendulum that forever swings between unsustainable optimism and unjustified pessimism.", vi: "Thi truong la con lac mai mai dao dong giua lac quan khong ben vung va bi quan vo co.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Never buy a stock immediately after a substantial rise or sell one immediately after a substantial drop.", vi: "Dung bao gio mua co phieu ngay sau khi tang manh hay ban ngay sau khi giam manh.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Wall Street people learn nothing and forget everything.", vi: "Nguoi Wall Street khong hoc gi va quen het.", author: "Benjamin Graham", source: "The Intelligent Investor" },
  { text: "Obvious prospects for physical growth in a business do not translate into obvious profits for investors.", vi: "Trien vong tang truong ro rang cua doanh nghiep khong chuyen thanh loi nhuan ro rang cho nha dau tu.", author: "Benjamin Graham", source: "The Intelligent Investor" },

  // Poor Charlie's Almanack — Charlie Munger (976-1000)
  { text: "Spend each day trying to be a little wiser than you were when you woke up.", vi: "Moi ngay hay co tro nen khon ngoan hon mot chut so voi khi thuc day.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "The big money is not in the buying and selling, but in the waiting.", vi: "Tien lon khong nam o viec mua ban, ma o viec cho doi.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "In my whole life, I have known no wise people who didn't read all the time — none, zero.", vi: "Ca doi toi, toi khong biet nguoi khon ngoan nao khong doc sach lien tuc — khong mot ai.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Knowing what you don't know is more useful than being brilliant.", vi: "Biet dieu minh khong biet huu ich hon la xuat sac.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "The best thing a human being can do is to help another human being know more.", vi: "Dieu tot nhat con nguoi co the lam la giup nguoi khac biet them.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Acquire worldly wisdom and adjust your behavior accordingly. If your new behavior gives you a little temporary unpopularity with your peer group, then to hell with them.", vi: "Tich luy tri tue va dieu chinh hanh vi. Neu hanh vi moi khien ban tam thoi khong duoc ua thich, mac ke ho.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "It is remarkable how much long-term advantage people like us have gotten by trying to be consistently not stupid, instead of trying to be very intelligent.", vi: "Dang chu y la chung toi dat duoc bao nhieu loi the dai han bang cach co khong ngu ngoc nhat quan, thay vi co thong minh.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Invert, always invert: Turn a situation or problem upside down. Look at it backward.", vi: "Dao nguoc, luon dao nguoc: Lat nguoc tinh huong hay van de. Nhin no tu phia sau.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "I constantly see people rise in life who are not the smartest, sometimes not even the most diligent, but they are learning machines.", vi: "Toi luon thay nguoi vuon len trong doi khong phai gioi nhat, doi khi khong cham chi nhat, nhung ho la co may hoc hoi.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "You don't have to be brilliant, only a little bit wiser than the other guys, on average, for a long, long time.", vi: "Ban khong can xuat sac, chi can khon hon nguoi khac mot chut, trung binh, trong thoi gian rat dai.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "We all are learning, modifying, or destroying ideas all the time. Rapid destruction of your ideas when the time is right is one of the most valuable qualities you can acquire.", vi: "Chung ta luon hoc, sua doi hay pha huy y tuong. Nhanh chong pha bo y tuong khi den luc la mot trong nhung pham chat gia tri nhat.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "A lot of people with high IQs are terrible investors because they've got terrible temperaments.", vi: "Nhieu nguoi IQ cao la nha dau tu te vi ho co tinh khi te.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "There is no better teacher than history in determining the future. There are answers worth billions of dollars in a 30-dollar history book.", vi: "Khong co thay giao nao tot hon lich su trong viec dinh hinh tuong lai. Co nhung cau tra loi tri gia hang ty do la trong cuon sach lich su 30 do la.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Those who keep learning, will keep rising in life.", vi: "Nguoi tiep tuc hoc se tiep tuc vuon len trong cuoc doi.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "The desire to get rich fast is pretty dangerous.", vi: "Mong muon giau nhanh kha nguy hiem.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "To get what you want, you have to deserve what you want. The world is not yet a crazy enough place to reward a whole bunch of undeserving people.", vi: "De co dieu muon, ban phai xung dang voi no. The gioi chua dien den muc thuong cho dam nguoi khong xung dang.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Live within your income and save so that you can invest. Learn what you need to learn.", vi: "Song trong kha nang thu nhap va tiet kiem de dau tu. Hoc nhung gi can hoc.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Take a simple idea and take it seriously.", vi: "Lay mot y tuong don gian va nghiem tuc voi no.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "If you want to get smart, the question you have to keep asking is 'why, why, why?'", vi: "Neu muon thong minh, cau hoi ban phai luon hoi la 'tai sao, tai sao, tai sao?'", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "The iron rule of nature is: you get what you reward for. If you want ants to come, you put sugar on the floor.", vi: "Quy luat sat da cua tu nhien la: ban nhan duoc dieu ban thuong. Neu muon kien den, hay do duong xuong san.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "You need patience, discipline, and agility to take losses and adversity without going crazy.", vi: "Ban can kien nhan, ky luat va linh hoat de chiu thua lo va nghich canh ma khong phat dien.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "The safest way to try to get what you want is to try to deserve what you want.", vi: "Cach an toan nhat de co dieu muon la co lam xung dang voi dieu muon.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Mimicking the herd invites regression to the mean.", vi: "Bat chuoc dam dong moi goi su quay ve trung binh.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "You must know the big ideas in the big disciplines, and use them routinely — all of them, not just a few.", vi: "Ban phai biet nhung y tuong lon trong nhung linh vuc lon, va su dung chung thuong xuyen — tat ca, khong chi vai cai.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },
  { text: "Develop into a lifelong self-learner through voracious reading; cultivate curiosity and strive to become a little wiser every day.", vi: "Phat trien thanh nguoi tu hoc suot doi qua doc sach ngau nghien; boi duong tri to mo va phan dau khon hon mot chut moi ngay.", author: "Charlie Munger", source: "Poor Charlie's Almanack" },

  // Additional Self-Development quotes (931-950)
  { text: "The only impossible journey is the one you never begin.", vi: "Hanh trinh bat kha thi duy nhat la hanh trinh ban khong bao gio bat dau.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Life doesn't happen to you; it happens for you.", vi: "Cuoc song khong xay ra voi ban, ma xay ra vi ban.", author: "Tony Robbins", source: "Awaken the Giant Within" },
  { text: "Change is inevitable. Growth is optional.", vi: "Thay doi la tat yeu. Truong thanh la lua chon.", author: "John Maxwell", source: "The 15 Invaluable Laws of Growth" },
  { text: "People often say that motivation doesn't last. Well, neither does bathing — that's why we recommend it daily.", vi: "Nguoi ta thuong noi dong luc khong ben lau. Tam rua cung vay — do la ly do chung toi khuyen ban lam moi ngay.", author: "Zig Ziglar", source: "Speech" },
  { text: "What you get by achieving your goals is not as important as what you become by achieving your goals.", vi: "Nhung gi ban dat duoc khi hoan thanh muc tieu khong quan trong bang nhung gi ban tro thanh.", author: "Zig Ziglar", source: "Speech" },
  { text: "You were born to win, but to be a winner, you must plan to win, prepare to win, and expect to win.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Zig Ziglar", source: "Speech" },
  { text: "The best time to plant a tree was 20 years ago. The second best time is now.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Chinese Proverb", source: "Traditional" },
  { text: "Success usually comes to those who are too busy to be looking for it.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Henry David Thoreau", source: "Walden" },
  { text: "The mind is everything. What you think you become.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Buddha", source: "Attributed" },
  { text: "Do what you can, with what you have, where you are.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Theodore Roosevelt", source: "Attributed" },
  { text: "It always seems impossible until it's done.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Nelson Mandela", source: "Speech" },
  { text: "What lies behind us and what lies before us are tiny matters compared to what lies within us.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Ralph Waldo Emerson", source: "Essay" },
  { text: "Believe you can and you're halfway there.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Theodore Roosevelt", source: "Attributed" },
  { text: "The only limit to our realization of tomorrow will be our doubts of today.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Franklin D. Roosevelt", source: "Speech" },
  { text: "We may encounter many defeats but we must not be defeated.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Maya Angelou", source: "Interview" },
  { text: "The future belongs to those who believe in the beauty of their dreams.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Eleanor Roosevelt", source: "Attributed" },
  { text: "It is during our darkest moments that we must focus to see the light.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Aristotle", source: "Attributed" },
  { text: "Everything you've ever wanted is on the other side of fear.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "George Addair", source: "Attributed" },
  { text: "Success is not final, failure is not fatal: it is the courage to continue that counts.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Winston Churchill", source: "Speech" },
  { text: "Act as if what you do makes a difference. It does.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "William James", source: "Attributed" },

  // Additional Leadership quotes (951-970)
  { text: "A leader is one who knows the way, goes the way, and shows the way.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "John Maxwell", source: "The 21 Irrefutable Laws of Leadership" },
  { text: "The greatest leader is not the one who does the greatest things, but the one who gets people to do the greatest things.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Ronald Reagan", source: "Speech" },
  { text: "Management is doing things right; leadership is doing the right things.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "The Effective Executive" },
  { text: "The function of leadership is to produce more leaders, not more followers.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Ralph Nader", source: "Attributed" },
  { text: "Leadership is the capacity to translate vision into reality.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Warren Bennis", source: "On Becoming a Leader" },
  { text: "Before you are a leader, success is all about growing yourself. When you become a leader, success is all about growing others.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Jack Welch", source: "Winning" },
  { text: "The task of leadership is not to put greatness into people, but to elicit it, for the greatness is there already.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "John Buchan", source: "Attributed" },
  { text: "Innovation is the specific instrument of entrepreneurship. The act that endows resources with a new capacity to create wealth.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "Innovation and Entrepreneurship" },
  { text: "The entrepreneur always searches for change, responds to it, and exploits it as an opportunity.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "Innovation and Entrepreneurship" },
  { text: "Business has only two functions — marketing and innovation.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "The Practice of Management" },
  { text: "Efficiency is doing things right; effectiveness is doing the right things.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "The Effective Executive" },
  { text: "Culture eats strategy for breakfast.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "Attributed" },
  { text: "There is nothing so useless as doing efficiently that which should not be done at all.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "The Effective Executive" },
  { text: "The best way to predict the future is to create it.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Peter Drucker", source: "Attributed" },
  { text: "Your most unhappy customers are your greatest source of learning.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Bill Gates", source: "Business @ the Speed of Thought" },
  { text: "It's fine to celebrate success but it is more important to heed the lessons of failure.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Bill Gates", source: "Interview" },
  { text: "Don't compare yourself with anyone in this world. If you do so, you are insulting yourself.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Bill Gates", source: "Interview" },
  { text: "Success is a lousy teacher. It seduces smart people into thinking they can't lose.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Bill Gates", source: "The Road Ahead" },
  { text: "We always overestimate the change that will occur in the next two years and underestimate the change that will occur in the next ten.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Bill Gates", source: "The Road Ahead" },
  { text: "If you are born poor it's not your mistake, but if you die poor it's your mistake.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Bill Gates", source: "Interview" },

  // Additional Philosophy quotes (971-985)
  { text: "The only true wisdom is in knowing you know nothing.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Socrates", source: "Attributed" },
  { text: "Happiness is not something ready made. It comes from your own actions.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Dalai Lama", source: "The Art of Happiness" },
  { text: "In three words I can sum up everything I've learned about life: it goes on.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Robert Frost", source: "Attributed" },
  { text: "Life is really simple, but we insist on making it complicated.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Confucius", source: "Analects" },
  { text: "Turn your wounds into wisdom.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Oprah Winfrey", source: "Interview" },
  { text: "The only person you are destined to become is the person you decide to be.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Ralph Waldo Emerson", source: "Essay" },
  { text: "Not how long, but how well you have lived is the main thing.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Seneca", source: "Letters from a Stoic" },
  { text: "The soul that is within me no man can degrade.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Frederick Douglass", source: "Narrative" },
  { text: "What we achieve inwardly will change outer reality.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Plutarch", source: "Attributed" },
  { text: "No great mind has ever existed without a touch of madness.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Aristotle", source: "Attributed" },
  { text: "He who has a why to live can bear almost any how.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Friedrich Nietzsche", source: "Twilight of the Idols" },
  { text: "That which does not kill us makes us stronger.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Friedrich Nietzsche", source: "Twilight of the Idols" },
  { text: "Man is condemned to be free; because once thrown into the world, he is responsible for everything he does.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Jean-Paul Sartre", source: "Being and Nothingness" },
  { text: "The mind is its own place, and in itself can make a heaven of hell, a hell of heaven.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "John Milton", source: "Paradise Lost" },
  { text: "To live is the rarest thing in the world. Most people exist, that is all.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Oscar Wilde", source: "The Soul of Man Under Socialism" },

  // Additional Financial quotes (986-1000)
  { text: "Do not save what is left after spending, but spend what is left after saving.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Warren Buffett", source: "Interview" },
  { text: "Wide diversification is only required when investors do not understand what they are doing.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Warren Buffett", source: "Interview" },
  { text: "Be fearful when others are greedy and greedy when others are fearful.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Warren Buffett", source: "Interview" },
  { text: "The stock market is a device for transferring money from the impatient to the patient.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Warren Buffett", source: "Interview" },
  { text: "Time in the market beats timing the market.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Ken Fisher", source: "Attributed" },
  { text: "Compound interest is the eighth wonder of the world. He who understands it, earns it; he who doesn't, pays it.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Albert Einstein", source: "Attributed" },
  { text: "The four most dangerous words in investing are: 'This time it's different.'", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "John Templeton", source: "Attributed" },
  { text: "An investment in knowledge pays the best interest.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Benjamin Franklin", source: "Attributed" },
  { text: "Money is a terrible master but an excellent servant.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "P.T. Barnum", source: "Attributed" },
  { text: "Formal education will make you a living; self-education will make you a fortune.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Jim Rohn", source: "Speech" },
  { text: "Rich people have small TVs and big libraries, and poor people have small libraries and big TVs.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Zig Ziglar", source: "Speech" },
  { text: "Never depend on a single income. Make investment to create a second source.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Warren Buffett", source: "Interview" },
  { text: "Financial peace isn't the acquisition of stuff. It's learning to live on less than you make, so you can give money back and have money to invest.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Dave Ramsey", source: "The Total Money Makeover" },
  { text: "It's not your salary that makes you rich, it's your spending habits.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "Charles A. Jaffe", source: "Attributed" },
  { text: "The habit of saving is itself an education; it fosters every virtue, teaches self-denial, cultivates the sense of order, trains to forethought, and so broadens the mind.", vi: "Ban hay tin vao chinh minh va khong ngung no luc moi ngay.", author: "T.T. Munger", source: "Attributed" },
] as const;

export function getTodayQuote() {
  const today = new Date();
  const dayOfYear = Math.floor(
    (today.getTime() - new Date(today.getFullYear(), 0, 0).getTime()) /
      86400000
  );
  return QUOTES[dayOfYear % QUOTES.length];
}
